export interface MCQQuestion { id: number; text: string; image?: string; table?: string;
  options: { label: string; text: string }[]; correct: string; }
export interface MCQPaper { id: string; year: number; session: string; paperCode: string; questionData: MCQQuestion[]; }

const paper_01: MCQQuestion[] = [{"id":1,"text":"A government department provides milk at no charge to very low income families. Which term best describes the milk?","options":[{"label":"A","text":"free good"},{"label":"B","text":"inferior good"},{"label":"C","text":"private good"},{"label":"D","text":"public good"}],"correct":""},{"id":2,"text":"Which statement is a normative statement?","options":[{"label":"A","text":"China has never had a balance of payments surplus."},{"label":"B","text":"Higher interest rates might reduce investment."},{"label":"C","text":"Perfect competition is allocatively efficient."},{"label":"D","text":"Welfare payments should be increased."}],"correct":""},{"id":3,"text":"What do economists regard as the reward for taking risks and organising production?","options":[{"label":"A","text":"enterprise"},{"label":"B","text":"interest"},{"label":"C","text":"wages"},{"label":"D","text":"profit"}],"correct":""},{"id":4,"text":"The British pound is the national currency of the UK. In Brixton in south London it is possible to get a distinctively marked currency called the Brixton pound from special cash machines. This can be spent with 150 local shopkeepers. Similar schemes are found in towns in the US, Italy and France. Should Brixton pounds be considered money?","options":[{"label":"A","text":"no, because it is not possible to have two currencies in a country"},{"label":"B","text":"no, because they are not generally acceptable outside of Brixton"},{"label":"C","text":"yes, because some shopkeepers are willing to accept them"},{"label":"D","text":"yes, because they fulfil all the functions of money"}],"correct":""},{"id":5,"text":"When stating the law of demand for a good, economists use the phrase 'all other things being equal'. What is not one of these 'all other things'?","options":[{"label":"A","text":"the income of the consumer"},{"label":"B","text":"the price of other goods"},{"label":"C","text":"the price of the good"},{"label":"D","text":"the tastes of the consumer"}],"correct":""},{"id":6,"text":"What will not cause a shift in the market supply curve of a commodity?","options":[{"label":"A","text":"a change in technology"},{"label":"B","text":"a rise in the price of a factor input"},{"label":"C","text":"a rise in the price of the commodity"},{"label":"D","text":"the introduction of a specific tax on the commodity"}],"correct":""},{"id":7,"text":"A product has a low price elasticity of supply. What might explain this?","options":[{"label":"A","text":"The product has a low opportunity cost."},{"label":"B","text":"The product is highly perishable."},{"label":"C","text":"The product is classed as an inferior good."},{"label":"D","text":"The product is considered to be a necessity."}],"correct":""},{"id":8,"text":"A car manufacturer estimates that the price elasticity of supply of its cars is +2.5 . What will be the impact of a 10\\% increase in price?","options":[{"label":"A","text":"a 2.5\\% fall in total revenue"},{"label":"B","text":"a 25\\% rise in total revenue"},{"label":"C","text":"a 2.5\\% fall in quantity supplied"},{"label":"D","text":"a 25\\% rise in quantity supplied"}],"correct":""},{"id":9,"text":"A UK based food company wishes to diversify its product range. To finance this, it has obtained a \\$10m loan from a bank to buy land, build and equip a bakery. What would not be classified by an economist as a factor of production?","options":[{"label":"A","text":"the \\$10m loan used to finance the project"},{"label":"B","text":"the land on which the bakery will be built"},{"label":"C","text":"the ovens required to bake the bread"},{"label":"D","text":") the soya used in the making of the bread"}],"correct":""},{"id":10,"text":"The diagram shows the outcome when a landowner, who had allowed motorists to park on his field at no cost, introduces a parking charge of \\$1. What happens as a result of the change?","options":[{"label":"A","text":"The landowner gains a surplus of \\(Y + Z\\) ."},{"label":"B","text":"The motorist gains a surplus of \\(X + Y\\) ."},{"label":"C","text":"The ownership of surplus Y changes."},{"label":"D","text":"There is a total surplus of \\(X + Y + Z\\) ."}],"correct":"","image":"/images/econ-as-mcq/3_646_266_503_429_0.jpg"},{"id":11,"text":"The table gives information about the market for two models of car. } If the prices of the cars remain unchanged, but the price of petrol increases by 100\\%, what will be the effect on the number of cars sold per week?","options":[{"label":"A","text":"increase by 5000"},{"label":"B","text":"no change"},{"label":"C","text":"decrease by 5000"},{"label":"D","text":"decrease by 15000"}],"correct":"","table":"<table><tr><td>number of cars sold per week</td><td>cross elasticity of demand with respect to the price of petrol</td></tr><tr><td>1200 cc</td><td>10000</td><td>-0.25</td></tr><tr><td>2000 cc</td><td>5000</td><td>-0.50</td></tr></table>"},{"id":12,"text":"In many countries there are goods that must be provided directly by the government. What would be the most convincing argument for such provision?","options":[{"label":"A","text":"The consumption of these products may be beneficial."},{"label":"B","text":"The production of these products may be harmful."},{"label":"C","text":"The production of these products have high opportunity costs."},{"label":"D","text":"These products are non-rival in consumption and non-excludable."}],"correct":""},{"id":13,"text":"The provision of rail services is switched from the private sector to the public sector. What is necessarily correct?","options":[{"label":"A","text":"The average fare charged for the service will fall."},{"label":"B","text":"The profitability of the service will fall."},{"label":"C","text":"The rail service's management will be responsible to different owners."},{"label":"D","text":"There will be an increase in the number of workers employed."}],"correct":""},{"id":14,"text":"A government decides to build additional public sector housing to be rented to people receiving low incomes. What is most likely to fall as a result of this increase in public sector housing?","options":[{"label":"A","text":"employment in the construction industry"},{"label":"B","text":"land prices in towns and cities"},{"label":"C","text":"rents of houses in the private sector"},{"label":"D","text":"total government spending"}],"correct":""},{"id":15,"text":"What would be certain to cause a fall in a country's cost of living?","options":[{"label":"A","text":"a fall in real incomes"},{"label":"B","text":"a fall in the inflation rate"},{"label":"C","text":"a negative inflation rate"},{"label":"D","text":"a reduction in direct tax rates"}],"correct":""},{"id":16,"text":"What is not an aim of protectionism?","options":[{"label":"A","text":"to improve balance of trade"},{"label":"B","text":"to increase price of exports"},{"label":"C","text":"to protect infant industries"},{"label":"D","text":") to reduce the volume of imports"}],"correct":""},{"id":17,"text":"A sudden rise in the price of imported oil caused the annual rate of inflation in a given period to be higher than expected. What might be a likely result of this?","options":[{"label":"A","text":"Borrowers would gain."},{"label":"B","text":"Real wages would rise."},{"label":"C","text":"The balance of trade would improve."},{"label":"D","text":"Unemployment would fall."}],"correct":""},{"id":18,"text":"What may increase the benefits a country gains from international trade?","options":[{"label":"A","text":"a reduction in transportation costs because of a fall in world oil prices"},{"label":"B","text":"domestic wage rates increase at a faster rate than output per worker"},{"label":"C","text":"the domestic labour force becomes more occupationally immobile"},{"label":"D","text":"trading partners increase tariffs on imported goods"}],"correct":""},{"id":19,"text":"A country has a balance of trade deficit. When will this be least likely to be improved as a result of a depreciation of its currency?","options":[{"label":"A","text":"if it is currently operating with a significant amount of unused resources"},{"label":"B","text":"if the sum of the price elasticities of demand for exports and imports is less than 1"},{"label":"C","text":"if in the long term, the price elasticity of demand for exports should increase"},{"label":"D","text":"if the country uses a relatively small proportion of imports in their production process"}],"correct":""},{"id":20,"text":"Which statement about trade protection is correct?","options":[{"label":"A","text":"A tariff results in a greater decrease in demand for an import the lower is its price elasticity of demand."},{"label":"B","text":"Embargoes are only an effective trade barrier when the demand for imports is price-elastic."},{"label":"C","text":"Export subsidies to domestic firms will prevent the dumping of foreign products in the domestic market."},{"label":"D","text":"Quotas are less effective than tariffs for raising government revenue."}],"correct":""},{"id":21,"text":"Which type of policy would have the most immediate effect in dealing with a deflationary economic downturn?","options":[{"label":"A","text":"increasing the government's budget surplus"},{"label":"B","text":"increasing borrowing by assisting banks to lend more"},{"label":"C","text":"investing in long-term projects to improve transport networks"},{"label":"D","text":"Switching the burden of taxation from earning to spending"}],"correct":""},{"id":22,"text":"Deflation is associated with persistent falling price levels. Which government policy would be most effective to prevent deflation?","options":[{"label":"A","text":"imposing maximum price levels on basic foodstuffs"},{"label":"B","text":"improving consumer confidence by reducing sales taxes"},{"label":"C","text":"increasing income tax rates and increasing government borrowing"},{"label":"D","text":"removing economic uncertainty and encouraging business investment"}],"correct":""},{"id":23,"text":"Which policy would be likely to increase inflation?","options":[{"label":"A","text":"an increase in income tax"},{"label":"B","text":"an increase in interest rates"},{"label":"C","text":"limiting the amount banks can lend"},{"label":"D","text":"raising the level of import tariffs"}],"correct":""},{"id":24,"text":"A government believes its current account deficit will be beneficial in the long run. What is the most likely reason for this?","options":[{"label":"A","text":"Immigration has increased."},{"label":"B","text":"It imports capital goods."},{"label":"C","text":"It exports raw materials."},{"label":"D","text":"It reduces unemployment."}],"correct":""},{"id":25,"text":"A country has a freely floating exchange rate. In which circumstance is it most likely to appreciate?","options":[{"label":"A","text":"A competitor trading country experiences a fall in the value of its currency."},{"label":"B","text":"Increased administrative burdens are placed on companies within this country wishing to buy imports."},{"label":"C","text":"There is a fall in demand for its exports."},{"label":"D","text":"There is a fall in the level of its rate of interest."}],"correct":""}];

const paper_02: MCQQuestion[] = [{"id":1,"text":"Line XX is the production possibility curve (PPC) of a worker picking peas and beans in a 10 hour working day. What could cause the worker's PPC to shift to the line YY?","options":[{"label":"A","text":"a decrease in working hours to 8 per day and a machine that increases the worker's pea picking productivity"},{"label":"B","text":"a machine that increases the worker's pea picking productivity only"},{"label":"C","text":"a new work schedule where the worker spends 6 hours per day picking peas and only 4 hours picking beans"},{"label":"D","text":"a reduction in working hours to 8 per day only"}],"correct":"","image":"/images/econ-as-mcq/9_543_268_714_519_0.jpg"},{"id":2,"text":"What is a function of money?","options":[{"label":"A","text":"divisibility"},{"label":"B","text":"durability"},{"label":"C","text":"portability"},{"label":"D","text":"medium of exchange"}],"correct":""},{"id":3,"text":"What is classified as a public good by economists?","options":[{"label":"A","text":"flood defences"},{"label":"B","text":"government-funded hospitals"},{"label":"C","text":"government-run national parks"},{"label":"D","text":"the internet"}],"correct":""},{"id":4,"text":"Which statement about the factors of production is correct?","options":[{"label":"A","text":"The factor capital includes shares and deposit accounts at banks."},{"label":"B","text":"The factor labour includes human-made resources."},{"label":"C","text":"The factor land includes forests and undiscovered copper."},{"label":"D","text":"The factor enterprise takes risks and is rewarded with interest."}],"correct":""},{"id":5,"text":"Which supply curve shows that the price elasticity of supply of the good is always equal to 1?","options":[{"label":"A","text":"a straight line that intersects the horizontal axis"},{"label":"B","text":"a straight line that intersects the vertical axis"},{"label":"C","text":"a straight line that passes through the origin"},{"label":"D","text":"a straight line that is vertical to the horizontal axis"}],"correct":""},{"id":6,"text":"What is an example of the rationing function of the price mechanism?","options":[{"label":"A","text":"When the price of a product is falling, firms will allocate less resources to its production."},{"label":"B","text":"When the price of a product is falling, the government can set an effective minimum price."},{"label":"C","text":"When the price of a product is rising, firms will expand production of the product to make profits."},{"label":"D","text":"When the price of a product is rising, some consumers will no longer be able to buy it."}],"correct":""},{"id":7,"text":"The diagram shows the demand and supply curves for bread in a developed economy. Bread is a substitute for pasta and rice. What would cause the demand curve for bread to shift from \\({D}_{1}\\) to \\({D}_{2}\\) in a developed economy?","options":[{"label":"A","text":"a rise in the price of pasta and rice"},{"label":"B","text":"a decrease in the real income of consumers"},{"label":"C","text":"a recession and rising unemployment"},{"label":"D","text":"a subsidy given to producers of pasta and rice"}],"correct":"","image":"/images/econ-as-mcq/13_654_269_489_386_0.jpg"},{"id":8,"text":"The diagram shows three supply curves. What can be concluded about the price elasticity of supply of the curves?","options":[{"label":"A","text":"As price rises, the price elasticity of supply of \\({S}_{2}\\) will increase."},{"label":"B","text":"At any price, the price elasticity of supply of \\({S}_{1}\\) will be less than that of \\({S}_{3}\\) ."},{"label":"C","text":"At any price, the price elasticity of supply of \\({S}_{2}\\) will be higher than that of \\({S}_{3}\\) ."},{"label":"D","text":"The price elasticity of supply of each curve is constant."}],"correct":"","image":"/images/econ-as-mcq/14_636_232_521_366_0.jpg"},{"id":9,"text":"What is a distinguishing feature of a progressive income tax?","options":[{"label":"A","text":"High earners pay a higher proportion of their income in tax than low earners."},{"label":"B","text":"High earners pay a lower proportion of their income in tax than low earners."},{"label":"C","text":"High earners pay the same proportion of their income in tax as low earners."},{"label":"D","text":"Low earners pay more tax than high earners."}],"correct":""},{"id":10,"text":"Why might a government nationalise a private firm?","options":[{"label":"A","text":"to gain greater efficiency due to more competition"},{"label":"B","text":"to increase merit good provision"},{"label":"C","text":"to increase choice for the consumer"},{"label":"D","text":"to raise more tax revenue"}],"correct":""},{"id":11,"text":"The diagram shows a firm's supply of and demand for apples. If a minimum price is increased from \\({P}_{1}\\) to \\({P}_{2}\\) what will happen to the amount of apples sold?","options":[{"label":"A","text":"It will decrease from \\({Q}_{1}\\) to \\({Q}_{2}\\) ."},{"label":"B","text":"It will decrease from \\({Q}_{4}{Q}_{1}\\) to \\({Q}_{2}{Q}_{3}\\) ."},{"label":"C","text":"It will increase from \\({Q}_{3}\\) to \\({Q}_{4}\\) ."},{"label":"D","text":"It will increase from \\({Q}_{3}{Q}_{2}\\) to \\({Q}_{4}{Q}_{1}\\) ."}],"correct":"","image":"/images/econ-as-mcq/16_627_231_543_491_0.jpg"},{"id":12,"text":"Compared with Pakistan, Germany has a higher output of pharmaceuticals per unit of resources used. What could explain this?","options":[{"label":"A","text":"the existence of floating exchange rates"},{"label":"B","text":"the law of absolute advantage"},{"label":"C","text":"the Marshall-Lerner condition"},{"label":"D","text":"the terms of trade"}],"correct":""},{"id":13,"text":"Which statement about inflation is correct?","options":[{"label":"A","text":"Inflation will lead to a rise in exports."},{"label":"B","text":"Inflation will lead to a rise in real incomes."},{"label":"C","text":"Inflation will lead to a rise in the cost of living."},{"label":"D","text":"Inflation will lead to a rise in the purchasing power of money."}],"correct":""},{"id":14,"text":"Why is it that a country's balance of payments must always balance?","options":[{"label":"A","text":"Exchange rate changes will correct any deficit or surplus."},{"label":"B","text":"One country's deficit is balanced by another country's surplus."},{"label":"C","text":"The current account is balanced by the capital and financial accounts."},{"label":"D","text":"The government must act to correct any disequilibrium."}],"correct":""},{"id":15,"text":"Which argument for protection would be most relevant if the government of country X decided to exercise voluntary export restraint in its trade with country Y?","options":[{"label":"A","text":"Voluntary export restraint would achieve an immediate correction for X's balance of trade deficit."},{"label":"B","text":"Voluntary export restraint would cause the level of GDP to increase in country X."},{"label":"C","text":"Voluntary export restraint would help to negotiate improved trading conditions between X and Y."},{"label":"D","text":"Voluntary export restraint would help to reduce the level of unemployment in country X."}],"correct":""},{"id":16,"text":"The average price of a country's exports increased by 5\\% and the average price of its imports increased by 10\\%. What can definitely be concluded from this information?","options":[{"label":"A","text":"Its balance of trade will improve."},{"label":"B","text":"Its balance of trade will worsen."},{"label":"C","text":"Its terms of trade have improved."},{"label":"D","text":"Its terms of trade have worsened."}],"correct":""},{"id":17,"text":"The table shows the number of biscuits and cakes that can be produced by four workers in an hour. } Who has the greatest comparative advantage in producing biscuits?","options":[{"label":"A","text":"Laura"},{"label":"B","text":"Mo"},{"label":"C","text":"Nathan"},{"label":"D","text":"Omar"}],"correct":"","table":"<table><tr><td>Laura</td><td>Mo</td><td>Nathan</td><td>Omar</td></tr><tr><td>biscuits</td><td>6</td><td>10</td><td>13</td><td>8</td></tr><tr><td>cakes</td><td>3</td><td>10</td><td>12</td><td>16</td></tr></table>"},{"id":18,"text":"Which condition is necessary for a country's balance of payments on its current account to improve if it reduced its exchange rate?","options":[{"label":"A","text":"Both the price elasticities of supply for its imports and its exports must be elastic."},{"label":"B","text":"The importing country will buy all the excess supplies of its trading partner to clear the market."},{"label":"C","text":"The sum of the price elasticities of domestic demand for imports and the foreign demand for exports must be greater than one."},{"label":"D","text":"The trading partners need to agree on the maximum prices to be charged for imports and exports."}],"correct":""},{"id":19,"text":"The diagram shows the effect of the United States (US) imposing a tariff on the import of steel in 2018. quantity of steel Which statement about the impact of the tariff is correct?","options":[{"label":"A","text":"Consumer surplus falls from \\({\\mathrm{P}}_{1}\\mathrm{{TO}}\\) to PUO."},{"label":"B","text":"Domestic output increases from \\({\\mathrm{{OQ}}}_{1}\\) to \\({\\mathrm{{OQ}}}_{3}\\) ."},{"label":"C","text":"Imports fall from \\({\\mathrm{Q}}_{1}{\\mathrm{Q}}_{4}\\) to \\({\\mathrm{Q}}_{2}{\\mathrm{Q}}_{3}\\) ."},{"label":"D","text":"The tax revenue raised on imports is \\({\\mathrm{P}}_{1}\\) YWP."}],"correct":"","image":"/images/econ-as-mcq/19_391_271_1018_565_0.jpg"},{"id":20,"text":"In 2012, the Indian Government stated that it aimed to reduce its budget deficit to 5.1\\% of GDP. Which policy is most likely to help this aim in the short run?","options":[{"label":"A","text":"a decrease in import tariffs"},{"label":"B","text":"a decrease in the rate of interest"},{"label":"C","text":"an increase in the sale of state-owned assets"},{"label":"D","text":"an increase in government pension payments"}],"correct":""},{"id":21,"text":"What would make a policy of raising interest rates less likely to be effective in reducing inflation?","options":[{"label":"A","text":"Aggregate supply is increasing faster than aggregate demand."},{"label":"B","text":"Consumers expect prices to rise even faster in the future."},{"label":"C","text":"Consumers' spending is largely paid for on credit."},{"label":"D","text":"Interest rates are still higher abroad."}],"correct":""},{"id":22,"text":"The average price of a country's exports increased by 5% and the average price of its imports increased by 10%. What can definitely be concluded from this information?","options":[{"label":"A","text":"Its balance of trade will improve."},{"label":"B","text":"Its balance of trade will worsen."},{"label":"C","text":"Its terms of trade have improved."},{"label":"D","text":"Its terms of trade have worsened."}],"correct":""},{"id":23,"text":"The table shows the number of biscuits and cakes that can be produced by four workers in an hour. Who has the greatest comparative advantage in producing biscuits?","options":[{"label":"A","text":"Laura"},{"label":"B","text":"Mo"},{"label":"C","text":"Nathan"},{"label":"D","text":"Omar"}],"correct":"","table":"<table><tr><td></td><td>Laura</td><td>Mo</td><td>Nathan</td><td>Omar</td></tr><tr><td>biscuits</td><td>6</td><td>10</td><td>13</td><td>8</td></tr><tr><td>cakes</td><td>3</td><td>10</td><td>12</td><td>16</td></tr></table>"},{"id":24,"text":"In 2012, the Indian Government stated that it aimed to reduce its budget deficit to 5.1% of GDP. Which policy is most likely to help this aim in the short run?","options":[{"label":"A","text":"a decrease in import tariffs"},{"label":"B","text":"a decrease in the rate of interest"},{"label":"C","text":"an increase in the sale of state-owned assets"},{"label":"D","text":"an increase in government pension payments"}],"correct":""},{"id":25,"text":"Raising interest rates is proposed to reduce a balance of payments deficit. Which justification for this action is not valid?","options":[{"label":"A","text":"It will attract more foreign currency inflows."},{"label":"B","text":"It will encourage exporters to find new foreign markets."},{"label":"C","text":"It will lower the level of imported consumer goods."},{"label":"D","text":"It will put downward pressure on the exchange rate."}],"correct":""},{"id":26,"text":"Which policy would be likely to increase inflation?","options":[{"label":"A","text":"an increase in income tax"},{"label":"B","text":"an increase in interest rates"},{"label":"C","text":"limiting the amount banks can lend"},{"label":"D","text":"raising the level of import tariffs"}],"correct":""}];

const paper_03: MCQQuestion[] = [{"id":1,"text":"In the diagram JK is the initial production possibility curve for an economy producing computers and cars. What could cause the curve to shift to JL?","options":[{"label":"A","text":"a fall in output per worker in the car industry"},{"label":"B","text":"a fall in the level of competition in the car industry"},{"label":"C","text":"a rise in the potential workforce of the economy"},{"label":"D","text":"a rise in the price of cars"}],"correct":"","image":"/images/econ-as-mcq/24_571_266_651_459_0.jpg"},{"id":2,"text":"Consumers in country X buy some goods and services from private sector firms. Other goods and services are provided by the state. What is this type of economy?","options":[{"label":"A","text":"free market economy"},{"label":"B","text":"joint economy"},{"label":"C","text":"mixed economy"},{"label":"D","text":"planned economy"}],"correct":""},{"id":3,"text":"In 2017 the Bank of England introduced a new version of the £1 coin as there were concerns that large quantities of illegal \\(\\textsterling 1\\) coins had been put into circulation. Which characteristic of money did the illegal \\(\\textsterling 1\\) coins threaten?","options":[{"label":"A","text":"acceptability"},{"label":"B","text":"divisibility"},{"label":"C","text":"durability"},{"label":"D","text":"portability"}],"correct":""},{"id":4,"text":"Which statement is a positive statement?","options":[{"label":"A","text":"Low inflation is preferable to low unemployment as a government aim."},{"label":"B","text":"Low inflation will provide a more stable macro economy."},{"label":"C","text":"The government must intervene in all markets to improve resource allocation."},{"label":"D","text":"The government should cut income tax so living standards can improve."}],"correct":""},{"id":5,"text":"The diagrams show the effect of a change in the market for good X on the market for good Y. What can be concluded from the diagrams?","options":[{"label":"A","text":"X and Y are complements."},{"label":"B","text":"X and Y are in joint supply."},{"label":"C","text":"X and Y are substitutes."},{"label":"D","text":"Y is a derived demand from X."}],"correct":"","image":"/images/econ-as-mcq/25_353_1093_1087_514_0.jpg"},{"id":6,"text":"The diagram shows the average world price of coffee in US cents per pound weight (lb) between 1997 and 2005. Which event is consistent with the price behaviour shown in the specified time period?","options":[{"label":"A","text":"a continuous rise in the price of tea between 1997 and 2001"},{"label":"B","text":"the entry to the market of new producers of coffee between 1997 and 2001"},{"label":"C","text":"a series of good coffee harvests between 2001 and 2005"},{"label":"D","text":"increasing health worries about drinking coffee between 2001 and 2005"}],"correct":"","image":"/images/econ-as-mcq/26_418_267_965_622_0.jpg"},{"id":7,"text":"The diagram shows a shift in the supply curve for a product from \\({S}_{1}\\) to \\({S}_{2}\\) . What could cause this shift in the supply curve?","options":[{"label":"A","text":"an increase in the cost of producing the product"},{"label":"B","text":"an increase in the income of consumers of the product"},{"label":"C","text":"an increase in the demand for a product that is jointly supplied"},{"label":"D","text":"an increase in the price of the product"}],"correct":"","image":"/images/econ-as-mcq/26_673_1331_449_378_0.jpg"},{"id":8,"text":"The diagram shows the demand for and supply of a normal good. \\({E}_{1}\\) is the initial equilibrium position. Which changes could result in a new equilibrium \\({\\mathrm{E}}_{2}\\) ?","options":[{"label":"A","text":"a decrease in both the demand for and the supply of the good"},{"label":"B","text":"an increase in both the demand for and the supply of the good"},{"label":"C","text":"an increase in consumer incomes, and a decrease in the supply of the good"},{"label":"D","text":"an increase in the price of a complement to the good, and an increase in the supply of the good"}],"correct":"","image":"/images/econ-as-mcq/27_605_1090_586_426_0.jpg"},{"id":9,"text":"The table shows the market demand and market supply for kiwifruit over a year. At a market price of \\$3 per kg there is disequilibrium in the market. } Which action would the government have to take to achieve market equilibrium at a price of \\$3 per kg?","options":[{"label":"A","text":"impose an indirect tax of \\$2 per kg on kiwifruit"},{"label":"B","text":"purchase the entire supply at \\$3 per kg and sell at \\$2 per kg"},{"label":"C","text":"set a maximum price of \\$3 per kg"},{"label":"D","text":"subsidise kiwifruit production by \\$2 per kg"}],"correct":"","table":"<table><tr><td>total market demand (thousand tonnes)</td><td>total market supply (thousand tonnes)</td></tr><tr><td>1</td><td>220</td><td>120</td></tr><tr><td>2</td><td>190</td><td>130</td></tr><tr><td>3</td><td>160</td><td>140</td></tr><tr><td>4</td><td>130</td><td>150</td></tr><tr><td>5</td><td>100</td><td>160</td></tr></table>"},{"id":10,"text":"The cross-elasticity of demand of good S with respect to the price of good P is +1.5. The cross-elasticity of demand of good S with respect to the price of good R is -1.5. The cross-elasticity of demand of good P with respect to the price of good R is -1.5. What can be concluded about goods P, R and S?","options":[{"label":"A","text":"S and P are complements; P and R are substitutes."},{"label":"B","text":"S and P are complements; R is an inferior good."},{"label":"C","text":"S and P are substitutes; P and R are complements."},{"label":"D","text":"S and P are substitutes; R is an inferior good."}],"correct":""},{"id":11,"text":"A government wishes to impose a tax on a good so that the consumer pays most of the tax increase. Which type of elasticity would best achieve this aim?","options":[{"label":"A","text":"high price elasticity of supply"},{"label":"B","text":"low price elasticity of supply"},{"label":"C","text":"unitary price elasticity of supply"},{"label":"D","text":"perfectly inelastic price elasticity of supply"}],"correct":""},{"id":12,"text":"Why does the production of public goods have to be financed by the government?","options":[{"label":"A","text":"One person's consumption of a public good means it is not available for anyone else."},{"label":"B","text":"People are able to consume public goods without paying for them."},{"label":"C","text":"Private sector firms will charge a price significantly above cost for public goods."},{"label":"D","text":"The cost of producing public goods is higher in the private sector."}],"correct":""},{"id":13,"text":"Which payment is a transfer payment?","options":[{"label":"A","text":"households' payments of indirect taxes"},{"label":"B","text":"government pension payments"},{"label":"C","text":"payments between firms for the supply of raw materials"},{"label":"D","text":"payment of salaries"}],"correct":""},{"id":14,"text":"A government wishes to reduce the consumption of alcohol. Which policy will it use to achieve this aim by fixing the price of alcohol?","options":[{"label":"A","text":"fix maximum price above market price"},{"label":"B","text":"fix maximum price below market price"},{"label":"C","text":"fix minimum price above market price"},{"label":"D","text":"fix minimum price below market price"}],"correct":""},{"id":15,"text":"According to the theory of comparative advantage, what makes trade beneficial between two countries?","options":[{"label":"A","text":"Each country has different goods to sell and different tastes."},{"label":"B","text":"Each country has different opportunity costs of production."},{"label":"C","text":"One country has the absolute advantage in producing both goods."},{"label":"D","text":"The prices of goods are different between each country."}],"correct":""},{"id":16,"text":"A government decides to increase a quota on an imported good. What is likely to happen?","options":[{"label":"A","text":"The demand for the good will fall."},{"label":"B","text":"The good will become more expensive."},{"label":"C","text":"The government's revenue will decline."},{"label":"D","text":"There will be more of the good imported."}],"correct":""},{"id":17,"text":"The diagram shows aggregate demand (AD) and aggregate supply (AS) for an economy. What is most likely to cause the shift from \\({\\mathrm{{AS}}}_{1}\\) to \\({\\mathrm{{AS}}}_{2}\\) ?","options":[{"label":"A","text":"a decrease in the exchange rate"},{"label":"B","text":"a decrease in the price level"},{"label":"C","text":"a fall in immigration"},{"label":"D","text":"a fall in the average level of wages"}],"correct":"","image":"/images/econ-as-mcq/31_601_235_591_473_0.jpg"},{"id":18,"text":"Country X places a tariff of 20\\% on steel products imported from country Y. Country Y retaliates with a 20\\% tariff on computers imported from country X. What is a certain economic consequence of these actions?","options":[{"label":"A","text":"The balance of payments of country X and country Y will remain unchanged."},{"label":"B","text":"The exchange rate value on which trade between the two countries is based will be maintained."},{"label":"C","text":"The profits and employment of domestic firms in both countries will be preserved."},{"label":"D","text":"The volume of bilateral trade between country X and country Y will be reduced."}],"correct":""},{"id":19,"text":"A country has a floating exchange rate. An increase in which variable within that country can cause its exchange rate to appreciate?","options":[{"label":"A","text":"employment levels"},{"label":"B","text":"income levels"},{"label":"C","text":"interest rates"},{"label":"D","text":"price levels"}],"correct":""},{"id":20,"text":"The graph shows the change in the current account of Belgium's balance of payments from 2016 to 2017. What will be the most likely impact of the change shown by the graph on Belgium's domestic economy?","options":[{"label":"A","text":"a fall in the rate of economic growth"},{"label":"B","text":"a fall in the foreign currency reserves"},{"label":"C","text":"a fall in the number of unemployed"},{"label":"D","text":"a fall in the rate of inflation"}],"correct":"","image":"/images/econ-as-mcq/32_590_1377_616_407_0.jpg"},{"id":21,"text":"Which policy would be likely to increase inflation?","options":[{"label":"A","text":"an increase in income tax"},{"label":"B","text":"an increase in interest rates"},{"label":"C","text":"limiting the amount banks can lend"},{"label":"D","text":"raising the level of import tariffs"}],"correct":""},{"id":22,"text":"What are the components of aggregate demand?","options":[{"label":"A","text":"consumption + investment + government spending + (exports - imports)"},{"label":"B","text":"consumption + investment + taxation - (exports - imports)"},{"label":"C","text":"consumption + saving + taxation - (exports - imports)"},{"label":"D","text":"consumption + saving + taxation + (exports - imports)"}],"correct":""},{"id":23,"text":"The diagram shows aggregate demand (AD) and aggregate supply (AS) for an economy. What is most likely to cause the shift from \\( {\\mathrm{{AS}}}_{1} \\) to \\( {\\mathrm{{AS}}}_{2} \\) ?","options":[{"label":"A","text":"a decrease in the exchange rate"},{"label":"B","text":"a decrease in the price level"},{"label":"C","text":"a fall in immigration"},{"label":"D","text":"a fall in the average level of wages"}],"correct":"","image":"/images/econ-as-mcq/31_601_235_591_473_0.jpg"},{"id":24,"text":"Country X places a tariff of 20% on steel products imported from country Y. Country Y retaliates with a 20% tariff on computers imported from country X. What is a certain economic consequence of these actions?","options":[{"label":"A","text":"The balance of payments of country X and country Y will remain unchanged."},{"label":"B","text":"The exchange rate value on which trade between the two countries is based will be maintained."},{"label":"C","text":"The profits and employment of domestic firms in both countries will be preserved."},{"label":"D","text":"The volume of bilateral trade between country X and country Y will be reduced."}],"correct":""},{"id":25,"text":"What is an example of the use of monetary policy?","options":[{"label":"A","text":"a cut in the rate of corporation tax"},{"label":"B","text":"a reduction in interest rates"},{"label":"C","text":"- a switch from direct to indirect taxation"},{"label":"D","text":"the introduction of maximum price controls to reduce inflation"}],"correct":""},{"id":26,"text":"What does the Marshall-Lerner condition state must be present for a depreciation of a currency to cause an improvement in the current account balance?","options":[{"label":"A","text":"The price elasticity of demand for exports and the price elasticity of demand for imports are both greater than one."},{"label":"B","text":"The price elasticity of demand for exports and the price elasticity of demand for imports are both less than one."},{"label":"C","text":"The sum of the price elasticity of demand for exports and the price elasticity of demand for imports is greater than one."},{"label":"D","text":"The sum of the price elasticity of demand for exports and the price elasticity of demand for imports is less than one."}],"correct":""},{"id":27,"text":"Raising interest rates is proposed to reduce a balance of payments deficit. Which justification for this action is not valid?","options":[{"label":"A","text":"It will attract more foreign currency inflows."},{"label":"B","text":"It will encourage exporters to find new foreign markets."},{"label":"C","text":"It will lower the level of imported consumer goods."},{"label":"D","text":"It will put downward pressure on the exchange rate."}],"correct":""}];

const paper_04: MCQQuestion[] = [{"id":1,"text":"A production possibility curve shows the combinations of outputs an economy can produce using all available resources. At which points on the diagram are all available resources used? manufactures (units)","options":[{"label":"A","text":"W and X only"},{"label":"B","text":"W, X and Z only"},{"label":"C","text":"W, X, Y and Z"},{"label":"D","text":"Z and Y only"}],"correct":"","image":"/images/econ-as-mcq/34_601_336_591_406_0.jpg"},{"id":2,"text":"What is a normative economic action based on?","options":[{"label":"A","text":"fact"},{"label":"B","text":"market forces"},{"label":"C","text":"opinion"},{"label":"D","text":"price changes"}],"correct":""},{"id":3,"text":"Which function of money overcomes the double coincidence of wants problem that exists in a barter system?","options":[{"label":"A","text":"medium of exchange"},{"label":"B","text":"standard of deferred payment"},{"label":"C","text":"store of value"},{"label":"D","text":"unit of account"}],"correct":""},{"id":4,"text":"The diagram shows a supply curve for chicken. What explains why the supply curve for chicken slopes upwards?","options":[{"label":"A","text":"An increase in the demand for chicken will bring about a rise in supply."},{"label":"B","text":"Farmers' productivity rises as the price rises."},{"label":"C","text":"Increased production leads to a reduction in costs."},{"label":"D","text":"The cost of additional chicken production rises as output increases."}],"correct":"","image":"/images/econ-as-mcq/35_650_1013_496_469_0.jpg"},{"id":5,"text":"Demand curves are drawn ceteris paribus. Which 'other things' are not required to remain the same when an individual's demand curve for ice cream is constructed?","options":[{"label":"A","text":"the consumer's income"},{"label":"B","text":"the consumer's tastes and preferences"},{"label":"C","text":"the price of fresh fruit"},{"label":"D","text":"the price of ice cream"}],"correct":""},{"id":6,"text":"What is the measure of cross-elasticity of demand for good X in terms of good Y?","options":[{"label":"A","text":"the change in the demand for \\(X\\) divided by the change in the price of \\(Y\\)"},{"label":"B","text":"the change in the price of \\(X\\) divided by the change in the demand for \\(Y\\)"},{"label":"C","text":"the percentage change in the demand for \\(X\\) divided by the percentage change in the price of \\(Y\\)"},{"label":"D","text":"the percentage change in the demand for \\(Y\\) divided by the percentage change in the price of X"}],"correct":""},{"id":7,"text":"When will the price mechanism be least likely to reallocate resources to meet a change in consumer preferences?","options":[{"label":"A","text":"when the government removes all price controls"},{"label":"B","text":"when the new preferences are for more public goods"},{"label":"C","text":"when the supply of factors of production is limited"},{"label":"D","text":"when there is a redistribution of income"}],"correct":""},{"id":8,"text":"A firm estimates that the price elasticity of supply of its product is +1.5. What does this indicate?","options":[{"label":"A","text":"The firm has available stock."},{"label":"B","text":"The firm has no excess capacity."},{"label":"C","text":"The firm operates in a competitive market."},{"label":"D","text":"The firm raises its price by 10\\% and its total revenue increases by 15\\%."}],"correct":""},{"id":9,"text":"A rise in the price of a good is accompanied by an increase in the quantity demanded. What could explain this?","options":[{"label":"A","text":"Consumers spend a high proportion of disposable income on the good."},{"label":"B","text":"The price of a complementary good has also increased."},{"label":"C","text":"The price of the good is taken to be an indication of the level of quality."},{"label":"D","text":"The substitute goods are all very much more expensive."}],"correct":""},{"id":10,"text":"What causes the demand curve for an inferior good to shift to the right?","options":[{"label":"A","text":"a decrease in consumer incomes"},{"label":"B","text":"a decrease in income tax"},{"label":"C","text":"a decrease in the price of a substitute good"},{"label":"D","text":"a decrease in the price of the good"}],"correct":""},{"id":11,"text":"The diagrams show the effect of a change in the market for good X on the market for good Y. What is the most likely relationship between the two goods?","options":[{"label":"A","text":"X and Y are complements."},{"label":"B","text":"X and Y are demerit goods."},{"label":"C","text":"X and Y are in joint supply."},{"label":"D","text":"X and Y are substitutes."}],"correct":"","image":"/images/econ-as-mcq/38_350_234_1096_479_0.jpg"},{"id":12,"text":"To improve its financial position, a government decided to reduce expenditure on investment in the public sector. There was not a fall in economic growth. What was the most likely effect of the government's action?","options":[{"label":"A","text":"An original budget deficit was reduced."},{"label":"B","text":"An original budget surplus was reduced."},{"label":"C","text":"Consumer expenditure decreased."},{"label":"D","text":"Public sector productivity decreased."}],"correct":""},{"id":13,"text":"The National Library Board of Singapore is a public sector organisation that finances and manages the state libraries. What is the most likely reason for this?","options":[{"label":"A","text":"Libraries are public goods."},{"label":"B","text":"Libraries are merit goods."},{"label":"C","text":"The cost of providing library services would be greater in the private sector."},{"label":"D","text":"The opportunity cost to the public sector of providing library services is zero."}],"correct":""},{"id":14,"text":"The diagram shows a shift in an economy’s aggregate demand curve from \\({\\mathrm{{AD}}}_{1}\\) to \\({\\mathrm{{AD}}}_{2}\\) . What could not be a cause of the shift?","options":[{"label":"A","text":"a decrease in income tax"},{"label":"B","text":"a decrease in the price of goods"},{"label":"C","text":"an increase in money wage rates"},{"label":"D","text":"an increase in the money supply"}],"correct":"","image":"/images/econ-as-mcq/42_606_1308_585_466_0.jpg"},{"id":15,"text":"Which item is not included in the current account on the balance of payments statement?","options":[{"label":"A","text":"the balancing item"},{"label":"B","text":"the export of services"},{"label":"C","text":"the import of goods"},{"label":"D","text":"the interest received from investment overseas"}],"correct":""},{"id":16,"text":"The prices of a country's exports rise by 5\\% while the prices of its imports fall by 5\\%. What will definitely improve in the country as a result of these changes?","options":[{"label":"A","text":"balance of trade"},{"label":"B","text":"current account balance"},{"label":"C","text":"exchange rate"},{"label":"D","text":"terms of trade"}],"correct":""},{"id":17,"text":"What is not a form of protectionism?","options":[{"label":"A","text":"embargoes"},{"label":"B","text":"increase in sales tax (VAT)"},{"label":"C","text":"subsidies on goods for export"},{"label":"D","text":"voluntary export restraints"}],"correct":""},{"id":18,"text":"Two countries, X and Y, produce food and drink. The table shows how many hours it takes them to produce one unit of each. } What will be the result if country Y doubles its productivity in the output of drink and both countries produce only one good according to comparative advantage?","options":[{"label":"A","text":"X will continue to produce drink."},{"label":"B","text":"Y will produce drink instead of food."},{"label":"C","text":"World drink production will rise."},{"label":"D","text":"World food production will fall."}],"correct":"","table":"<table><tr><td>food</td><td>drink</td></tr><tr><td>X</td><td>10</td><td>2</td></tr><tr><td>Y</td><td>20</td><td>12</td></tr></table>"},{"id":19,"text":"An increase in which variable is a contractionary monetary policy?","options":[{"label":"A","text":"the budget deficit"},{"label":"B","text":"the budget surplus"},{"label":"C","text":"the interest rate"},{"label":"D","text":"the money supply"}],"correct":""},{"id":20,"text":"What are government monetary policies that would be the most effective in a global recession?","options":[{"label":"A","text":"allowing the rate of interest to fluctuate and increasing business taxation"},{"label":"B","text":"increasing the budget surplus and raising tariffs on imports"},{"label":"C","text":"keeping the rate of interest very low and increasing the money supply"},{"label":"D","text":"raising the rate of interest and restricting the money supply"}],"correct":""},{"id":21,"text":"The diagram shows a shift in an economy’s aggregate demand curve from \\( {\\mathrm{{AD}}}_{1} \\) to \\( {\\mathrm{{AD}}}_{2} \\) . What could not be a cause of the shift?","options":[{"label":"A","text":"a decrease in income tax"},{"label":"B","text":"a decrease in the price of goods"},{"label":"C","text":"an increase in money wage rates"},{"label":"D","text":"an increase in the money supply"}],"correct":"","image":"/images/econ-as-mcq/42_606_1308_585_466_0.jpg"},{"id":22,"text":"The prices of a country's exports rise by 5% while the prices of its imports fall by 5%. What will definitely improve in the country as a result of these changes?","options":[{"label":"A","text":"balance of trade"},{"label":"B","text":"current account balance"},{"label":"C","text":"exchange rate"},{"label":"D","text":"terms of trade"}],"correct":""},{"id":23,"text":"Two countries, X and Y, produce food and drink. The table shows how many hours it takes them to produce one unit of each. What will be the result if country Y doubles its productivity in the output of drink and both countries produce only one good according to comparative advantage?","options":[{"label":"A","text":"X will continue to produce drink."},{"label":"B","text":"Y will produce drink instead of food."},{"label":"C","text":"World drink production will rise."},{"label":"D","text":"World food production will fall."}],"correct":"","table":"<table><tr><td></td><td>food</td><td>drink</td></tr><tr><td>X</td><td>10</td><td>2</td></tr><tr><td>Y</td><td>20</td><td>12</td></tr></table>"},{"id":24,"text":"What could be described as an expansionary fiscal policy?","options":[{"label":"A","text":"a decrease in the budget deficit"},{"label":"B","text":"a decrease in the budget surplus"},{"label":"C","text":"a decrease in the exchange rate"},{"label":"D","text":"a decrease in the money supply"}],"correct":""},{"id":25,"text":"An economy is experiencing accelerating cost-push inflation. Which group is likely to be least concerned by this?","options":[{"label":"A","text":"borrowers"},{"label":"B","text":"consumers"},{"label":"C","text":"creditors"},{"label":"D","text":"exporters"}],"correct":""},{"id":26,"text":"Which statement about changing price levels is correct?","options":[{"label":"A","text":"Anyone on a fixed income has rising real income during deflation."},{"label":"B","text":"Government revenue from indirect taxes falls during inflation."},{"label":"C","text":"Producers prefer deflation to inflation."},{"label":"D","text":"Savers prefer index-linked savings when there is deflation rather than inflation."}],"correct":""},{"id":27,"text":"What would be likely to decrease inflation in an economy?","options":[{"label":"A","text":"a decrease in consumer saving"},{"label":"B","text":"a decrease in unemployment"},{"label":"C","text":"an increase in labour productivity"},{"label":"D","text":"an increase in taxes on imports"}],"correct":""},{"id":28,"text":"Which change in economic circumstances is most likely to lead to a reduction in the rate of domestic inflation in an economy?","options":[{"label":"A","text":"a depreciation in the currency"},{"label":"B","text":"a reduction in the productivity of labour"},{"label":"C","text":"a worldwide recession"},{"label":"D","text":"an increase in direct taxes to finance increased welfare payments"}],"correct":""}];

const paper_05: MCQQuestion[] = [{"id":1,"text":"The Indian government operates a pension scheme. Which statement about this scheme would be classed as normative?","options":[{"label":"A","text":"To be eligible, individuals must be above the age of 60 and live below the poverty line."},{"label":"B","text":"In January 2020, eligible individuals aged over 70 received 500 rupees per month."},{"label":"C","text":"In 2018, the Supreme Court said the government must review pension payments because they are unrealistic."},{"label":"D","text":"In January 2020, the Indian government announced that it might increase the payment to 1000 rupees per month."}],"correct":""},{"id":2,"text":"What is not a function of money?","options":[{"label":"A","text":"It is a medium of exchange."},{"label":"B","text":"It is a store of value."},{"label":"C","text":"It is a unit of account."},{"label":"D","text":"It is a measure of satisfaction."}],"correct":""},{"id":3,"text":"The producer of a good with a price-elastic demand observes that a rise in its price is accompanied by a rise in total revenue. What might explain this?","options":[{"label":"A","text":"The good is an inferior good."},{"label":"B","text":"The rise in price was due to an increase in demand for the good."},{"label":"C","text":"The supply of the good was inadequate to meet the demand."},{"label":"D","text":"The supply of the good was price-inelastic."}],"correct":""},{"id":4,"text":"What will increase the producer surplus of farmers that grow carrots?","options":[{"label":"A","text":"a decrease in the demand for carrots"},{"label":"B","text":"a decrease in the price of carrot seed"},{"label":"C","text":"a decrease in the price of cabbage"},{"label":"D","text":"a decrease in the subsidy on carrots"}],"correct":""},{"id":5,"text":"Why does an individual's demand curve generally slope downwards to the right?","options":[{"label":"A","text":"The additional satisfaction an individual gets from consuming most goods decreases as consumption increases."},{"label":"B","text":"The additional satisfaction an individual gets from consumption decreases as income rises."},{"label":"C","text":"The individual has finite income which is used to attempt to satisfy many wants."},{"label":"D","text":"For most goods the price charged by producers falls as the quantity purchased increases."}],"correct":""},{"id":6,"text":"What is price elasticity of supply?","options":[{"label":"A","text":"the change in the quantity supplied when a price changes"},{"label":"B","text":"the change in the quantity supplied when demand changes"},{"label":"C","text":"the comparison of the proportionate change in supply to the proportionate change in demand"},{"label":"D","text":"the comparison of the proportionate change in supply to the proportionate change in price"}],"correct":""},{"id":7,"text":"What is necessary for consumer surplus to be zero?","options":[{"label":"A","text":"Demand is perfectly elastic."},{"label":"B","text":"Demand is perfectly inelastic."},{"label":"C","text":"Supply is perfectly elastic."},{"label":"D","text":"Supply is perfectly inelastic."}],"correct":""},{"id":8,"text":"When will the price mechanism not function as a system for allocating goods?","options":[{"label":"A","text":"when the government bans advertising"},{"label":"B","text":"when the government maintains an effective maximum price"},{"label":"C","text":"when there is a limited supply of the good"},{"label":"D","text":"when there is a powerful company able to set the market price"}],"correct":""},{"id":9,"text":"The table shows data from a bus company that was privatised in 2013. } What is the most likely conclusion that can be made from the data?","options":[{"label":"A","text":"Average prices were higher in 2012 than 2015."},{"label":"B","text":"Average prices were higher in 2015 than 2014."},{"label":"C","text":"The number of passenger journeys remained the same since privatisation."},{"label":"D","text":"Profits have increased since privatisation."}],"correct":"","table":"<table><tr><td>revenue $000</td><td>passenger journeys percentage change from previous year (%)</td></tr><tr><td>2012</td><td>470</td><td>\\(+ 5\\)</td></tr><tr><td>2013</td><td>495</td><td>\\(+ 2\\)</td></tr><tr><td>2014</td><td>430</td><td>-2</td></tr><tr><td>2015</td><td>440</td><td>-1</td></tr></table>"},{"id":10,"text":"The diagram shows the market for electricity in a country that has a fixed supply of electricity and introduces a maximum price to make it affordable for poorer households. What will be the effect of this?","options":[{"label":"A","text":"It will encourage producers to build more power stations in the future."},{"label":"B","text":"It will encourage the development of renewable sources of electricity."},{"label":"C","text":"It will increase producer surplus."},{"label":"D","text":"It will increase the probability of power cuts."}],"correct":"","image":"/images/econ-as-mcq/50_473_270_855_597_0.jpg"},{"id":11,"text":"What is an example of a transfer payment?","options":[{"label":"A","text":"government spending on hospitals"},{"label":"B","text":"government spending on motorways"},{"label":"C","text":"minimum wage"},{"label":"D","text":"welfare benefits"}],"correct":""},{"id":12,"text":"The diagram shows the change in the supply curve of imports, \\(S - {S}_{1}\\) to curve \\(S - {S}_{2}\\) , after the introduction by the government of a trade protection measure. What is the form of protection?","options":[{"label":"A","text":"an ad valorem tariff"},{"label":"B","text":"an embargo"},{"label":"C","text":"a quota"},{"label":"D","text":"a specific tariff"}],"correct":"","image":"/images/econ-as-mcq/51_611_995_577_482_0.jpg"},{"id":13,"text":"Why might a country's government impose a tax on fuel exports?","options":[{"label":"A","text":"to encourage domestic refineries to increase production"},{"label":"B","text":"to improve the country's trade balance"},{"label":"C","text":"to reduce fuel prices for domestic consumers"},{"label":"D","text":"to reduce the government's budget surplus"}],"correct":""},{"id":14,"text":"What leads to a fall in a country's terms of trade?","options":[{"label":"A","text":"a fall in the price of exports relative to the price of imports"},{"label":"B","text":"a fall in the price of imports relative to the price of exports"},{"label":"C","text":"a fall in the quantity of exports relative to the quantity of imports"},{"label":"D","text":"a fall in the quantity of imports relative to the quantity of exports"}],"correct":""},{"id":15,"text":"What would be the best policy to increase the value of a currency?","options":[{"label":"A","text":"Impose tariffs on imported goods with price-inelastic demand."},{"label":"B","text":"Increase interest rates."},{"label":"C","text":"Reduce income tax."},{"label":"D","text":"Sell the currency on the foreign exchange markets."}],"correct":""},{"id":16,"text":"The central bank of an economy decides to raise interest rates in order to attract capital inflows and improve the financial account of the balance of payments. When is the central bank's decision least likely to be effective?","options":[{"label":"A","text":"when the currency of the economy is expected to lose its value"},{"label":"B","text":"when the economy is politically and economically stable"},{"label":"C","text":"; when the interest rate of the economy is higher than that of other countries"},{"label":"D","text":") when the reserves of foreign currencies held by the central bank are high and rising"}],"correct":""},{"id":17,"text":"What could be described as an expansionary fiscal policy?","options":[{"label":"A","text":"a decrease in the budget deficit"},{"label":"B","text":"a decrease in the budget surplus"},{"label":"C","text":"a decrease in the exchange rate"},{"label":"D","text":"a decrease in the money supply"}],"correct":""},{"id":18,"text":"Why will a contractionary monetary policy reduce inflation?","options":[{"label":"A","text":"Banks will lend more."},{"label":"B","text":"Consumers will have higher disposable income."},{"label":"C","text":"Consumers will pay more tax."},{"label":"D","text":"Consumers will save more."}],"correct":""},{"id":19,"text":"The government of a country is worried about a large deficit on the current account of its balance of payments and an increasing rate of inflation. The country has a fixed exchange rate for its currency. Which policy measure is most likely to help the government to reduce the current account deficit and lower the rate of inflation?","options":[{"label":"A","text":"devaluation of the currency"},{"label":"B","text":"increasing government spending"},{"label":"C","text":"decreasing the direct taxes"},{"label":"D","text":"increasing the interest rate"}],"correct":""},{"id":20,"text":"The diagram shows the change in the supply curve of imports, \\( S - {S}_{1} \\) to curve \\( S - {S}_{2} \\) , after the introduction by the government of a trade protection measure. What is the form of protection?","options":[{"label":"A","text":"an ad valorem tariff"},{"label":"B","text":"an embargo"},{"label":"C","text":"a quota"},{"label":"D","text":"a specific tariff"}],"correct":"","image":"/images/econ-as-mcq/51_611_995_577_482_0.jpg"},{"id":21,"text":"A government aims to reduce unemployment through expansionary fiscal policy and borrows more from the commercial banks, increasing its borrowing requirement. What will be the result?","options":[{"label":"A","text":"a decrease in the budget deficit"},{"label":"B","text":"a decrease in the national debt"},{"label":"C","text":"an increase in the balance of payments deficit on the current account"},{"label":"D","text":"an increase in the interest rates"}],"correct":""},{"id":22,"text":"A government wants to use an expansionary monetary policy. What should the government increase?","options":[{"label":"A","text":"credit regulations"},{"label":"B","text":"the exchange rate"},{"label":"C","text":"the interest rate"},{"label":"D","text":"the money supply"}],"correct":""},{"id":23,"text":"Over a period of a year, the annual rate of inflation becomes negative. Which statement must be correct?","options":[{"label":"A","text":"The cost of living has fallen."},{"label":"B","text":"The purchasing power of money has fallen."},{"label":"C","text":"The standard of living has increased."},{"label":"D","text":"There has been an increase in the Consumer Price Index."}],"correct":""},{"id":24,"text":"An economy is experiencing accelerating cost-push inflation. Which group is likely to be least concerned by this?","options":[{"label":"A","text":"borrowers"},{"label":"B","text":"consumers"},{"label":"C","text":"creditors"},{"label":"D","text":"exporters"}],"correct":""}];

const paper_06: MCQQuestion[] = [{"id":1,"text":"Which list has the most words that are more likely to relate to a positive statement than to a normative statement?","options":[{"label":"A","text":"describe, better, should, value, emotion"},{"label":"B","text":"bias, objective, ought, opinion, tastes"},{"label":"C","text":"contestable, is, motive, subjective, moral"},{"label":"D","text":"actual, ethics, fact, was, testable"}],"correct":""},{"id":2,"text":"What is the main characteristic of a planned economy?","options":[{"label":"A","text":"All goods and services are produced by privately-owned firms."},{"label":"B","text":"All goods and services are produced by state-owned firms."},{"label":"C","text":"Privately-owned firms produce private goods and state-owned firms produce public goods."},{"label":"D","text":"The price mechanism allocates scarce resources through the actions of buyers and sellers."}],"correct":""},{"id":3,"text":"In which situation is the price elasticity of supply for a product most likely to be relatively low?","options":[{"label":"A","text":"Demand for the product comes from a wide range of customers."},{"label":"B","text":"Producers in closely related industries can easily switch to making the product."},{"label":"C","text":"Manufacture of the product requires highly skilled labour."},{"label":"D","text":"The main raw material used in the production of the product is in abundant supply."}],"correct":""},{"id":4,"text":"The diagram shows supply and demand for a good. If price increases from \\({\\mathrm{P}}_{1}\\) to \\({\\mathrm{P}}_{2}\\) , what will happen to consumer surplus?","options":[{"label":"A","text":"It falls from ABE to A."},{"label":"B","text":"It falls from CDFG to BCD."},{"label":"C","text":"It increases from CF to BCEF."},{"label":"D","text":"It increases from CF to BCEFH."}],"correct":"","image":"/images/econ-as-mcq/56_627_585_541_440_0.jpg"},{"id":5,"text":"What can be concluded about the roles of demand and supply in a free market?","options":[{"label":"A","text":"They allocate resources to the greatest needs."},{"label":"B","text":"They ensure that goods and services are distributed equally."},{"label":"C","text":"They are both significant in setting the market price."},{"label":"D","text":"They ensure that everyone can benefit from the good or service provided."}],"correct":""},{"id":6,"text":"A firm has a successful advertising campaign for a good. Which combination shows the impact on demand or supply and the associated reason?","options":[{"label":"A","text":"a leftward shift in the good's demand curve, as increased advertising cost raises the price of the product and reduces its demand"},{"label":"B","text":"a rightward shift in the good's supply curve, as the advertising cost of the firm increases"},{"label":"C","text":"a rightward shift in the good's demand curve, as successful advertising increases demand"},{"label":"D","text":"a leftward shift in the good's supply curve, as successful advertising enables firms to sell more"}],"correct":""},{"id":7,"text":"What would be the most likely reason for a firm's decision to calculate the price elasticity of demand for its product?","options":[{"label":"A","text":"to provide retail statistics for the government"},{"label":"B","text":"to predict the change in its total revenue after it raises prices"},{"label":"C","text":"to calculate the firm's competitive position"},{"label":"D","text":"to enable the firm to complete consumer satisfaction surveys"}],"correct":""},{"id":8,"text":"The cross-elasticity of demand of good S with respect to the price of good P is +1.5. The cross-elasticity of demand of good S with respect to the price of good R is -1.5. The cross-elasticity of demand of good P with respect to the price of good R is -1.5. What can be concluded about goods P, R and S?","options":[{"label":"A","text":"S and P are complements; P and R are substitutes."},{"label":"B","text":"S and P are complements; R is an inferior good."},{"label":"C","text":"S and P are substitutes; P and R are complements."},{"label":"D","text":"S and P are substitutes; R is an inferior good."}],"correct":""},{"id":9,"text":"Which combination of events is most likely to leave the demand curve for a normal good in the same position?","options":[{"label":"A","text":"a decrease in consumer incomes and an increase in the price of a substitute good"},{"label":"B","text":"a decrease in consumer incomes and an increase in the price of the good"},{"label":"C","text":"an increase in consumer incomes and an increase in the price of a substitute good"},{"label":"D","text":"an increase in consumer incomes and an increase in the price of the good"}],"correct":""},{"id":10,"text":"What does not happen when price acts as a means to allocate resources?","options":[{"label":"A","text":"Price determines the supply of public goods."},{"label":"B","text":"Price operates in the markets for both goods and factors of production."},{"label":"C","text":"Price recognises consumers' ability to pay rather than consumers' needs."},{"label":"D","text":"Price signals to producers which goods are most profitable."}],"correct":""},{"id":11,"text":"Which statement about market disequilibrium is correct?","options":[{"label":"A","text":"Price is likely to change."},{"label":"B","text":"Supply is equal to demand."},{"label":"C","text":"The government must intervene."},{"label":"D","text":"There must be shortages."}],"correct":""},{"id":12,"text":"Which combination of tax changes is most likely to be regressive in a developed economy?","options":[{"label":"A","text":"increasing the rate of wealth tax and raising the rate of sales tax (VAT) on luxury products"},{"label":"B","text":"introducing a tax on owning property based on its sales value and increasing the rate of income tax"},{"label":"C","text":"reducing the basic rate of income tax and increasing the duty on fuel"},{"label":"D","text":"removing the tax-free allowance for income tax and extending sales tax (VAT) to include all food"}],"correct":""},{"id":13,"text":"What is definitely not involved when a transfer payment is made?","options":[{"label":"A","text":"bank deposits"},{"label":"B","text":"cash"},{"label":"C","text":"government"},{"label":"D","text":"production"}],"correct":""},{"id":14,"text":"What is unlikely to occur with an increase in the provision of public goods?","options":[{"label":"A","text":"consumer non-excludability"},{"label":"B","text":"improved use of resources"},{"label":"C","text":"opportunity cost"},{"label":"D","text":"reduction in tax"}],"correct":""},{"id":15,"text":"In 2020, shops reported a fall in sales as domestic demand in an economy fell. However, the impact on the overall economy was not as unfavourable as was first feared. What might have lessened the impact on the economy?","options":[{"label":"A","text":"Exports increased."},{"label":"B","text":"Imports increased."},{"label":"C","text":"Savings increased."},{"label":"D","text":"Taxes increased."}],"correct":""},{"id":16,"text":"What does a trade-weighted exchange rate attempt to take account of?","options":[{"label":"A","text":"a country's terms of trade"},{"label":"B","text":"international trade as a proportion of a country's national income"},{"label":"C","text":"the relative value of international trade done with a country's trading partners"},{"label":"D","text":"the size of a country's current account surplus or deficit"}],"correct":""},{"id":17,"text":"What will lead to an improvement in the terms of trade?","options":[{"label":"A","text":"Export prices fall by 10\\% and import prices fall by 5\\%."},{"label":"B","text":"Export prices fall by 10\\% and import prices rise by 5\\%."},{"label":"C","text":"Export prices rise by 5\\% and import prices rise by 10\\%."},{"label":"D","text":"Export prices rise by 10\\% and import prices rise by 5\\%."}],"correct":""},{"id":18,"text":"The diagram shows the annual inflation rate in an economy. What can be deduced from the graph?","options":[{"label":"A","text":"The price of goods and services fell between 2013 and 2014."},{"label":"B","text":"Disinflation took place between 2014 and 2015."},{"label":"C","text":"The purchasing power of money increased between 2014 and 2015."},{"label":"D","text":"The cost of living fell from 2016 onwards."}],"correct":"","image":"/images/econ-as-mcq/60_445_937_905_479_0.jpg"},{"id":19,"text":"A country operates a fixed exchange rate system. What will put pressure on the country to devalue its currency?","options":[{"label":"A","text":"a decrease in the country's inflation rate relative to the inflation rates of other countries"},{"label":"B","text":"a decrease in the tariffs on its products imposed by other countries"},{"label":"C","text":"an increase in its current account balance of payments deficit with other countries"},{"label":"D","text":"an increase in the country's interest rate relative to the interest rates of other countries"}],"correct":""},{"id":20,"text":"A small country imposes no tariffs and has a perfectly elastic supply of smartphones from the rest of the world. Which statement is correct after the imposition of a tariff?","options":[{"label":"A","text":"The domestic demand for smartphones will rise."},{"label":"B","text":"The domestic price of smartphones will rise."},{"label":"C","text":"The government will lose tax revenue."},{"label":"D","text":"The supply of imports will increase."}],"correct":""},{"id":21,"text":"In a recent year, Japanese car manufacturers agreed to limit exports of cars to the USA. Which form of protectionism is this?","options":[{"label":"A","text":"an embargo"},{"label":"B","text":"an export subsidy"},{"label":"C","text":"a quota"},{"label":"D","text":"voluntary export restraint"}],"correct":""},{"id":22,"text":"The diagram shows a shift in a country's short-run aggregate supply curve from SRAS1 to SRAS2. The country imports oil. Why might an increase in the world price of oil have caused this shift?","options":[{"label":"A","text":"A rise in inflation is expected."},{"label":"B","text":"Consumers face a fall in their disposable income."},{"label":"C","text":"Domestic firms' costs have increased."},{"label":"D","text":"The government reduces tax on oil and petroleum products."}],"correct":"","image":"/images/econ-as-mcq/62_627_269_541_417_0.jpg"},{"id":23,"text":"What, if decreased, will help to reduce the rate of inflation?","options":[{"label":"A","text":"budget deficit"},{"label":"B","text":"direct taxes"},{"label":"C","text":"exchange rate"},{"label":"D","text":"interest rate"}],"correct":""},{"id":24,"text":"What is an example of contractionary fiscal policy?","options":[{"label":"A","text":"an increase in the budget deficit"},{"label":"B","text":"an increase in the budget surplus"},{"label":"C","text":"an increase in the interest rate"},{"label":"D","text":"an increase in the money supply"}],"correct":""},{"id":25,"text":"A country with low unemployment and a managed floating exchange rate has a persistent current account deficit on its balance of payments. Which policy to reduce this deficit is most likely to keep unemployment low, but cause inflation?","options":[{"label":"A","text":"depreciating its currency"},{"label":"B","text":"higher direct taxation"},{"label":"C","text":"higher import tariffs"},{"label":"D","text":"higher interest rates"}],"correct":""},{"id":26,"text":"Which supply-side measure is most likely to produce short-run growth in a country's aggregate supply?","options":[{"label":"A","text":"easing of controls on immigration of workers"},{"label":"B","text":"expenditure on primary education"},{"label":"C","text":"expenditure on research and development"},{"label":"D","text":"privatisation of public utilities"}],"correct":""},{"id":27,"text":"A government aims to reduce unemployment through expansionary fiscal policy and borrows more from the commercial banks, increasing its borrowing requirement. What will be the result?","options":[{"label":"A","text":"a decrease in the budget deficit"},{"label":"B","text":"a decrease in the national debt"},{"label":"C","text":"an increase in the balance of payments deficit on the current account"},{"label":"D","text":"an increase in the interest rates"}],"correct":""},{"id":28,"text":"A government wants to use an expansionary monetary policy. What should the government increase?","options":[{"label":"A","text":"credit regulations"},{"label":"B","text":"the exchange rate"},{"label":"C","text":"the interest rate"},{"label":"D","text":"the money supply"}],"correct":""}];

const paper_07: MCQQuestion[] = [{"id":1,"text":"What will result from a government's decision to allow health care to be provided entirely by market forces?","options":[{"label":"A","text":"There will be a reduction in the provision of a public good."},{"label":"B","text":"All consumers will receive better health care."},{"label":"C","text":"Market failure will be eliminated in the health care market."},{"label":"D","text":"The health care market will reach an equilibrium."}],"correct":""},{"id":2,"text":"What would make online payment methods less acceptable as a medium of exchange?","options":[{"label":"A","text":"a fee charged for use of the online payment service"},{"label":"B","text":"both high and low priced goods can be paid for using the online service"},{"label":"C","text":"payments can be made at any time of day and night"},{"label":"D","text":"the online payment service can be accessed through a smartphone"}],"correct":""},{"id":3,"text":"Professional gardeners now use power tools instead of hand tools to maintain their customers' gardens. What can be concluded from this information?","options":[{"label":"A","text":"Capital has replaced all labour for maintaining gardens."},{"label":"B","text":"Gardening has become more labour-intensive."},{"label":"C","text":"Land has become more productive."},{"label":"D","text":"New technology has been introduced."}],"correct":""},{"id":4,"text":"A change in which factor will be least likely to alter a consumer's ability to pay for a product?","options":[{"label":"A","text":"a consumer's income"},{"label":"B","text":"a consumer's tastes"},{"label":"C","text":"a change in the price of the product"},{"label":"D","text":") a fall in the tax on goods and services"}],"correct":""},{"id":5,"text":"What is likely to decrease the price elasticity of supply (PES) of a product?","options":[{"label":"A","text":"an increase in advertising the product"},{"label":"B","text":"an increase in the firm's ability to substitute capital for labour"},{"label":"C","text":"an increase in the time during which the product can be stored"},{"label":"D","text":"an increase in the time required to produce the product"}],"correct":"","image":"/images/econ-as-mcq/65_440_234_922_517_0.jpg","table":"<table><tr><td>good X</td><td>good Y</td><td>good Z</td></tr><tr><td>A</td><td>equal to 1</td><td>equal to 1</td><td>equal to 1</td></tr><tr><td>B</td><td>equal to 1</td><td>greater than 1</td><td>greater than 1</td></tr><tr><td>C</td><td>less than 1</td><td>equal to 1</td><td>greater than 1</td></tr><tr><td>D</td><td>less than 1</td><td>greater than 1</td><td>greater than 1</td></tr></table>"},{"id":6,"text":"Money is paid by the government to an unemployed worker in the form of a benefit. Why is this called a transfer payment?","options":[{"label":"A","text":"The payment comes from taxes paid by employed workers."},{"label":"B","text":"The payment comes from government savings, not current income."},{"label":"C","text":"The payment is made without the production of goods and services taking place."},{"label":"D","text":"The payment must be spent as directed by the government."}],"correct":""},{"id":7,"text":"What would be a valid objection to the government provision of goods and services?","options":[{"label":"A","text":"There will be an increase in consumer sovereignty."},{"label":"B","text":"Only the private sector can provide merit goods."},{"label":"C","text":"Tax rates and tax income are likely to fall."},{"label":"D","text":"Investment in the private sector might be reduced."}],"correct":""},{"id":8,"text":"What will be the result of a subsidy that is given to the producers of a good with an inelastic demand curve?","options":[{"label":"A","text":"The equilibrium price of the good will fall by a larger percentage than the fall in equilibrium quantity."},{"label":"B","text":"The equilibrium price of the good will fall by a larger percentage than the rise in equilibrium quantity."},{"label":"C","text":"The equilibrium price of the good will fall by a smaller percentage than the fall in equilibrium quantity."},{"label":"D","text":"The equilibrium price of the good will fall by a smaller percentage than the rise in equilibrium quantity."}],"correct":""},{"id":9,"text":"The market for good X is in equilibrium. A government then introduces an effective minimum price on good X. What will decrease as a result of this minimum price?","options":[{"label":"A","text":"the excess supply of the product"},{"label":"B","text":"the market price of the product"},{"label":"C","text":"the quantity of the product supplied"},{"label":"D","text":"the size of the consumer surplus"}],"correct":""},{"id":10,"text":"Which change will not affect the balance of payments current account?","options":[{"label":"A","text":"a rise in export and import prices"},{"label":"B","text":"a rise in foreign aid flows"},{"label":"C","text":"a rise in international exchange rates"},{"label":"D","text":"a rise in foreign direct investment"}],"correct":""},{"id":11,"text":"Which statement correctly describes how an import quota works?","options":[{"label":"A","text":"It is a ban on the import of demerit goods."},{"label":"B","text":"It imposes strict product regulations on imports."},{"label":"C","text":"It is a unit tax that raises the price of imported goods."},{"label":"D","text":"It limits the quantity of certain imported goods."}],"correct":""},{"id":12,"text":"The diagram shows a freely floating foreign exchange market in the United Kingdom (UK) for the demand and supply of pounds sterling (£) in exchange for United States (US) dollars (\\$). What could cause the downward shift shown?","options":[{"label":"A","text":"UK interest rate falls below US interest rate."},{"label":"B","text":"The demand for UK exports is price-elastic and prices increase."},{"label":"C","text":"The demand for US exports is price-elastic and prices decrease."},{"label":"D","text":"People believe that sterling will appreciate."}],"correct":"","image":"/images/econ-as-mcq/69_515_1280_764_525_0.jpg"},{"id":13,"text":"What is a likely consequence of inflation?","options":[{"label":"A","text":"Fixed-income earners gain more than those whose income is gained from the ownership of property."},{"label":"B","text":"Real wages rise more than money wages."},{"label":"C","text":"The assets of creditors decrease in value at the expense of those of debtors."},{"label":"D","text":"The domestic purchasing power of money increases."}],"correct":""},{"id":14,"text":"A country has a floating exchange rate. An increase in which variable in the country will cause its currency to appreciate?","options":[{"label":"A","text":"the budget deficit"},{"label":"B","text":"the general price level"},{"label":"C","text":"the interest rate"},{"label":"D","text":"the trade deficit"}],"correct":""},{"id":15,"text":"What is an accurate statement about possible causes and/or consequences of a worsening in a country's terms of trade?","options":[{"label":"A","text":"It will result from a fall in the demand for its exports."},{"label":"B","text":"It will result from an increase in consumers' incomes in its major trading partners."},{"label":"C","text":"It will result in a decrease in interest rates by its major trading partners."},{"label":"D","text":"It will result in an improvement in its balance of trade."}],"correct":""},{"id":16,"text":"An economy has a balance of payments surplus, which it wishes to eliminate. In order to achieve this objective, which combination of policies would be most appropriate?","options":[{"label":"A","text":"a depreciation of the currency and an increase in government spending"},{"label":"B","text":"an appreciation of the currency and a cut in interest rates"},{"label":"C","text":"an increase in the money supply and a pay freeze"},{"label":"D","text":"increases in both direct and indirect taxation"}],"correct":""},{"id":17,"text":"What would be increased by an expansionary fiscal policy?","options":[{"label":"A","text":"budget deficit"},{"label":"B","text":"exchange rate"},{"label":"C","text":"money supply"},{"label":"D","text":"rate of direct taxation"}],"correct":""},{"id":18,"text":"Using all their resources efficiently, country X can produce 6 million tonnes of wheat or 2 million tonnes of steel whilst country Y can produce 4 million tonnes of wheat or 1 million tonnes of steel. Based on this information, what does the theory of comparative advantage suggest?","options":[{"label":"A","text":"Country X should produce only steel."},{"label":"B","text":"Country X will not gain from international trade."},{"label":"C","text":"Country Y has no comparative advantage."},{"label":"D","text":"Country Y will not gain from international trade."}],"correct":""},{"id":19,"text":"Countries X and Y are trade partners. An increase in which economic indicator in country Y is most likely to cause a fall in the exchange rate of country X?","options":[{"label":"A","text":"economic growth"},{"label":"B","text":"inflation rate"},{"label":"C","text":"money supply"},{"label":"D","text":"trade barriers"}],"correct":""},{"id":20,"text":"Which transaction is not recorded in the current account?","options":[{"label":"A","text":"aid received from the government of another country"},{"label":"B","text":"exports of raw materials"},{"label":"C","text":"investments by a foreign company"},{"label":"D","text":"payments of dividends to an overseas investor"}],"correct":""},{"id":21,"text":"A government decides to place a tariff on imports of raw materials. Which statement about the impact of the tariff is correct?","options":[{"label":"A","text":"It will increase costs of production for domestic firms."},{"label":"B","text":"It will increase consumer surplus for domestic consumers."},{"label":"C","text":"It will reduce government revenue."},{"label":"D","text":"There will be a fall in the price of imports and a rise in the demand."}],"correct":""},{"id":22,"text":"In which situation will a country's terms of trade improve?","options":[{"label":"A","text":"Its imports rise in value less than its exports."},{"label":"B","text":"Its imports rise in volume less than its exports."},{"label":"C","text":"The price of its imports rises by less than the prices of its exports."},{"label":"D","text":"The value of its external payments rises by less than the value of its external receipts."}],"correct":""}];

const paper_08: MCQQuestion[] = [{"id":1,"text":"An economy is changing from a planned economy to a market economy. Which action would be expected during this change?","options":[{"label":"A","text":"the replacement of fiscal policy by monetary policy"},{"label":"B","text":"the replacement of multinational companies by national companies"},{"label":"C","text":"the replacement of nationalisation by privatisation"},{"label":"D","text":"the replacement of private property rights by common ownership"}],"correct":""},{"id":2,"text":"A local council provides a tap for drinking water in a town. Would this make drinking water a free good?","options":[{"label":"A","text":"No, because it is possible to exclude some people from using the tap."},{"label":"B","text":"No, because it requires the use of scarce resources."},{"label":"C","text":"Yes, because it is available to all passers-by."},{"label":"D","text":"Yes, because it is impossible to charge for it."}],"correct":""},{"id":3,"text":"Food prices in a country increased by 20\\% in three months due to an infectious virus. Which statement about the cause of this rise in food prices is normative?","options":[{"label":"A","text":"Consumers were scared of running out of food."},{"label":"B","text":"Farm workers demanded higher wages to cover extra hours worked."},{"label":"C","text":"Supply of foreign food was reduced because of closed borders."},{"label":"D","text":"Transport costs increased by 10\\%."}],"correct":""},{"id":4,"text":"A doctor has very long working hours and a high level of stress. She can become a teacher instead of continuing as a doctor. What is the opportunity cost of choosing to continue as a doctor?","options":[{"label":"A","text":"the risk of mistakes caused by tiredness"},{"label":"B","text":"the possible costs of illness caused by high stress levels"},{"label":"C","text":"the potential salary as a teacher"},{"label":"D","text":"the retraining costs of becoming a teacher"}],"correct":""},{"id":5,"text":"When will the demand curve for motorcycles shift to the left?","options":[{"label":"A","text":"when the price of cars falls"},{"label":"B","text":"when the price of motorcycles falls"},{"label":"C","text":"when the tax on motorcycles rises"},{"label":"D","text":"when the price of public transport rises"}],"correct":""},{"id":6,"text":"The diagram shows the demand curve for housing. What is not assumed to remain constant when drawing this curve?","options":[{"label":"A","text":"consumer incomes"},{"label":"B","text":"expectations about future house prices"},{"label":"C","text":"the price of houses"},{"label":"D","text":"the rate of interest charged on loans for house purchase"}],"correct":"","image":"/images/econ-as-mcq/74_643_584_511_392_0.jpg"},{"id":7,"text":"Which statement defines the price elasticity of supply?","options":[{"label":"A","text":"It is a measure of how the price of a good responds to a change in the quantity supplied."},{"label":"B","text":"It is a measure of how the quantity supplied of a good responds to a change in its price."},{"label":"C","text":"It is a measure of how the supply of a good responds to a change in its cost of production."},{"label":"D","text":"It is a measure of how the supply of good X responds to a change in the price of good Y."}],"correct":""},{"id":8,"text":"Which products are likely to have a positive cross-elasticity of demand with tea?","options":[{"label":"A","text":"biscuits and cakes"},{"label":"B","text":"coffee and hot chocolate"},{"label":"C","text":"cups and saucers"},{"label":"D","text":"sugar and milk"}],"correct":""},{"id":9,"text":"What does not cause a shift in the supply curve of cars?","options":[{"label":"A","text":"a change in the car producers' costs of production"},{"label":"B","text":"a change in the price of fuel used by car owners"},{"label":"C","text":"a change in the rate of sales tax on cars"},{"label":"D","text":"a change in the wage rate of workers in the car industry"}],"correct":""},{"id":10,"text":"When is the supply curve for a car manufacturing firm most likely to be price elastic?","options":[{"label":"A","text":"when the firm finds it difficult to recruit new labour"},{"label":"B","text":"when the firm has a large quantity of stock"},{"label":"C","text":"when the firm is operating in the short run"},{"label":"D","text":"when the firm is operating near to full capacity"}],"correct":""},{"id":11,"text":"The diagram shows the market for electric steel-plated switches used in new houses. What could not have caused the market equilibrium position to have changed from X to Y?","options":[{"label":"A","text":"increasing the availability of loans for buying houses"},{"label":"B","text":"granting a subsidy for producers of bricks"},{"label":"C","text":"removing sales tax on electric switches"},{"label":"D","text":"removing tariffs on imports of wood"}],"correct":"","image":"/images/econ-as-mcq/77_647_234_502_435_0.jpg"},{"id":12,"text":"In mixed economies, what explains why the provision of certain goods and services will remain under government control?","options":[{"label":"A","text":"The market system fails to provide public goods."},{"label":"B","text":"Management ideas are hampered by excessive bureaucracy."},{"label":"C","text":"Ownership of companies depends on the ease of buying shares."},{"label":"D","text":"The profit motive tends to improve efficiency in organisations."}],"correct":""},{"id":13,"text":"The diagram shows the percentages of those on low pay and those on extremely low pay in a country from 1976 to 2012. A national minimum wage was introduced in 1999. Which conclusion is consistent with the diagram?","options":[{"label":"A","text":"The minimum wage helped the low paid more than the extremely low paid."},{"label":"B","text":"The minimum wage reduced the numbers of both low paid and extremely low paid."},{"label":"C","text":"The minimum wage reversed the trend in low pay of the previous 20 years."},{"label":"D","text":"The minimum wage was responsible for the largest reduction of low pay in the period."}],"correct":"","image":"/images/econ-as-mcq/78_424_272_952_550_0.jpg"},{"id":14,"text":"A government announces its intention to reduce the level of transfer payments in the economy. Which statement made by the government is consistent with this intention?","options":[{"label":"A","text":"There need to be more incentives for unemployed workers to seek jobs."},{"label":"B","text":"State pensions need to be increased."},{"label":"C","text":"The level of income tax needs to be raised."},{"label":"D","text":"The level of government expenditure needs to be increased."}],"correct":""},{"id":15,"text":"Assume the Chinese monetary authorities are committed to maintaining the exchange rate of China’s currency, the Yuan, against the US\\$ between \\({\\mathrm{P}}_{1}\\) and \\({\\mathrm{P}}_{2}\\) on the diagram. What might they do if supply changed from \\({\\mathrm{S}}_{1}\\) to \\({\\mathrm{S}}_{2}\\) ?","options":[{"label":"A","text":"introduce controls on Chinese investment overseas"},{"label":"B","text":"lower interest rates"},{"label":"C","text":"remove tariffs on imports from USA"},{"label":"D","text":"sell Yuan on the foreign exchange markets"}],"correct":"","image":"/images/econ-as-mcq/80_444_267_909_475_0.jpg"},{"id":16,"text":"The table shows information from the current account of the balance of payments for Canada and Singapore in 2019. } What can be concluded from the table?","options":[{"label":"A","text":"Canada exported more goods than Singapore."},{"label":"B","text":"Canada and Singapore had current account deficits."},{"label":"C","text":"Singapore had a surplus on its trade in goods and services."},{"label":"D","text":"Singapore imported cheaper goods than Canada."}],"correct":"","table":"<table><tr><td>Canada (US$ million)</td><td>Singapore (US$ million)</td></tr><tr><td>exports of goods</td><td>448360</td><td>440800</td></tr><tr><td>imports of goods</td><td>462105</td><td>342805</td></tr><tr><td>exports of services</td><td>100350</td><td>204810</td></tr><tr><td>imports of services</td><td>115270</td><td>119050</td></tr><tr><td>primary income balance</td><td>-3475</td><td>-34340</td></tr><tr><td>secondary income balance</td><td>-2060</td><td>-6280</td></tr></table>"},{"id":17,"text":"What is a measure of a country's terms of trade index?","options":[{"label":"A","text":"price index of exports \\(\\times  {100}\\)"},{"label":"B","text":"\\(\\frac{\\text{ price index of imports }}{\\text{ price index of exports }} \\times  {100}\\)"},{"label":"C","text":"c total value of exports \\(\\times  {100}\\)"},{"label":"D","text":"total value of exports - total value of imports"}],"correct":""},{"id":18,"text":"What is likely to cause an increase in the exchange rate of an economy?","options":[{"label":"A","text":"an increase in demand-pull inflation"},{"label":"B","text":"an increase in national income"},{"label":"C","text":"a decision of the central bank to raise money supply"},{"label":"D","text":"a discovery of a natural resource that replaces imports"}],"correct":""},{"id":19,"text":"What is likely to explain an increase in the deficit on a country's current account of the balance of payments?","options":[{"label":"A","text":"an increase in government foreign aid to countries abroad"},{"label":"B","text":"an increase in government tax rates"},{"label":"C","text":"an increase in other countries' exchange rates"},{"label":"D","text":"an increase in the proportion of income saved by the country's residents"}],"correct":""},{"id":20,"text":"What does the Marshall-Lerner condition state must be present for a depreciation of a currency to cause an improvement in the current account balance?","options":[{"label":"A","text":"The price elasticity of demand for exports and the price elasticity of demand for imports are both greater than one."},{"label":"B","text":"The price elasticity of demand for exports and the price elasticity of demand for imports are both less than one."},{"label":"C","text":"The sum of the price elasticity of demand for exports and the price elasticity of demand for imports is greater than one."},{"label":"D","text":"The sum of the price elasticity of demand for exports and the price elasticity of demand for imports is less than one."}],"correct":""},{"id":21,"text":"Raising interest rates is proposed to reduce a balance of payments deficit. Which justification for this action is not valid?","options":[{"label":"A","text":"It will attract more foreign currency inflows."},{"label":"B","text":"It will encourage exporters to find new foreign markets."},{"label":"C","text":"It will lower the level of imported consumer goods."},{"label":"D","text":"It will put downward pressure on the exchange rate."}],"correct":""},{"id":22,"text":"The table shows information from the current account of the balance of payments for Canada and Singapore in 2019. What can be concluded from the table?","options":[{"label":"A","text":"Canada exported more goods than Singapore."},{"label":"B","text":"Canada and Singapore had current account deficits."},{"label":"C","text":"Singapore had a surplus on its trade in goods and services."},{"label":"D","text":"Singapore imported cheaper goods than Canada."}],"correct":"","table":"<table><tr><td></td><td>Canada (US$ million)</td><td>Singapore (US$ million)</td></tr><tr><td>exports of goods</td><td>448360</td><td>440800</td></tr><tr><td>imports of goods</td><td>462105</td><td>342805</td></tr><tr><td>exports of services</td><td>100350</td><td>204810</td></tr><tr><td>imports of services</td><td>115270</td><td>119050</td></tr><tr><td>primary income balance</td><td>-3475</td><td>-34340</td></tr><tr><td>secondary income balance</td><td>-2060</td><td>-6280</td></tr></table>"},{"id":23,"text":"What is not an example of protectionism?","options":[{"label":"A","text":"the European Union (EU) requiring goods imported into member states to meet safety standards"},{"label":"B","text":"the Pakistan government increasing the rate of goods and services tax (GST) on some exported goods from 2\\% to 5\\%"},{"label":"C","text":"the Nigeria government banning the import of packaged sugar"},{"label":"D","text":"the US imposing a 35\\% tariff on tyres imported from China"}],"correct":""},{"id":24,"text":"Using all their resources efficiently, country X can produce 6 million tonnes of wheat or 2 million tonnes of steel whilst country Y can produce 4 million tonnes of wheat or 1 million tonnes of steel. Based on this information, what does the theory of comparative advantage suggest?","options":[{"label":"A","text":"Country X should produce only steel."},{"label":"B","text":"Country X will not gain from international trade."},{"label":"C","text":"Country Y has no comparative advantage."},{"label":"D","text":"Country Y will not gain from international trade."}],"correct":""},{"id":25,"text":"Countries X and Y are trade partners. An increase in which economic indicator in country Y is most likely to cause a fall in the exchange rate of country X?","options":[{"label":"A","text":"economic growth"},{"label":"B","text":"inflation rate"},{"label":"C","text":"money supply"},{"label":"D","text":"trade barriers"}],"correct":""},{"id":26,"text":"Which transaction is not recorded in the current account?","options":[{"label":"A","text":"aid received from the government of another country"},{"label":"B","text":"exports of raw materials"},{"label":"C","text":"investments by a foreign company"},{"label":"D","text":"payments of dividends to an overseas investor"}],"correct":""},{"id":27,"text":"A government decides to place a tariff on imports of raw materials. Which statement about the impact of the tariff is correct?","options":[{"label":"A","text":"It will increase costs of production for domestic firms."},{"label":"B","text":"It will increase consumer surplus for domestic consumers."},{"label":"C","text":"It will reduce government revenue."},{"label":"D","text":"There will be a fall in the price of imports and a rise in the demand."}],"correct":""},{"id":28,"text":"In which situation will a country's terms of trade improve?","options":[{"label":"A","text":"Its imports rise in value less than its exports."},{"label":"B","text":"Its imports rise in volume less than its exports."},{"label":"C","text":"The price of its imports rises by less than the prices of its exports."},{"label":"D","text":"The value of its external payments rises by less than the value of its external receipts."}],"correct":""}];

const paper_09: MCQQuestion[] = [{"id":1,"text":"Which action would not raise the quality of the particular factor of production?","options":[{"label":"A","text":"capital - operating a machine continuously at full capacity"},{"label":"B","text":"enterprise - providing risk management advice"},{"label":"C","text":"land - increasing the use of fertilisers"},{"label":"D","text":"labour - making apprenticeships and training compulsory"}],"correct":""},{"id":2,"text":"During a period of deflation an economy's aggregate monetary demand falls. Which function of money explains this fall?","options":[{"label":"A","text":"a measure of value"},{"label":"B","text":"a medium of exchange"},{"label":"C","text":"a standard for deferred payment"},{"label":"D","text":"a store of value"}],"correct":""},{"id":3,"text":"A government wishes to ensure adequate flood defences are provided in its coastal areas. Which action is most likely to be undertaken only by the government?","options":[{"label":"A","text":"building the defences"},{"label":"B","text":"designing the defences"},{"label":"C","text":"financing the defences"},{"label":"D","text":"maintaining the defences"}],"correct":""},{"id":4,"text":"Consumer surplus exists in the market for rice. What does this mean?","options":[{"label":"A","text":"Consumers benefit from rice production more than producers."},{"label":"B","text":"Consumer demand for rice exceeds supply."},{"label":"C","text":"Some consumers would be willing to pay more than the market price for rice."},{"label":"D","text":"The production of rice exceeds the supply."}],"correct":""},{"id":5,"text":"The diagram shows the demand curve and supply curve for a product. Which area represents producer surplus?","options":[{"label":"A","text":"OWYZ minus OWY"},{"label":"B","text":"OWYZ minus OYZ"},{"label":"C","text":"OXYZ minus OYZ"},{"label":"D","text":"OXYZ minus WXY"}],"correct":"","image":"/images/econ-as-mcq/86_573_234_649_450_0.jpg"},{"id":6,"text":"What causes an inelastic market supply curve for an agricultural crop such as wheat?","options":[{"label":"A","text":"a government decision to import crops at times of shortage"},{"label":"B","text":"an efficient use of fertilisers causing crop production to rise"},{"label":"C","text":"the storage of excess production for future sale"},{"label":"D","text":"the very long time required to produce additional output"}],"correct":""},{"id":7,"text":"The diagrams show the effect of a change in the market for good X on the market for good Y. good X good Y What can be concluded about the goods?","options":[{"label":"A","text":"X and Y are complements."},{"label":"B","text":"X and Y are in joint supply."},{"label":"C","text":"X and Y are substitutes."},{"label":"D","text":"Y is a derived demand from X."}],"correct":"","image":"/images/econ-as-mcq/87_950_585_468_371_0.jpg"},{"id":8,"text":"The market for a product is initially in equilibrium. Which combination of changes will cause the price of the product to rise and the quantity sold to fall?","options":[{"label":"A","text":"a decrease in demand that is larger than a decrease in supply"},{"label":"B","text":"a decrease in demand that is smaller than a decrease in supply"},{"label":"C","text":"an increase in demand that is larger than an increase in supply"},{"label":"D","text":"an increase in demand that is smaller than an increase in supply"}],"correct":""},{"id":9,"text":"The diagram shows two demand curves and two supply curves. The initial equilibrium is at H. Which combinations of shifts in the demand and supply curves would result in a change in the equilibrium position from \\(\\mathrm{H}\\) to \\(\\mathrm{K}\\) ?","options":[{"label":"A","text":"an increase in demand and an increase in supply"},{"label":"B","text":"an increase in demand and a decrease in supply"},{"label":"C","text":"a decrease in demand and an increase in supply"},{"label":"D","text":"a decrease in demand and a decrease in supply"}],"correct":"","image":"/images/econ-as-mcq/89_592_690_611_450_0.jpg"},{"id":10,"text":"In 2009, the Australian Government made a payment of \\$900 to those who earned less than \\$100000 per year. How would this payment best be described?","options":[{"label":"A","text":"neutral"},{"label":"B","text":"progressive"},{"label":"C","text":"proportional"},{"label":"D","text":"regressive"}],"correct":""},{"id":11,"text":"If an industry is currently state-owned and state-run, what does not represent a reason for it being privatised?","options":[{"label":"A","text":"Decisions will no longer be taken with political considerations in mind."},{"label":"B","text":"The benefits of merit goods will be taken into account in decision-making."},{"label":"C","text":"Its owners would have more incentive to make it operate profitably."},{"label":"D","text":"There will be greater incentives for managers to introduce modern technology."}],"correct":""},{"id":12,"text":"What does the incidence of an indirect tax on a product refer to?","options":[{"label":"A","text":"the proportion of the tax paid by the consumer relative to the producer"},{"label":"B","text":"the reduction in output as a result of the imposition of the tax"},{"label":"C","text":"the revenue the tax generates for the government"},{"label":"D","text":"the increase in the hidden economy as a result of tax evasion after the tax is imposed"}],"correct":""},{"id":13,"text":"A government wishes to influence the price of a good. It introduces a maximum price, \\({P}_{\\max }\\) , and a minimum price, \\({P}_{\\min }\\) . The diagram shows these prices relative to the current market price P. What can be concluded from the diagram?","options":[{"label":"A","text":"Both the maximum and the minimum price will be effective."},{"label":"B","text":"Only the maximum price will be effective."},{"label":"C","text":"Only the minimum price will be effective."},{"label":"D","text":"The market price will continue to operate."}],"correct":"","image":"/images/econ-as-mcq/91_663_338_470_413_0.jpg"},{"id":14,"text":"A government removes the tariff on a product, as shown. What will be the change in domestic production?","options":[{"label":"A","text":"a reduction of WV"},{"label":"B","text":"a reduction of XV"},{"label":"C","text":"a reduction of XW"},{"label":"D","text":"a reduction of ZY"}],"correct":"","image":"/images/econ-as-mcq/91_376_1191_1043_482_0.jpg"},{"id":15,"text":"What is a certain outcome on an aggregate demand and aggregate supply diagram of an increase in factor productivity?","options":[{"label":"A","text":"downward shift of the aggregate demand curve"},{"label":"B","text":"downward shift of the aggregate supply curve"},{"label":"C","text":"an upward shift of the aggregate demand curve"},{"label":"D","text":"an upward shift of the aggregate supply curve"}],"correct":""},{"id":16,"text":"Trade in services is a component of the current account of the balance of payments. What is an example of a trade in services?","options":[{"label":"A","text":"development aid for foreign countries"},{"label":"B","text":"export revenue from primary commodities"},{"label":"C","text":"income from foreign tourists"},{"label":"D","text":"income from overseas investments"}],"correct":""},{"id":17,"text":"Which statement about changing price levels is correct?","options":[{"label":"A","text":"Anyone on a fixed income has rising real income during deflation."},{"label":"B","text":"Government revenue from indirect taxes falls during inflation."},{"label":"C","text":"Producers prefer deflation to inflation."},{"label":"D","text":"Savers prefer index-linked savings when there is deflation rather than inflation."}],"correct":""},{"id":18,"text":"What would be likely to decrease inflation in an economy?","options":[{"label":"A","text":"a decrease in consumer saving"},{"label":"B","text":"a decrease in unemployment"},{"label":"C","text":"an increase in labour productivity"},{"label":"D","text":"an increase in taxes on imports"}],"correct":""},{"id":19,"text":"Which change in economic circumstances is most likely to lead to a reduction in the rate of domestic inflation in an economy?","options":[{"label":"A","text":"a depreciation in the currency"},{"label":"B","text":"a reduction in the productivity of labour"},{"label":"C","text":"a worldwide recession"},{"label":"D","text":"an increase in direct taxes to finance increased welfare payments"}],"correct":""},{"id":20,"text":"A country currently producing at point \\(X\\) on its production possibility curve decides to specialise in the manufacture of cars and import trucks. It finds it can import one truck in exchange for four cars. What is the result in the domestic market if it exports all the extra cars?","options":[{"label":"A","text":"250 extra trucks"},{"label":"B","text":"1000 extra trucks"},{"label":"C","text":"1250 extra trucks"},{"label":"D","text":"2000 extra trucks"}],"correct":"","image":"/images/econ-mcq/79_502_686_790_326_0.jpg"},{"id":21,"text":"A country has a floating exchange rate. Its current account on the balance of payments moves from a surplus to a deficit. Which rate is likely to increase in the short run as a consequence of this worsening of its current account?","options":[{"label":"A","text":"economic growth rate"},{"label":"B","text":"exchange rate"},{"label":"C","text":"interest rate"},{"label":"D","text":"unemployment rate"}],"correct":""},{"id":22,"text":"Which policy is most likely to reduce a balance of payments deficit without causing inflation?","options":[{"label":"A","text":"decreased import quotas"},{"label":"B","text":"depreciation of currency"},{"label":"C","text":"higher interest rates"},{"label":"D","text":"decreased import tariffs"}],"correct":""},{"id":23,"text":"What is not an example of protectionism?","options":[{"label":"A","text":"the European Union (EU) requiring goods imported into member states to meet safety standards"},{"label":"B","text":"the Pakistan government increasing the rate of goods and services tax (GST) on some exported goods from 2\\% to 5\\%"},{"label":"C","text":"the Nigeria government banning the import of packaged sugar"},{"label":"D","text":"the US imposing a 35\\% tariff on tyres imported from China"}],"correct":""}];

const paper_10: MCQQuestion[] = [{"id":1,"text":"What is 'a produced means of further production'?","options":[{"label":"A","text":"capital"},{"label":"B","text":"enterprise"},{"label":"C","text":"labour"},{"label":"D","text":"land"}],"correct":""},{"id":2,"text":"A hospital management board decides to reallocate \\$800000 from its \\$1.2m new buildings budget to spend on cancer care. What is the opportunity cost of this decision?","options":[{"label":"A","text":"a cost of \\$400000"},{"label":"B","text":"a cost of \\$800000"},{"label":"C","text":"the cost of healthcare for cancer patients"},{"label":"D","text":") the loss of some new buildings"}],"correct":""},{"id":3,"text":"The diagram shows the change in a country's production possibility curve from XX to YY. What would explain this change?","options":[{"label":"A","text":"Consumers chose to consume more food and less drink."},{"label":"B","text":"Government taxed food production and subsidised drink production."},{"label":"C","text":"Productivity rose in food production and fell in drink production."},{"label":"D","text":"There were more imports of food and more exports of drink."}],"correct":"","image":"/images/econ-as-mcq/95_661_1039_474_404_0.jpg"},{"id":4,"text":"A factory manufactures chairs. The manufacturing process is divided into a number of tasks. What is a likely disadvantage of this division of labour?","options":[{"label":"A","text":"decrease in motivation"},{"label":"B","text":"decrease in output"},{"label":"C","text":"decrease in productivity"},{"label":"D","text":"decrease in quality of the final product"}],"correct":""},{"id":5,"text":"What does consumer surplus measure?","options":[{"label":"A","text":"the excess profit earned by the producer of a good"},{"label":"B","text":"the opportunity cost to the consumer of not buying a good"},{"label":"C","text":"the price the marginal consumer is willing to pay for a good"},{"label":"D","text":"the consumer's gain from purchasing a good at a price below what they are willing to pay"}],"correct":""},{"id":6,"text":"In which situation is the demand for a product said to be price elastic?","options":[{"label":"A","text":"The quantity demanded responds to a change in price."},{"label":"B","text":"An increase in price brings about a decrease in the quantity demanded."},{"label":"C","text":"An increase in price induces consumers to spend more on the product."},{"label":"D","text":"A decrease in price brings about an increase in revenue."}],"correct":""},{"id":7,"text":"Demand for medical face masks exceeds supply during a disease outbreak. What is the most likely cause of this excess demand?","options":[{"label":"A","text":"Some consumers do not have effective demand."},{"label":"B","text":"The demand for medical face masks is price inelastic in the short run."},{"label":"C","text":"The price of medical face masks is fixed below the equilibrium price."},{"label":"D","text":"The supply of medical face masks is inelastic in the short run."}],"correct":""},{"id":8,"text":"Which statement correctly describes absolute advantage?","options":[{"label":"A","text":"It is when a country has a higher opportunity cost in producing a good than another country."},{"label":"B","text":"It is when a country has a lower wage cost in producing a good than another country."},{"label":"C","text":"It is when the relative prices of exports of a country are greater than the relative prices of its imports."},{"label":"D","text":"It is when a country's output of a good is greater per unit of resource than another country."}],"correct":""},{"id":9,"text":"Which group is most likely to suffer during high inflation?","options":[{"label":"A","text":"borrowers"},{"label":"B","text":"importers"},{"label":"C","text":"producers"},{"label":"D","text":"fixed wage earners"}],"correct":""},{"id":10,"text":"The diagram shows the aggregate demand (AD) and aggregate supply (AS) for an economy. Which changes in subsidies and indirect taxes would have caused the change from \\({\\mathrm{{AS}}}_{1}\\) to \\({\\mathrm{{AS}}}_{2}\\) ?","options":[{"label":"A","text":"higher subsidies and higher indirect taxes"},{"label":"B","text":"higher subsidies and lower indirect taxes"},{"label":"C","text":"lower subsidies and higher indirect taxes"},{"label":"D","text":"lower subsidies and lower indirect taxes"}],"correct":"","image":"/images/econ-as-mcq/101_655_934_482_370_0.jpg"},{"id":11,"text":"The graph gives the percentage unemployed for all people aged 16 and over, and for young people aged 16-24. What is the consequence for consumer expenditure on products consumed by the 16-24 age group over the period 2010-2020?","options":[{"label":"A","text":"a fall in consumer expenditure across the whole period"},{"label":"B","text":"an initial fall in consumer expenditure followed by a rise"},{"label":"C","text":"an initial rise in consumer expenditure followed by a fall"},{"label":"D","text":"a rise in consumer expenditure across the whole period"}],"correct":"","image":"/images/econ-as-mcq/102_379_269_1031_535_0.jpg"},{"id":12,"text":"The table shows data on the Japanese balance of trade in goods. } What can be concluded from this data?","options":[{"label":"A","text":"The demand for Japanese exports was price inelastic."},{"label":"B","text":"The Japanese current account was in surplus."},{"label":"C","text":"The majority of Japanese imports were essential goods."},{"label":"D","text":"The Marshall-Lerner condition for Japan is greater than 1."}],"correct":"","table":"<table><tr><td>exchange rate yen/dollar</td><td>exports $bn</td><td>imports $bn</td></tr><tr><td>2016</td><td>109</td><td>635</td><td>585</td></tr><tr><td>2017</td><td>111</td><td>689</td><td>645</td></tr></table>"},{"id":13,"text":"A country's currency has depreciated against all the currencies of its main trading partners. How will the depreciation affect its terms of trade?","options":[{"label":"A","text":"The terms of trade will improve."},{"label":"B","text":"The terms of trade will not change."},{"label":"C","text":"The terms of trade will worsen."},{"label":"D","text":"The terms of trade will worsen only if the depreciation causes inflation."}],"correct":""},{"id":14,"text":"A country with a floating exchange rate experiences a large surplus on the current account of its balance of payments. What is likely to decrease as a consequence?","options":[{"label":"A","text":"the exports of capital from the country"},{"label":"B","text":"the level of employment in the country"},{"label":"C","text":"the prices of imports into the country"},{"label":"D","text":"the value of the country's currency"}],"correct":""},{"id":15,"text":"Which measure is aimed directly at promoting international trade?","options":[{"label":"A","text":"decreasing existing quotas"},{"label":"B","text":"increasing interest rates"},{"label":"C","text":"subsidies paid to export industries"},{"label":"D","text":"wage subsidy schemes during recessions"}],"correct":""},{"id":16,"text":"What would be classified as a supply-side policy measure?","options":[{"label":"A","text":"a law to reduce the power of trade unions"},{"label":"B","text":"a reduction in the government's fiscal deficit"},{"label":"C","text":"an open market sale of securities"},{"label":"D","text":"the imposition of a tariff on imported goods"}],"correct":""},{"id":17,"text":"What is the equivalent of a country's national debt?","options":[{"label":"A","text":"the accumulated borrowing of the government"},{"label":"B","text":"the difference between government spending and taxation"},{"label":"C","text":"the interest paid by the government on all the money it owes"},{"label":"D","text":"the total money owed by all households in the country"}],"correct":""},{"id":18,"text":"The country's Marshall-Lerner condition is greater than 1.","options":[{"label":"C","text":"The government has a budget deficit."},{"label":"D","text":"The overall balance of payments is in surplus."},{"label":"A","text":"publisher will be pleased to make amends at the earliest possible opportunity."},{"label":"B","text":"To avoid the issue of disclosure of answer-related information to candidates, all copyright acknowledgements are reproduced online in the Cambridge Assessment International Education Copyright Acknowledgements Booklet. This is produced for each series of examinations and is freely available to download at www.cambridgeinternational.org after the live examination series."}],"correct":""},{"id":19,"text":"The diagram shows the aggregate demand (AD) and aggregate supply (AS) for an economy. Which changes in subsidies and indirect taxes would have caused the change from \\( {\\mathrm{{AS}}}_{1} \\) to \\( {\\mathrm{{AS}}}_{2} \\) ?","options":[{"label":"A","text":"higher subsidies and higher indirect taxes"},{"label":"B","text":"higher subsidies and lower indirect taxes"},{"label":"C","text":"lower subsidies and higher indirect taxes"},{"label":"D","text":"lower subsidies and lower indirect taxes"}],"correct":"","image":"/images/econ-as-mcq/101_655_934_482_370_0.jpg"},{"id":20,"text":"The table shows data on the Japanese balance of trade in goods. What can be concluded from this data?","options":[{"label":"A","text":"The demand for Japanese exports was price inelastic."},{"label":"B","text":"The Japanese current account was in surplus."},{"label":"C","text":"The majority of Japanese imports were essential goods."},{"label":"D","text":"The Marshall-Lerner condition for Japan is greater than 1."}],"correct":"","table":"<table><tr><td>year</td><td>exchange rate yen/dollar</td><td>exports $bn</td><td>imports $bn</td></tr><tr><td>2016</td><td>109</td><td>635</td><td>585</td></tr><tr><td>2017</td><td>111</td><td>689</td><td>645</td></tr></table>"},{"id":21,"text":"In a closed economy with no government sector, the multiplier shows the impact of a change in","options":[{"label":"A","text":"consumption on investment."},{"label":"B","text":"investment on national income."},{"label":"C","text":"national income on consumption."},{"label":"D","text":"national income on investment."}],"correct":""},{"id":22,"text":"The table shows key macroeconomic indicators for four countries in 2018. } What can be concluded from the table?","options":[{"label":"A","text":"Countries with current account surpluses had low unemployment rates."},{"label":"B","text":"Countries with high economic growth rates had high inflation rates."},{"label":"C","text":"Countries with low economic growth rates had high unemployment rates."},{"label":"D","text":"Countries with positive economic growth rates had current account deficits."}],"correct":""},{"id":23,"text":"What is not a valid explanation of why a government might allow a deficit on the balance of payments current account to continue?","options":[{"label":"A","text":"The balance of payments account must always balance."},{"label":"B","text":"Foreign direct investment might help to finance the deficit."},{"label":"C","text":"The country may have a larger surplus on the other parts of its balance of payments account."},{"label":"D","text":"The standard of living is increased if the level of cheap food imports is significant."}],"correct":""},{"id":24,"text":"A country currently producing at point \\(X\\) on its production possibility curve decides to specialise in the manufacture of cars and import trucks. It finds it can import one truck in exchange for four cars. What is the result in the domestic market if it exports all the extra cars?","options":[{"label":"A","text":"250 extra trucks"},{"label":"B","text":"1000 extra trucks"},{"label":"C","text":"1250 extra trucks"},{"label":"D","text":"2000 extra trucks"}],"correct":"","image":"/images/econ-mcq/79_502_686_790_326_0.jpg"}];

const paper_11: MCQQuestion[] = [{"id":1,"text":"People plant flowers in a local park. Which statement is correct?","options":[{"label":"A","text":"Flowers in parks are a public good because people can enjoy them at no charge."},{"label":"B","text":"Flowers in parks are a public good because they are owned by local people and are not for profit."},{"label":"C","text":"Flowers in parks are not a public good if local people can limit the number of visitors to the parks."},{"label":"D","text":"Flowers in parks are not a public good if they are individual, not identical, in nature."}],"correct":""},{"id":2,"text":"A government decides that all non-essential businesses must close for three months due to a disease pandemic. What is an opportunity cost of this policy?","options":[{"label":"A","text":"increased leisure time for employees"},{"label":"B","text":"lives that are saved due to reduced disease levels"},{"label":"C","text":"the production of goods by essential businesses"},{"label":"D","text":") the loss of goods from the closed businesses"}],"correct":""},{"id":3,"text":"The diagram shows an economy's production possibility curve. The economy produces combinations of goods and services using all available resources. What does the production possibility curve indicate for goods and services?","options":[{"label":"A","text":"constant returns to scale in the production of both goods and services"},{"label":"B","text":"diminishing returns to scale in the production of both goods and services"},{"label":"C","text":"increasing returns to scale in the production of both goods and services"},{"label":"D","text":"infinite returns to scale in the production of both goods and services"}],"correct":"","image":"/images/econ-as-mcq/106_617_1213_561_474_0.jpg"},{"id":4,"text":"When is the price elasticity of demand for a product most likely to be price elastic?","options":[{"label":"A","text":"A large percentage of income is spent on the product."},{"label":"B","text":"It is measured in the short run."},{"label":"C","text":"It is a necessity product."},{"label":"D","text":"There are few substitutes available."}],"correct":""},{"id":5,"text":"What is most likely to cause a shift in the supply curve for rice?","options":[{"label":"A","text":"a change in the price of the rice"},{"label":"B","text":"a change in the price of meat"},{"label":"C","text":"a change in the size of the rice industry"},{"label":"D","text":"a change in tastes and preferences for rice"}],"correct":""},{"id":6,"text":"What does joint supply mean?","options":[{"label":"A","text":"A firm can choose between producing a range of different goods."},{"label":"B","text":"A good has multiple uses."},{"label":"C","text":"A good is a by-product of the production process of another good."},{"label":"D","text":"Consumers consider two goods as complements."}],"correct":""},{"id":7,"text":"When the price of a firm's product falls by 5\\%, its total revenue also falls by 5\\%. What describes the product's price elasticity of demand?","options":[{"label":"A","text":"elastic"},{"label":"B","text":"infinite"},{"label":"C","text":"unitary"},{"label":"D","text":"zero"}],"correct":""},{"id":8,"text":"The table shows how an individual's weekly consumption of biscuits and coffee varies with income. } Which statement about the income elasticity of demand over the range of income shown is correct?","options":[{"label":"A","text":"For biscuits it is greater than 1."},{"label":"B","text":"For biscuits it is zero."},{"label":"C","text":"For coffee it is less than 1."},{"label":"D","text":"For coffee it is unitary."}],"correct":"","table":"<table><tr><td>biscuits (packs)</td><td>coffee (cups)</td></tr><tr><td>100</td><td>0</td><td>5</td></tr><tr><td>150</td><td>5</td><td>10</td></tr></table>"},{"id":9,"text":"The diagram shows four supply curves. Which statement about the price elasticity of these supply curves is correct?","options":[{"label":"A","text":"W has elasticity of 0 that will rise as price rises."},{"label":"B","text":"X has elasticity greater than 1 that will be constant as price rises."},{"label":"C","text":"Y has elasticity greater than 1 that will fall as price rises."},{"label":"D","text":"Z has elasticity of 0 that is constant as quantity rises."}],"correct":"","image":"/images/econ-as-mcq/109_645_232_504_410_0.jpg"},{"id":10,"text":"Product X has a price elasticity of supply (PES) of +2, whilst product Y has a PES of +0.2. Which statement about products \\(X\\) and \\(Y\\) is correct?","options":[{"label":"A","text":"X has more substitutes than Y."},{"label":"B","text":"A 20\\% price fall would lead to a greater decrease in production of Y than of X."},{"label":"C","text":"After a price rise, it is more difficult to increase Y's output than X's."},{"label":"D","text":"After a price fall of 10\\%, more people would buy X than would buy Y."}],"correct":""},{"id":11,"text":"A Bangladeshi citizen is employed as a construction worker in Qatar. He sends some of his wages to his family in Bangladesh. How will this be recorded on Qatar's balance of payments?","options":[{"label":"A","text":"as part of the balance of trade in services"},{"label":"B","text":"as part of net primary income"},{"label":"C","text":"as part of net secondary income"},{"label":"D","text":"as part of the financial account"}],"correct":""},{"id":12,"text":"Which policy is most likely to help to correct an adverse balance on the current account of the balance of payments?","options":[{"label":"A","text":"abolishing tariffs"},{"label":"B","text":"depreciating the currency"},{"label":"C","text":"reducing direct taxes"},{"label":"D","text":"reducing indirect taxes"}],"correct":""},{"id":13,"text":"The table shows the relative price of exports compared with imports expressed as an index number for an economy \\(\\left( {{2013} = {100}}\\right)\\) . } Which statement about the period 2013-2015 is correct?","options":[{"label":"A","text":"Export prices have increased each year."},{"label":"B","text":"The general level of prices has fallen."},{"label":"C","text":"The terms of trade have deteriorated."},{"label":"D","text":"The volume of imports increasingly exceeds the volume of exports."}],"correct":"","table":"<table><tr><td>index</td></tr><tr><td>2013</td><td>100</td></tr><tr><td>2014</td><td>97</td></tr><tr><td>2015</td><td>95</td></tr></table>"},{"id":14,"text":"Which government action is least likely to prevent a fall in economic growth?","options":[{"label":"A","text":"additional controls on commercial banks' lending"},{"label":"B","text":"relaxation of rules for immigration of adult population"},{"label":"C","text":"removal of trade barriers on import of raw materials"},{"label":"D","text":"training and education of workforce"}],"correct":""},{"id":15,"text":"What is the most likely cause of an outward shift of a country's aggregate demand curve?","options":[{"label":"A","text":"a decrease in the competitiveness of domestically produced products"},{"label":"B","text":"a decrease in the general price level"},{"label":"C","text":"a decrease in the money supply"},{"label":"D","text":"a depreciation of the country's exchange rate"}],"correct":""},{"id":16,"text":"The diagram shows the macroeconomic equilibrium output and price level changing from Y and P to \\({Y}_{1}\\) and \\({P}_{1}\\) . real output What could have caused this change?","options":[{"label":"A","text":"a decrease in exports"},{"label":"B","text":"a decrease in labour productivity"},{"label":"C","text":"an increase in the government's spending"},{"label":"D","text":"an increase in the money supply"}],"correct":"","image":"/images/econ-as-mcq/113_521_621_750_446_0.jpg"},{"id":17,"text":"A country had a current account surplus of \\$141bn. Which policy may its government implement to reduce this surplus in the short run?","options":[{"label":"A","text":"a decrease in direct taxes"},{"label":"B","text":"a decrease in regulations to encourage more foreign firms to locate in this country"},{"label":"C","text":"an increase of import duties"},{"label":"D","text":"an increase in interest rates"}],"correct":""},{"id":18,"text":"The table shows the relative price of exports compared with imports expressed as an index number for an economy \\( \\left( {{2013} = {100}}\\right) \\) . Which statement about the period 2013-2015 is correct?","options":[{"label":"A","text":"Export prices have increased each year."},{"label":"B","text":"The general level of prices has fallen."},{"label":"C","text":"The terms of trade have deteriorated."},{"label":"D","text":"The volume of imports increasingly exceeds the volume of exports."}],"correct":"","table":"<table><tr><td>date</td><td>index</td></tr><tr><td>2013</td><td>100</td></tr><tr><td>2014</td><td>97</td></tr><tr><td>2015</td><td>95</td></tr></table>"},{"id":19,"text":"The diagram shows the macroeconomic equilibrium output and price level changing from Y and P to \\( {Y}_{1} \\) and \\( {P}_{1} \\) . real output What could have caused this change?","options":[{"label":"A","text":"a decrease in exports"},{"label":"B","text":"a decrease in labour productivity"},{"label":"C","text":"an increase in the government's spending"},{"label":"D","text":"an increase in the money supply"}],"correct":"","image":"/images/econ-as-mcq/113_521_621_750_446_0.jpg"},{"id":20,"text":"An economy is experiencing accelerating cost-push inflation. Which group is likely to be least concerned by this?","options":[{"label":"A","text":"borrowers"},{"label":"B","text":"consumers"},{"label":"C","text":"creditors"},{"label":"D","text":"exporters"}],"correct":""},{"id":21,"text":"Which cause of economic growth would involve the least cost for present and future generations of a country's population?","options":[{"label":"A","text":"increased exploitation of a country's mineral resources"},{"label":"B","text":"investment financed by borrowing from abroad"},{"label":"C","text":"investment financed by high rates of domestic savings"},{"label":"D","text":"technological innovations in production processes"}],"correct":""},{"id":22,"text":"Which curve is shown in the diagram?","options":[{"label":"A","text":"Kuznets curve"},{"label":"B","text":"Laffer curve"},{"label":"C","text":"Lorenz curve"},{"label":"D","text":"Phillips curve"}],"correct":"","image":"/images/econ-mcq/83_581_1161_632_370_0.jpg"},{"id":23,"text":"Which indicator is least likely to be used when measuring the comparative economic development of an economy?","options":[{"label":"A","text":"mean years of schooling"},{"label":"B","text":"average life expectancy at birth"},{"label":"C","text":"level of real GNP per head"},{"label":"D","text":"size of population"}],"correct":""},{"id":24,"text":"Which statement would be associated with Keynesian economic theory?","options":[{"label":"A","text":"A change in the money supply is the main determinant of the rate of inflation."},{"label":"B","text":"When unemployment falls below its natural rate, there is upward pressure on prices."},{"label":"C","text":"Total spending in the economy affects real output and employment in the short run."},{"label":"D","text":"Wages and prices are flexible so output and employment will always return to its equilibrium rate."}],"correct":""},{"id":25,"text":"In a closed economy with no government sector, the multiplier shows the impact of a change in","options":[{"label":"A","text":"consumption on investment."},{"label":"B","text":"investment on national income."},{"label":"C","text":"national income on consumption."},{"label":"D","text":"national income on investment."}],"correct":""},{"id":26,"text":"The table shows key macroeconomic indicators for four countries in 2018. } What can be concluded from the table?","options":[{"label":"A","text":"Countries with current account surpluses had low unemployment rates."},{"label":"B","text":"Countries with high economic growth rates had high inflation rates."},{"label":"C","text":"Countries with low economic growth rates had high unemployment rates."},{"label":"D","text":"Countries with positive economic growth rates had current account deficits."}],"correct":""}];

const paper_12: MCQQuestion[] = [{"id":1,"text":"What will help solve the basic economic problem?","options":[{"label":"A","text":"the control of the market system"},{"label":"B","text":"the efficient allocation of scarce resources"},{"label":"C","text":"the preservation of a healthy environment"},{"label":"D","text":"The elimination of hunger"}],"correct":""},{"id":2,"text":"A country's health care is funded by taxation but can be used free of charge by patients. Which type of good is health care in this country?","options":[{"label":"A","text":"demerit good"},{"label":"B","text":"free good"},{"label":"C","text":"private good"},{"label":"D","text":"public good"}],"correct":""},{"id":3,"text":"What is least likely to increase as a result of a transition from a planned economy to a free market economy?","options":[{"label":"A","text":"prices of goods and services"},{"label":"B","text":"privately owned resources"},{"label":"C","text":"provision of merit goods"},{"label":"D","text":"structural unemployment"}],"correct":""},{"id":4,"text":"Which statement correctly describes the area of producer surplus on a demand and supply diagram?","options":[{"label":"A","text":"It is above the supply curve and below the equilibrium price line."},{"label":"B","text":"It is above the supply curve and below the demand curve."},{"label":"C","text":"It is below the demand curve and above the equilibrium price line."},{"label":"D","text":"It is below the supply curve and above the horizontal axis."}],"correct":""},{"id":5,"text":"In a free market, there is a surplus of a good. Which change would cause the market to come to an equilibrium?","options":[{"label":"A","text":"a decrease in demand"},{"label":"B","text":"a fall in price"},{"label":"C","text":"a government minimum price"},{"label":"D","text":"an increase in supply"}],"correct":""},{"id":6,"text":"In the diagram, the supply curve shows the number of spaces in a car park and the demand curves show the demand for spaces on four different days, \\({D}_{1},{D}_{2},{D}_{3}\\) and \\({D}_{4}\\) . The owner wishes to charge a parking fee on each of these days to allocate the spaces according to the market mechanism. Which pricing policy should the owner use?","options":[{"label":"A","text":"set a fixed price at \\({\\mathrm{P}}_{1}\\)"},{"label":"B","text":"set a fixed price at \\({\\mathrm{P}}_{4}\\)"},{"label":"C","text":"vary prices between \\({\\mathrm{P}}_{2}\\) and \\({\\mathrm{P}}_{3}\\)"},{"label":"D","text":"vary prices between \\({\\mathrm{P}}_{1}\\) and \\({\\mathrm{P}}_{4}\\)"}],"correct":"","image":"/images/econ-as-mcq/117_534_1223_734_426_0.jpg"},{"id":7,"text":"The table shows the demand schedule for textbooks. } What can be concluded from this information?","options":[{"label":"A","text":"Profit would be maximised at a price of \\$30."},{"label":"B","text":"Profit would not change if the price rose from \\$20 to \\$30."},{"label":"C","text":"Revenue would increase if the price was decreased from \\$40 to \\$30."},{"label":"D","text":"Revenue would be maximised at a price of \\$40."}],"correct":"","table":"<table><tr><td>quantity demanded</td></tr><tr><td>50</td><td>0</td></tr><tr><td>40</td><td>100</td></tr><tr><td>30</td><td>200</td></tr><tr><td>20</td><td>300</td></tr><tr><td>10</td><td>400</td></tr><tr><td>0</td><td>500</td></tr></table>"},{"id":8,"text":"Which event is most likely to enable firms to respond to an increase in demand by increasing supply rather than by raising price?","options":[{"label":"A","text":"Firms reduce their expenditure on the training of workers."},{"label":"B","text":"Import duties are increased on machines that increase the speed of production."},{"label":"C","text":"The government introduces buffer stock schemes for the goods produced by the firm."},{"label":"D","text":"Trade unions become strong, leading to poor labour productivity."}],"correct":""},{"id":9,"text":"In the diagram, \\({S}_{1}\\) is the supply curve and \\({D}_{1}\\) is the initial demand for facemask X. A rival firm produces facemask Y, which is a close substitute. What would cause the demand curve to shift to \\({\\mathrm{D}}_{2}\\) ?","options":[{"label":"A","text":"a decrease in the costs of the materials to make facemask X"},{"label":"B","text":"a decrease in the costs of the materials to make facemask Y"},{"label":"C","text":"an increase in the price of facemask X"},{"label":"D","text":"an increase in the price of facemask Y"}],"correct":"","image":"/images/econ-as-mcq/119_555_266_685_502_0.jpg"},{"id":10,"text":"A government introduces charges for vehicles using the roads in its capital city. Which characteristic must the roads have for this to be successful in reducing congestion?","options":[{"label":"A","text":"The roads must be excludable."},{"label":"B","text":"The roads must be merit goods."},{"label":"C","text":"The roads must be non-rivalrous."},{"label":"D","text":"The roads must be public goods."}],"correct":""},{"id":11,"text":"What is not included in the measurement of national income?","options":[{"label":"A","text":"benefits paid to the unemployed"},{"label":"B","text":"dividends paid to shareholders"},{"label":"C","text":"profits retained by companies"},{"label":"D","text":") rent paid to landlords"}],"correct":""},{"id":12,"text":"Which statement best describes the consumer prices index (CPI)?","options":[{"label":"A","text":"It is a measure of changes in the spending patterns of the average household."},{"label":"B","text":"It is a measure of changes in the standard of living of the average household."},{"label":"C","text":"It is a measure of the average change in prices of a basket of goods and services over time."},{"label":"D","text":"It is a measure of the level of prices of all goods and services."}],"correct":""},{"id":13,"text":"The diagram shows the production possibility curves (PPCs) for country X and country Y, the only two countries in the world. Both countries produce just two goods, M and N. Under which terms of trade will both country X and country Y benefit from trading with each other?","options":[{"label":"A","text":"1M for 0.75N"},{"label":"B","text":"1M for 0.8N"},{"label":"C","text":"1M for 1N"},{"label":"D","text":"1M for 2N"}],"correct":"","image":"/images/econ-as-mcq/122_561_266_677_548_0.jpg"},{"id":14,"text":"Why is increased government provision of education most likely to shift the aggregate demand curve to the right?","options":[{"label":"A","text":"It will increase aggregate supply."},{"label":"B","text":"More schools will be built."},{"label":"C","text":"The government will have to raise taxes."},{"label":"D","text":"Workers will be more highly skilled."}],"correct":""},{"id":15,"text":"Which item is not included in the current account of a country's balance of payments?","options":[{"label":"A","text":"exports of services"},{"label":"B","text":"interest on foreign loans"},{"label":"C","text":"profits from foreign investments"},{"label":"D","text":"the purchase of foreign assets"}],"correct":""},{"id":16,"text":"General equilibrium in the macroeconomy is achieved when total injections are equal to total leakages. What is most likely to cause disequilibrium in the macroeconomy in the short run?","options":[{"label":"A","text":"an increase in government spending of \\$10bn and a decrease in exports of \\$10bn"},{"label":"B","text":"an increase in investment of \\$30bn and a decrease in household savings of \\$30bn"},{"label":"C","text":"an increase in spending on imports of \\$40bn and an increase in government spending of \\$40bn"},{"label":"D","text":"an increase in taxation of \\$40bn and a decrease in spending on imports of \\$40bn"}],"correct":""},{"id":17,"text":"What would be the most likely reason for a decrease in frictional unemployment?","options":[{"label":"A","text":"more capital-intensive manufacturing"},{"label":"B","text":"more demand for public sector workers"},{"label":"C","text":"more government spending on education"},{"label":"D","text":"more information on labour market vacancies"}],"correct":""},{"id":18,"text":"A Kenyan banker who lives and works in India sends 15\\% of their wage back to Kenya every month. What would be the change in the current account components for either country?","options":[{"label":"A","text":"a fall in secondary income for India"},{"label":"B","text":"an increase in the balance of trade in services for Kenya"},{"label":"C","text":"an increase in the current account surplus for India"},{"label":"D","text":"an increase in primary income for Kenya"}],"correct":""},{"id":19,"text":"Over a period of a year, the annual rate of inflation becomes negative. Which statement must be correct?","options":[{"label":"A","text":"The cost of living has fallen."},{"label":"B","text":"The purchasing power of money has fallen."},{"label":"C","text":"The standard of living has increased."},{"label":"D","text":"There has been an increase in the Consumer Price Index."}],"correct":""},{"id":20,"text":"An economy is experiencing accelerating cost-push inflation. Which group is likely to be least concerned by this?","options":[{"label":"A","text":"borrowers"},{"label":"B","text":"consumers"},{"label":"C","text":"creditors"},{"label":"D","text":"exporters"}],"correct":""},{"id":21,"text":"A Kenyan banker who lives and works in India sends 15% of their wage back to Kenya every month. What would be the change in the current account components for either country?","options":[{"label":"A","text":"a fall in secondary income for India"},{"label":"B","text":"an increase in the balance of trade in services for Kenya"},{"label":"C","text":"an increase in the current account surplus for India"},{"label":"D","text":"an increase in primary income for Kenya"}],"correct":""},{"id":22,"text":"A country maintains its foreign exchange rate against the United States dollar, within a narrow but changing band. What is this type of exchange rate?","options":[{"label":"A","text":"fixed"},{"label":"B","text":"floating"},{"label":"C","text":"managed float"},{"label":"D","text":"trade-weighted"}],"correct":""},{"id":23,"text":"What is likely to happen in a developing country as it becomes more developed?","options":[{"label":"A","text":"A lower percentage of people will go to university."},{"label":"B","text":"Average life expectancy will rise."},{"label":"C","text":"The rate of population growth will increase."},{"label":"D","text":"The tertiary sector will decline in importance."}],"correct":""},{"id":24,"text":"Which cause of economic growth would involve the least cost for present and future generations of a country's population?","options":[{"label":"A","text":"increased exploitation of a country's mineral resources"},{"label":"B","text":"investment financed by borrowing from abroad"},{"label":"C","text":"investment financed by high rates of domestic savings"},{"label":"D","text":"technological innovations in production processes"}],"correct":""},{"id":25,"text":"Which curve is shown in the diagram?","options":[{"label":"A","text":"Kuznets curve"},{"label":"B","text":"Laffer curve"},{"label":"C","text":"Lorenz curve"},{"label":"D","text":"Phillips curve"}],"correct":"","image":"/images/econ-mcq/83_581_1161_632_370_0.jpg"},{"id":26,"text":"Which indicator is least likely to be used when measuring the comparative economic development of an economy?","options":[{"label":"A","text":"mean years of schooling"},{"label":"B","text":"average life expectancy at birth"},{"label":"C","text":"level of real GNP per head"},{"label":"D","text":"size of population"}],"correct":""}];

const paper_13: MCQQuestion[] = [{"id":1,"text":"What is considered the essential requirement for all entrepreneurs?","options":[{"label":"A","text":"attracting customers"},{"label":"B","text":"buying stock"},{"label":"C","text":"managing staff"},{"label":"D","text":"taking risks"}],"correct":""},{"id":2,"text":"A new section of a road is provided toll-free by the government. What best describes this good?","options":[{"label":"A","text":"a demerit good"},{"label":"B","text":"a free good"},{"label":"C","text":"a private good"},{"label":"D","text":"a public good"}],"correct":""},{"id":3,"text":"Eastern European nations have changed from planned to market economies. Which policy was least likely to have been adopted?","options":[{"label":"A","text":"allowing prices to fluctuate"},{"label":"B","text":"keeping established economic organisations"},{"label":"C","text":"privatising essential industries"},{"label":"D","text":"permitting changes in the money supply"}],"correct":""},{"id":4,"text":"Rice and pasta are both basic foods in a country. How would a health scare concerning rice affect the market for pasta?","options":[{"label":"A","text":"There will be a shift of demand and a contraction of supply."},{"label":"B","text":"There will be a shift of demand and an extension of supply."},{"label":"C","text":"There will be a shift of supply and a contraction of demand."},{"label":"D","text":"There will be a shift of supply and an extension of demand."}],"correct":""},{"id":5,"text":"Some goods are over-consumed in a market economy. What is likely to be the cause of this?","options":[{"label":"A","text":"Consumer surplus exceeds producer surplus."},{"label":"B","text":"Consumers undervalue the benefits of consuming the goods."},{"label":"C","text":"There is excess supply in the market for the goods."},{"label":"D","text":"There is imperfect information in the market."}],"correct":""},{"id":6,"text":"The equation for the quantity demanded, \\({Q}_{D}\\) , for a product is {\\mathrm{Q}}_{\\mathrm{D}} = {400} - {20}\\mathrm{P} where \\(P =\\) price in \\$. The quantity supplied, \\({Q}_{S}\\) , is given by \\({Q}_{S} = {100} + {40P}\\) . Which change will occur if the price rises from \\$5 to \\$6?","options":[{"label":"A","text":"The market will move from equilibrium to shortage."},{"label":"B","text":"The market will move from equilibrium to surplus."},{"label":"C","text":"The market will move from shortage to surplus."},{"label":"D","text":"The market will move from surplus to shortage."}],"correct":""},{"id":7,"text":"What is the most likely cause of the continuous increase in prices of famous paintings by now dead artists?","options":[{"label":"A","text":"the increasing technological ability to copy famous paintings perfectly"},{"label":"B","text":"the popular view that famous paintings are an appreciating asset"},{"label":"C","text":"the totally inelastic supply of famous paintings by dead artists"},{"label":"D","text":"the wish of governments to treat art galleries as merit goods"}],"correct":""},{"id":8,"text":"What is most likely to be regressive?","options":[{"label":"A","text":"corporate profit taxes"},{"label":"B","text":"state pension benefits"},{"label":"C","text":"specific tax on cigarettes"},{"label":"D","text":"unemployment benefits"}],"correct":""},{"id":9,"text":"What is necessary for an action to be classed as a transfer payment?","options":[{"label":"A","text":"It must include a cash payment."},{"label":"B","text":"It must involve a banking transaction."},{"label":"C","text":"It must originate from government activity."},{"label":"D","text":"It must relate to a non-productive activity."}],"correct":""},{"id":10,"text":"The government imposes a specific indirect tax of \\$1 on each unit of a good sold. How does the imposition of the tax shift the demand or supply curve of the good?","options":[{"label":"A","text":"The demand curve of the good will shift vertically downwards by \\$1."},{"label":"B","text":"The demand curve of the good will shift vertically upwards by \\$1."},{"label":"C","text":"The supply curve of the good will shift vertically downwards by \\$1."},{"label":"D","text":"The supply curve of the good will shift vertically upwards by \\$1."}],"correct":""},{"id":11,"text":"Which term relates to a fall in the domestic real value of a currency?","options":[{"label":"A","text":"deflation"},{"label":"B","text":"depreciation"},{"label":"C","text":"appreciation"},{"label":"D","text":"inflation"}],"correct":""},{"id":12,"text":"What must be the result for a country of a rise in its export prices relative to its import prices?","options":[{"label":"A","text":"a deficit in its trade in goods"},{"label":"B","text":"an improvement in its terms of trade"},{"label":"C","text":"an increase in its inflation rate"},{"label":"D","text":"a rise in its exchange rate"}],"correct":""},{"id":13,"text":"Country X can produce a product at a lower opportunity cost than country Y. Which term best describes this statement?","options":[{"label":"A","text":"absolute advantage"},{"label":"B","text":"comparative advantage"},{"label":"C","text":"specialisation"},{"label":"D","text":"terms of trade"}],"correct":""},{"id":14,"text":"The graph shows the rate of inflation in Japan from April 2020 to February 2021. Apr May June July Aug Sept Oct Nov Dec Jan Feb Over which period did disinflation occur in Japan?","options":[{"label":"A","text":"July 2020 to February 2021"},{"label":"B","text":"July 2020 to September 2020"},{"label":"C","text":"October 2020 to December 2020"},{"label":"D","text":"October 2020 to February 2021"}],"correct":"","image":"/images/econ-as-mcq/132_269_234_1255_469_0.jpg"},{"id":15,"text":"A government increases the rate of income tax. What is the effect, in the short run, on the aggregate demand curve or the aggregate supply curve?","options":[{"label":"A","text":"The aggregate demand curve shifts left."},{"label":"B","text":"The aggregate demand curve shifts right."},{"label":"C","text":"The aggregate supply curve shifts left."},{"label":"D","text":"The aggregate supply curve shifts right."}],"correct":""},{"id":16,"text":"A country's current account deficit is larger this year than last. What is the most likely reason for this increase?","options":[{"label":"A","text":"Demand for domestically produced goods has risen."},{"label":"B","text":"Domestic inflation has risen faster than the inflation of its major trading partners."},{"label":"C","text":"Domestic unemployment has risen."},{"label":"D","text":"The exchange rate has depreciated."}],"correct":""},{"id":17,"text":"Which supply-side measure is most likely to produce short-run growth in a country's aggregate supply?","options":[{"label":"A","text":"easing of controls on immigration of workers"},{"label":"B","text":"expenditure on primary education"},{"label":"C","text":"expenditure on research and development"},{"label":"D","text":"privatisation of public utilities"}],"correct":""},{"id":18,"text":"Which tax may a government use to reduce inequality?","options":[{"label":"A","text":"progressive income tax"},{"label":"B","text":"proportionate income tax"},{"label":"C","text":"proportionate indirect tax"},{"label":"D","text":") specific indirect tax"}],"correct":""},{"id":19,"text":"The graph shows the rate of inflation in Japan from April 2020 to February 2021. Apr May June July Aug Sept Oct Nov Dec Jan Feb 2020 Over which period did disinflation occur in Japan?","options":[{"label":"A","text":"July 2020 to February 2021"},{"label":"B","text":"July 2020 to September 2020"},{"label":"C","text":"October 2020 to December 2020"},{"label":"D","text":"October 2020 to February 2021"}],"correct":"","image":"/images/econ-as-mcq/132_269_234_1255_469_0.jpg"},{"id":20,"text":"The graph plots the Gini coefficient and GDP per head for three countries, X, Y and Z. What can be concluded from the graph?","options":[{"label":"A","text":"Average incomes are higher in country X than in country Z."},{"label":"B","text":"Country X is the least developed country."},{"label":"C","text":"Income is equally distributed in country Y."},{"label":"D","text":"The distribution of income in country \\(Y\\) is more even than in country \\(X\\) ."}],"correct":"","image":"/images/econ-mcq/87_576_973_857_406_0.jpg"},{"id":21,"text":"What is least likely to lead to an increase in optimum population?","options":[{"label":"A","text":"an improvement in labour productivity"},{"label":"B","text":"an improvement in the quality of capital and technology"},{"label":"C","text":"an increase in birth rate and a fall in death rate"},{"label":"D","text":"an increase in the availability of natural resources"}],"correct":""},{"id":22,"text":"What is not included as a weighted indicator of poverty in the Multidimensional Poverty Index (MPI)?","options":[{"label":"A","text":"cooking fuel"},{"label":"B","text":"electricity"},{"label":"C","text":"medication"},{"label":"D","text":"water"}],"correct":""},{"id":23,"text":"Which role is performed by the World Bank but not by the International Monetary Fund (IMF)?","options":[{"label":"A","text":"facilitating free trade among member countries"},{"label":"B","text":"providing assistance to member countries to plan fiscal policies"},{"label":"C","text":"providing bailout packages to countries facing external account challenges"},{"label":"D","text":"providing monetary assistance to member countries to build infrastructure"}],"correct":""},{"id":24,"text":"Some economists argue there is little evidence of the value of aid in improving economic development in less-developed countries. Which situation supports this claim?","options":[{"label":"A","text":"Capacity to benefit from transfer of communications technology has increased."},{"label":"B","text":"Investment in infrastructure has created transport links and port facilities."},{"label":"C","text":"Over-reliance on technical assistance has impaired local initiatives and innovation."},{"label":"D","text":"Projects for education and training have helped to enhance the supply side."}],"correct":""},{"id":25,"text":"A country imports most of the raw materials used as factor inputs. Which policy is most likely to control cost-push inflation?","options":[{"label":"A","text":"an appreciation of the exchange rate"},{"label":"B","text":"an increase in the rate of income tax"},{"label":"C","text":"an increase in the rate of interest"},{"label":"D","text":"an increase in the rate of sales tax"}],"correct":""},{"id":26,"text":"A country maintains its foreign exchange rate against the United States dollar, within a narrow but changing band. What is this type of exchange rate?","options":[{"label":"A","text":"fixed"},{"label":"B","text":"floating"},{"label":"C","text":"managed float"},{"label":"D","text":"trade-weighted"}],"correct":""},{"id":27,"text":"What is likely to happen in a developing country as it becomes more developed?","options":[{"label":"A","text":"A lower percentage of people will go to university."},{"label":"B","text":"Average life expectancy will rise."},{"label":"C","text":"The rate of population growth will increase."},{"label":"D","text":"The tertiary sector will decline in importance."}],"correct":""}];

const paper_14: MCQQuestion[] = [{"id":1,"text":"Which item would be least likely to be classed as land?","options":[{"label":"A","text":"fertilisers"},{"label":"B","text":"fisheries"},{"label":"C","text":"forests"},{"label":"D","text":"coal"}],"correct":""},{"id":2,"text":"Why does the concept of scarcity apply to the use of fossil fuels?","options":[{"label":"A","text":"Demand fluctuates according to price changes."},{"label":"B","text":"Supply is insufficient to meet demand."},{"label":"C","text":"Their use is restricted because of harmful pollution."},{"label":"D","text":"They are being replaced by renewable energy sources."}],"correct":""},{"id":3,"text":"An economist knows the current point at which an economy operates within its production possibility curve. What can the economist conclude about this economy?","options":[{"label":"A","text":"its degree of self-sufficiency"},{"label":"B","text":"its international competitiveness"},{"label":"C","text":"its level of output of two goods"},{"label":"D","text":"its rate of economic growth"}],"correct":""},{"id":4,"text":"An increase in which factor is likely to cause a shift to the left of the demand curve for cinema movies?","options":[{"label":"A","text":"expenses for the heating system in the cinema"},{"label":"B","text":"payments charged by movie scriptwriters"},{"label":"C","text":"the cost of transport to the cinema"},{"label":"D","text":"taxes on the incomes of cinema operators"}],"correct":""},{"id":5,"text":"Which statement is correct?","options":[{"label":"A","text":"Demand for an inferior good has a positive relationship to income and a negative relationship to price."},{"label":"B","text":"Demand for an inferior good has a negative relationship to income and a negative relationship to price."},{"label":"C","text":"Demand for a normal good has a positive relationship to income and a positive relationship to price."},{"label":"D","text":"Demand for a normal good has a negative relationship to income and a positive relationship to price."}],"correct":""},{"id":6,"text":"A firm calculates that the income elasticity of demand for its product is -3.0. What can be deduced from this information?","options":[{"label":"A","text":"In a period of economic growth, its total revenue should increase."},{"label":"B","text":"In a period of economic recession, its total revenue should increase."},{"label":"C","text":"It has few substitutes so it should increase its price to increase total revenue."},{"label":"D","text":"It has many substitutes so it should decrease price to increase total revenue."}],"correct":""},{"id":7,"text":"A government gives free food to poor households in a community. What is this food an example of?","options":[{"label":"A","text":"a free good"},{"label":"B","text":"a public good"},{"label":"C","text":"a demerit good"},{"label":"D","text":"a normal good"}],"correct":""},{"id":8,"text":"A government wishes to raise the incomes of farmers without raising the price of food to consumers. Which policy should it use?","options":[{"label":"A","text":"a maximum price below the market price for food"},{"label":"B","text":"a minimum price below the market price for food"},{"label":"C","text":"a payment of a subsidy to farmers to produce food"},{"label":"D","text":"a release of government food stocks onto the market"}],"correct":""},{"id":9,"text":"Governments in market economies give different reasons for intervening in the operation of an economy. Which reason given is a normative statement?","options":[{"label":"A","text":"Average incomes have failed to keep pace with price rises during the past year."},{"label":"B","text":"Energy prices have increased by more than 50\\% during the past year."},{"label":"C","text":"The distribution of incomes has become more unfair during the past year."},{"label":"D","text":"The poorest 10\\% of households have suffered the greatest fall in average real income during the past year."}],"correct":""},{"id":10,"text":"A country's net national income (NNI) is less than its gross national income (GNI). What does this mean?","options":[{"label":"A","text":"incomes earned overseas were less than incomes sent overseas"},{"label":"B","text":"inflation has been accounted for in NNI but not in GNI"},{"label":"C","text":"the country's exports decreased"},{"label":"D","text":"There has been a net depreciation in the value of the country's fixed capital assets"}],"correct":""},{"id":11,"text":"Asha is currently unemployed. She has been offered a job but has decided to decline the offer and search for a better paid job. Which type of unemployment is this?","options":[{"label":"A","text":"cyclical"},{"label":"B","text":"frictional"},{"label":"C","text":"seasonal"},{"label":"D","text":"structural"}],"correct":""},{"id":12,"text":"Why would a fall in a country's average price level cause its aggregate demand curve to slope downwards?","options":[{"label":"A","text":"It leads to an increase in interest rates."},{"label":"B","text":"It reduces the real value of money balances."},{"label":"C","text":"It makes the country's goods cheaper relative to foreign goods."},{"label":"D","text":"It leads to the expectation of further price falls."}],"correct":""},{"id":13,"text":"To counter deflation a central bank uses expansionary monetary policy. What is likely to result?","options":[{"label":"A","text":"a higher cost of borrowing"},{"label":"B","text":"an increase in aggregate demand"},{"label":"C","text":"an appreciation of the exchange rate"},{"label":"D","text":"an increase in government debt"}],"correct":""},{"id":14,"text":"What is most likely to decrease if a government uses expansionary fiscal policy?","options":[{"label":"A","text":"a balance of payments deficit"},{"label":"B","text":"cyclical unemployment"},{"label":"C","text":"the level of wages"},{"label":"D","text":"the rate of inflation"}],"correct":""},{"id":15,"text":"Sweden had a change in its Consumer Prices Index (CPI) of -0.6\\%. Which combination of policies might its government use to restore price stability?","options":[{"label":"A","text":"increase interest rates and increase indirect taxes"},{"label":"B","text":"increase interest rates and reduce government spending"},{"label":"C","text":"reduce government spending and increase income tax"},{"label":"D","text":"reduce interest rates and increase government spending"}],"correct":""},{"id":16,"text":"What is not an example of protectionism?","options":[{"label":"A","text":"export subsidies"},{"label":"B","text":"import subsidies"},{"label":"C","text":"quotas"},{"label":"D","text":"tariffs"}],"correct":""},{"id":17,"text":"The table shows the number of Turkish lira (TRY) which can be exchanged for one US dollar (USD) in 2016 and 2021. } What is the most likely cause of the change in the price of Turkish lira between 2016 and 2021?","options":[{"label":"A","text":"a sustained fall in the demand for Turkish imports"},{"label":"B","text":"a sustained fall in Turkish government debt as a percentage of GDP"},{"label":"C","text":"a sustained rise in Turkish interest rates"},{"label":"D","text":"a sustained rise in Turkish inflation"}],"correct":"","table":"<table><tr><td>exchange rate</td></tr><tr><td>July 2016</td><td>1 USD = 2.83 TRY</td></tr><tr><td>July 2021</td><td>1 USD = 8.15 TRY</td></tr></table>"},{"id":18,"text":"The table shows the current account of a balance of payments for January 2021. } What is the current account balance?","options":[{"label":"A","text":"a deficit of \\$2340m"},{"label":"B","text":"a deficit of \\$2000m"},{"label":"C","text":"a surplus of \\$2340m"},{"label":"D","text":"a surplus of \\$2000m"}],"correct":"","table":"<table><tr><td>$m</td></tr><tr><td>exports of goods</td><td>15000</td></tr><tr><td>imports of goods</td><td>17000</td></tr><tr><td>services</td></tr><tr><td>credit</td><td>2500</td></tr><tr><td>debit</td><td>2000</td></tr><tr><td>primary income</td></tr><tr><td>credit</td><td>100</td></tr><tr><td>debit</td><td>1000</td></tr><tr><td>secondary income balance</td><td>60</td></tr></table>"},{"id":19,"text":"A finance company incurs heavy losses and makes an accountant redundant. The accountant seeks a new job through an employment agency which specialises in jobs in accounting. What describes the type of unemployment of the accountant who is seeking a new job?","options":[{"label":"A","text":"frictional"},{"label":"B","text":"seasonal"},{"label":"C","text":"structural"},{"label":"D","text":"technological"}],"correct":""},{"id":20,"text":"An aggregate demand curve slopes downwards from left to right. One reason for this is that a reduction in the average price level will lead to","options":[{"label":"A","text":"a decline in the country's international competitiveness."},{"label":"B","text":"an increase in interest rates."},{"label":"C","text":"an increase in the real value of money balances."},{"label":"D","text":"the expectation of further price falls."}],"correct":""},{"id":21,"text":"What is not included in the measurement of national income?","options":[{"label":"A","text":"dividends paid to shareholders"},{"label":"B","text":"overtime payments"},{"label":"C","text":"rents from government-owned houses"},{"label":"D","text":"welfare benefit payments"}],"correct":""},{"id":22,"text":"The graph shows the rate of inflation for seven countries for 2015 and 2016. What can be concluded from this graph?","options":[{"label":"A","text":"Prices in Costa Rica rose in 2015 but remained constant in 2016."},{"label":"B","text":"Prices in Ecuador and Mauritius were lower in 2016 than in 2015."},{"label":"C","text":"Prices in India and Malaysia remained constant in 2016 and 2015."},{"label":"D","text":"Prices in Thailand and Japan were lower in 2016 than in 2015."}],"correct":"","image":"/images/econ-as-mcq/141_304_588_1195_715_0.jpg"},{"id":23,"text":"What is the most likely cause of a current account deficit on the balance of payments?","options":[{"label":"A","text":"an undervalued exchange rate"},{"label":"B","text":"a relatively low rate of inflation"},{"label":"C","text":"a shrinking domestic economy"},{"label":"D","text":"a general fall in national productivity"}],"correct":""},{"id":24,"text":"A government aims to reduce unemployment through expansionary fiscal policy and borrows more from the commercial banks, increasing its borrowing requirement. What will be the result?","options":[{"label":"A","text":"a decrease in the budget deficit"},{"label":"B","text":"a decrease in the national debt"},{"label":"C","text":"an increase in the balance of payments deficit on the current account"},{"label":"D","text":"an increase in the interest rates"}],"correct":""},{"id":25,"text":"A government wants to use an expansionary monetary policy. What should the government increase?","options":[{"label":"A","text":"credit regulations"},{"label":"B","text":"the exchange rate"},{"label":"C","text":"the interest rate"},{"label":"D","text":"the money supply"}],"correct":""},{"id":26,"text":"Which policy does a central bank undertake to pursue quantitative easing?","options":[{"label":"A","text":"purchase long-term government debt from the public"},{"label":"B","text":"purchase short-term government debt from the public"},{"label":"C","text":"sell long-term government debt to the public"},{"label":"D","text":"sell short-term government debt to the public"}],"correct":""},{"id":27,"text":"Which statement would both Keynesian and Monetarist schools of thought accept?","options":[{"label":"A","text":"High inflation and high unemployment are undesirable in a properly-functioning economy."},{"label":"B","text":"Increased government spending on investment projects will always crowd out private investment."},{"label":"C","text":"The best way for an economy to get out of a recession is for the government to increase its expenditure."},{"label":"D","text":"The most effective way to reduce inflation is for the government to exercise tight control over the money supply."}],"correct":""},{"id":28,"text":"In country X the marginal rate of income tax imposed on the highest earners was \\({83}\\%\\) which increased to 98\\% if income was received from interest or dividends. The highest marginal rate was then reduced to 40\\%. Despite this reduction, the tax revenue raised from the highest earners increased substantially. Which theoretical concept illustrates this relationship between tax rates and tax revenue?","options":[{"label":"A","text":"the J curve"},{"label":"B","text":"the Laffer curve"},{"label":"C","text":"the Marshall-Lerner condition"},{"label":"D","text":"the Phillips curve"}],"correct":""},{"id":29,"text":"A government is increasing the role of market forces in its economy. However, it imposed temporary maximum price controls. Why might a government, committed to reducing central planning, introduce price controls?","options":[{"label":"A","text":"to increase allocative efficiency"},{"label":"B","text":"to increase the incentive for producers to raise supply"},{"label":"C","text":"to reduce consumer demand"},{"label":"D","text":"to reduce expectations of inflation"}],"correct":""},{"id":30,"text":"Some economists argue there is little evidence of the value of aid in improving economic development in less-developed countries. Which situation supports this claim?","options":[{"label":"A","text":"Capacity to benefit from transfer of communications technology has increased."},{"label":"B","text":"Investment in infrastructure has created transport links and port facilities."},{"label":"C","text":"Over-reliance on technical assistance has impaired local initiatives and innovation."},{"label":"D","text":"Projects for education and training have helped to enhance the supply side."}],"correct":""}];

const paper_15: MCQQuestion[] = [{"id":1,"text":"What is not an example of a public good?","options":[{"label":"A","text":"education"},{"label":"B","text":"flood control systems"},{"label":"C","text":"national defence"},{"label":"D","text":"street lighting"}],"correct":""},{"id":2,"text":"The diagram shows a production possibility curve for an economy that produces two goods, X and Y. When will the opportunity cost of producing more of good X be the largest?","options":[{"label":"A","text":"moving from point E to point F"},{"label":"B","text":"moving from point E to point G"},{"label":"C","text":"moving from point E to point H"},{"label":"D","text":"moving from point G to point H"}],"correct":"","image":"/images/econ-as-mcq/154_607_619_584_472_0.jpg"},{"id":3,"text":"What is essential to eliminate scarcity?","options":[{"label":"A","text":"the existence of sufficient resources to meet all needs and wants"},{"label":"B","text":"producers consistently produce in excess of demand"},{"label":"C","text":"the government has a surplus budget"},{"label":"D","text":"there is equilibrium in all markets"}],"correct":""},{"id":4,"text":"What will encourage a higher degree of division of labour?","options":[{"label":"A","text":"firms wishing for a greater level of self-sufficiency"},{"label":"B","text":"firms wishing to increase their flexibility in production"},{"label":"C","text":"firms wishing to raise their level of productivity"},{"label":"D","text":"firms wishing to reduce their level of risk"}],"correct":""},{"id":5,"text":"Which business is likely to be the slowest to alter its output in response to a sustained increase in demand for its product?","options":[{"label":"A","text":"a fast-food restaurant"},{"label":"B","text":"a household cleaning service"},{"label":"C","text":"a newspaper printer"},{"label":"D","text":"an oil exploration company"}],"correct":""},{"id":6,"text":"What most accurately describes a market supply curve?","options":[{"label":"A","text":"supply at different income levels, assuming product prices remain unchanged"},{"label":"B","text":"supply at different levels of factor prices, assuming product prices remain unchanged"},{"label":"C","text":"supply at different prices, assuming no changes in technology"},{"label":"D","text":") supply at different time periods, assuming no changes in technology"}],"correct":""},{"id":7,"text":"In the diagram, \\({\\mathrm{D}}_{1}\\) shows an individual’s initial demand curve for public transport. What could cause the demand curve to shift to \\({\\mathrm{D}}_{2}\\) ?","options":[{"label":"A","text":"The costs of running the individual's car fall."},{"label":"B","text":"The individual is no longer able to drive."},{"label":"C","text":"The price of public transport falls."},{"label":"D","text":"The public transport services are reduced."}],"correct":"","image":"/images/econ-as-mcq/156_561_1351_671_482_0.jpg"},{"id":8,"text":"A government introduces an effective minimum price for a product but makes no other intervention in the market. This policy suggests that the government's objective is","options":[{"label":"A","text":"to discourage consumption of a demerit good."},{"label":"B","text":"to increase the consumption of a merit good."},{"label":"C","text":"to reduce the price of a private good."},{"label":"D","text":"to support the incomes of producers."}],"correct":""},{"id":9,"text":"The diagram shows the supply curve of a product. The government imposes a specific indirect tax of \\$5 on the product. How will the price elasticity of supply of the product change?","options":[{"label":"A","text":"from elastic (>1) to inelastic (<1)"},{"label":"B","text":"from inelastic (<1) to elastic (>1)"},{"label":"C","text":"from inelastic (<1) to unitary (=1)"},{"label":"D","text":"from unitary (=1) to elastic (>1)"}],"correct":"","image":"/images/econ-as-mcq/158_566_233_661_448_0.jpg"},{"id":10,"text":"The diagram shows the effect on the average price level when aggregate demand (AD) increases from \\({\\mathrm{{AD}}}_{1}\\) to \\({\\mathrm{{AD}}}_{2}\\) . Which statement relating to this change in aggregate demand is correct?","options":[{"label":"A","text":"Nominal GDP has increased."},{"label":"B","text":"Nominal GDP is unchanged."},{"label":"C","text":"Real GDP has increased."},{"label":"D","text":"Real GDP has fallen."}],"correct":"","image":"/images/econ-as-mcq/160_609_268_579_485_0.jpg"},{"id":11,"text":"The table lists the values of the components of an economy's circular flow of income. } What can be concluded about the economy from the information shown?","options":[{"label":"A","text":"It has a budget surplus."},{"label":"B","text":"It has a trade deficit."},{"label":"C","text":"It is a mixed, open economy."},{"label":"D","text":"Its circular flow is in equilibrium."}],"correct":"","table":"<table><tr><td>value $m</td></tr><tr><td>government spending</td><td>6</td></tr><tr><td>exports</td><td>8</td></tr><tr><td>investment</td><td>9</td></tr><tr><td>imports</td><td>7</td></tr><tr><td>saving</td><td>10</td></tr><tr><td>tax</td><td>5</td></tr></table>"},{"id":12,"text":"What is a cost of negative economic growth?","options":[{"label":"A","text":"deteriorating balance of payments"},{"label":"B","text":"higher inflation"},{"label":"C","text":"higher unemployment"},{"label":"D","text":"increased pollution"}],"correct":""},{"id":13,"text":"A government statistical office measured changes in income from employment, pensions and benefits, then subtracted income tax and welfare contributions and adjusted for inflation. What did the final figure represent?","options":[{"label":"A","text":"changes in nominal income"},{"label":"B","text":"changes in nominal net earnings"},{"label":"C","text":"changes in real disposable income"},{"label":"D","text":"changes in real gross earnings"}],"correct":""},{"id":14,"text":"Which macroeconomic objective is most likely to be achieved by increasing income tax?","options":[{"label":"A","text":"depreciation of the exchange rate"},{"label":"B","text":"economic growth"},{"label":"C","text":"low unemployment"},{"label":"D","text":"price stability"}],"correct":""},{"id":15,"text":"What is not a supply-side policy?","options":[{"label":"A","text":"increasing government expenditure on infrastructure"},{"label":"B","text":"increasing research and development expenditure"},{"label":"C","text":"increasing subsidies for education and training"},{"label":"D","text":"increasing the supply of money"}],"correct":""},{"id":16,"text":"When can a policy be classified as macroeconomic?","options":[{"label":"A","text":"when it focuses on the level of individual welfare"},{"label":"B","text":"when it involves economy-wide institutions and behaviour"},{"label":"C","text":"when it is based on the control of monopoly markets"},{"label":"D","text":"when it relies on the use of buffer stock schemes"}],"correct":""},{"id":17,"text":"What is an unintended consequence of the US government restricting imports of cheap Chinese steel?","options":[{"label":"A","text":"US importers of steel pay lower prices for steel."},{"label":"B","text":"US manufacturers become less competitive."},{"label":"C","text":"US steel makers increase steel production."},{"label":"D","text":"US steel workers receive higher incomes."}],"correct":""},{"id":18,"text":"What is an export of services in Jamaica's current account?","options":[{"label":"A","text":"an inflow of funds to Jamaica to buy shares"},{"label":"B","text":"Bearnings from US tourists visiting Jamaica"},{"label":"C","text":"earnings of Haitian workers in Jamaica sent to Haiti"},{"label":"D","text":"the export of Jamaican coffee"}],"correct":""},{"id":19,"text":"A country imports natural gas for which it has price-inelastic demand. What is the effect if that country imposes an import duty on the gas?","options":[{"label":"A","text":"Consumers in the importing country will suffer a loss of consumer surplus."},{"label":"B","text":"The exporting country will gain export revenue."},{"label":"C","text":"The importing country's primary income will increase."},{"label":"D","text":"The price of natural gas will rise in other importing countries."}],"correct":""},{"id":20,"text":"Economists suggest that multilateral trade between many countries is preferable to bilateral trade between two countries. Why is this?","options":[{"label":"A","text":"Bilateral trade means that trade diversion is always greater than trade creation."},{"label":"B","text":"Bilateral trade misses the benefit of trade with third countries."},{"label":"C","text":"Gains from bilateral trade are less than the harm done to third countries."},{"label":"D","text":"Gains from comparative advantage cannot apply in the case of bilateral trade."}],"correct":""},{"id":21,"text":"A country experiences an improvement in its terms of trade. What is the most likely cause?","options":[{"label":"A","text":"a decrease in its budget deficit"},{"label":"B","text":"a relatively low rate of domestic inflation"},{"label":"C","text":"a rise in its exchange rate"},{"label":"D","text":"a surplus on its primary income account"}],"correct":""},{"id":22,"text":"Which policy does a central bank undertake to pursue quantitative easing?","options":[{"label":"A","text":"purchase long-term government debt from the public"},{"label":"B","text":"purchase short-term government debt from the public"},{"label":"C","text":"sell long-term government debt to the public"},{"label":"D","text":"sell short-term government debt to the public"}],"correct":""},{"id":23,"text":"Which statement would both Keynesian and Monetarist schools of thought accept?","options":[{"label":"A","text":"High inflation and high unemployment are undesirable in a properly-functioning economy."},{"label":"B","text":"Increased government spending on investment projects will always crowd out private investment."},{"label":"C","text":"The best way for an economy to get out of a recession is for the government to increase its expenditure."},{"label":"D","text":"The most effective way to reduce inflation is for the government to exercise tight control over the money supply."}],"correct":""},{"id":24,"text":"In country X the marginal rate of income tax imposed on the highest earners was \\({83}\\%\\) which increased to 98\\% if income was received from interest or dividends. The highest marginal rate was then reduced to 40\\%. Despite this reduction, the tax revenue raised from the highest earners increased substantially. Which theoretical concept illustrates this relationship between tax rates and tax revenue?","options":[{"label":"A","text":"the J curve"},{"label":"B","text":"the Laffer curve"},{"label":"C","text":"the Marshall-Lerner condition"},{"label":"D","text":"the Phillips curve"}],"correct":""},{"id":25,"text":"A government is increasing the role of market forces in its economy. However, it imposed temporary maximum price controls. Why might a government, committed to reducing central planning, introduce price controls?","options":[{"label":"A","text":"to increase allocative efficiency"},{"label":"B","text":"to increase the incentive for producers to raise supply"},{"label":"C","text":"to reduce consumer demand"},{"label":"D","text":"to reduce expectations of inflation"}],"correct":""}];

const paper_16: MCQQuestion[] = [{"id":1,"text":"Which statement is a normative statement?","options":[{"label":"A","text":"The annual rate of inflation in Malaysia increased from 2.8\\% in May 2022 to 3.4\\%."},{"label":"B","text":"The annual rate of inflation was 3.4\\% in Malaysia, lower than the 7.7\\% annual rate of inflation for Thailand."},{"label":"C","text":"The Malaysian Central Bank raised interest rates from 2.0\\% to 2.25\\% on 6 July 2022."},{"label":"D","text":"The rise in interest rates in Malaysia in July 2022 is expected to only have a small impact on the rate of inflation."}],"correct":""},{"id":2,"text":"A firm operating in country S moved its existing capital equipment to a larger factory in country T. It also installed more of the same equipment and increased the size of its workforce. From the evidence provided, what must be true?","options":[{"label":"A","text":"The firm is operating in the long run."},{"label":"B","text":"The firm is operating in the very long run."},{"label":"C","text":"The firm's division of labour has increased."},{"label":"D","text":"The firm's supply curve has shifted to the left."}],"correct":""},{"id":3,"text":"Which statement is not correct?","options":[{"label":"A","text":"Addictive drugs are regarded as demerit goods because users are unaware of the full damage they do."},{"label":"B","text":"Air is regarded as a free good because its use has no opportunity cost."},{"label":"C","text":"National defence is regarded as a public good because one citizen 'consuming' it reduces the amount of it available to others."},{"label":"D","text":"Visits to a doctor are regarded as private goods partly because they are rival."}],"correct":""},{"id":4,"text":"Farmers using traditional methods lack access to finance and often employ family members on a part-time basis. If working practices in agriculture could be improved, how would this be likely to be shown on the production possibility curve?","options":[{"label":"A","text":"by a movement from R to T"},{"label":"B","text":"by a movement from S to R"},{"label":"C","text":"by a movement from S to T"},{"label":"D","text":"by a movement from T to R"}],"correct":"","image":"/images/econ-as-mcq/165_587_1383_625_499_0.jpg"},{"id":5,"text":"In a particular year, 12000 units of a good are sold at \\$1 per unit. In a later year, 14000 units are sold at \\$1.20 per unit. If consumer tastes have remained constant, what could account for the change between the two years?","options":[{"label":"A","text":"a decrease in the price of raw materials used by producers"},{"label":"B","text":"an increase in the price of a substitute good"},{"label":"C","text":"an increase in the rate of tax imposed on producers"},{"label":"D","text":"the formation of a monopoly in the production of the good"}],"correct":""},{"id":6,"text":"What is most likely to cause an increase in the consumer surplus in the market for a normal good?","options":[{"label":"A","text":"an increase in consumer incomes"},{"label":"B","text":"an increase in the number of substitute goods"},{"label":"C","text":"an increase in the price of a complementary good"},{"label":"D","text":"an increase in the price of the good"}],"correct":""},{"id":7,"text":"What is not held constant when aggregating individual firms' supply curves to give the short-run market supply curve?","options":[{"label":"A","text":"the number of firms in the industry"},{"label":"B","text":"the price of the product"},{"label":"C","text":"the prices of factors of production"},{"label":"D","text":"the state of technology"}],"correct":""},{"id":8,"text":"Which elasticity would a shortage of skilled workers affect?","options":[{"label":"A","text":"cross elasticity of demand"},{"label":"B","text":"income elasticity of demand"},{"label":"C","text":"price elasticity of demand"},{"label":"D","text":"price elasticity of supply"}],"correct":"","image":"/images/econ-as-mcq/167_591_582_611_494_0.jpg"},{"id":9,"text":"A specific tax is imposed on a product for which the elasticity of supply is zero. Which statement is correct?","options":[{"label":"A","text":"The burden of this tax will fall entirely on consumers."},{"label":"B","text":"The burden of this tax will fall entirely on suppliers."},{"label":"C","text":"The burden of this tax will fall mainly on consumers."},{"label":"D","text":"The burden of this tax will fall mainly on suppliers."}],"correct":""},{"id":10,"text":"The table shows the Consumer Prices Index (CPI) for a country. } Which statement about the period 2008 to 2013 is correct?","options":[{"label":"A","text":"Prices increased each year."},{"label":"B","text":"Prices increased fastest in 2011."},{"label":"C","text":"The rate of inflation was 2\\% in 2010."},{"label":"D","text":"The smallest rise in prices was in 2013."}],"correct":"","table":"<table><tr><td>CPI</td></tr><tr><td>2008</td><td>100</td></tr><tr><td>2009</td><td>104</td></tr><tr><td>2010</td><td>102</td></tr><tr><td>2011</td><td>105</td></tr><tr><td>2012</td><td>108</td></tr><tr><td>2013</td><td>111</td></tr></table>"},{"id":11,"text":"What is most likely to cause the price level to rise? An increase in","options":[{"label":"A","text":"productivity of labour."},{"label":"B","text":"Braw material prices."},{"label":"C","text":"income taxes."},{"label":"D","text":"subsidies paid to producers."}],"correct":""},{"id":12,"text":"What is most likely to increase a country's circular flow of income?","options":[{"label":"A","text":"Its budget deficit increases."},{"label":"B","text":"Its imports increase."},{"label":"C","text":"Its interest rates increase."},{"label":"D","text":"Its exchange rate increases."}],"correct":""},{"id":13,"text":"A country with a constant population experiences a 5\\% increase in its nominal GDP during a year. In which situation will average living standards be most likely to have increased during the year?","options":[{"label":"A","text":"if government takes action to ensure there is no increase in unemployment"},{"label":"B","text":"if inflation during the year is 3\\%"},{"label":"C","text":"if there is no increase in real national income"},{"label":"D","text":"if there is no redistribution of income"}],"correct":""},{"id":14,"text":"Which supply-side policy is most likely to decrease a government's budget deficit?","options":[{"label":"A","text":"cutting tax rates on company profits"},{"label":"B","text":"cutting unemployment benefits"},{"label":"C","text":"raising spending on education and training"},{"label":"D","text":"raising tax-free income tax allowances"}],"correct":""},{"id":15,"text":"The table shows the trade in goods and services for an economy between 2019 and 2021. } What would have most likely caused the change from 2019 to 2021?","options":[{"label":"A","text":"increasing domestic unemployment"},{"label":"B","text":"increasing domestic rate of income tax"},{"label":"C","text":"increasing domestic inflation"},{"label":"D","text":"increasing import tariffs"}],"correct":"","table":"<table><tr><td>trade in goods and services ($ millions)</td></tr><tr><td>2019</td><td>-1000</td></tr><tr><td>2020</td><td>-3000</td></tr><tr><td>2021</td><td>-4000</td></tr></table>"},{"id":16,"text":"A government subsidises training to improve the skills of workers in the industrial sector of an economy. What is the most likely effect on the current account of the balance of payments?","options":[{"label":"A","text":"exports fall"},{"label":"B","text":"exports rise"},{"label":"C","text":"imports fall"},{"label":"D","text":"imports rise"}],"correct":""},{"id":17,"text":"Using all their resources efficiently, country X can produce 6 million tonnes of wheat or 2 million tonnes of steel whilst country Y can produce 4 million tonnes of wheat or 1 million tonnes of steel. Based on this information, what does the theory of comparative advantage suggest?","options":[{"label":"A","text":"Country X should produce only steel."},{"label":"B","text":"Country X will not gain from international trade."},{"label":"C","text":"Country Y has no comparative advantage."},{"label":"D","text":"Country Y will not gain from international trade."}],"correct":""},{"id":18,"text":"Countries X and Y are trade partners. An increase in which economic indicator in country Y is most likely to cause a fall in the exchange rate of country X?","options":[{"label":"A","text":"economic growth"},{"label":"B","text":"inflation rate"},{"label":"C","text":"money supply"},{"label":"D","text":"trade barriers"}],"correct":""},{"id":19,"text":"Which transaction is not recorded in the current account?","options":[{"label":"A","text":"aid received from the government of another country"},{"label":"B","text":"exports of raw materials"},{"label":"C","text":"investments by a foreign company"},{"label":"D","text":"payments of dividends to an overseas investor"}],"correct":""},{"id":20,"text":"A government decides to place a tariff on imports of raw materials. Which statement about the impact of the tariff is correct?","options":[{"label":"A","text":"It will increase costs of production for domestic firms."},{"label":"B","text":"It will increase consumer surplus for domestic consumers."},{"label":"C","text":"It will reduce government revenue."},{"label":"D","text":"There will be a fall in the price of imports and a rise in the demand."}],"correct":""},{"id":21,"text":"In which situation will a country's terms of trade improve?","options":[{"label":"A","text":"Its imports rise in value less than its exports."},{"label":"B","text":"Its imports rise in volume less than its exports."},{"label":"C","text":"The price of its imports rises by less than the prices of its exports."},{"label":"D","text":"The value of its external payments rises by less than the value of its external receipts."}],"correct":""},{"id":22,"text":"The table shows the trade in goods and services for an economy between 2019 and 2021. What would have most likely caused the change from 2019 to 2021?","options":[{"label":"A","text":"increasing domestic unemployment"},{"label":"B","text":"increasing domestic rate of income tax"},{"label":"C","text":"increasing domestic inflation"},{"label":"D","text":"increasing import tariffs"}],"correct":"","table":"<table><tr><td>year</td><td>trade in goods and services ($ millions)</td></tr><tr><td>2019</td><td>-1000</td></tr><tr><td>2020</td><td>-3000</td></tr><tr><td>2021</td><td>-4000</td></tr></table>"},{"id":23,"text":"In country X the marginal rate of income tax imposed on the highest earners was \\({83}\\%\\) which increased to 98\\% if income was received from interest or dividends. The highest marginal rate was then reduced to 40\\%. Despite this reduction, the tax revenue raised from the highest earners increased substantially. Which theoretical concept illustrates this relationship between tax rates and tax revenue?","options":[{"label":"A","text":"the J curve"},{"label":"B","text":"the Laffer curve"},{"label":"C","text":"the Marshall-Lerner condition"},{"label":"D","text":"the Phillips curve"}],"correct":""},{"id":24,"text":"A government is increasing the role of market forces in its economy. However, it imposed temporary maximum price controls. Why might a government, committed to reducing central planning, introduce price controls?","options":[{"label":"A","text":"to increase allocative efficiency"},{"label":"B","text":"to increase the incentive for producers to raise supply"},{"label":"C","text":"to reduce consumer demand"},{"label":"D","text":"to reduce expectations of inflation"}],"correct":""},{"id":25,"text":"The UK gives aid to the Ugandan government to spend on a school. One condition is that they must buy the materials from the UK. Which type of aid does not take place?","options":[{"label":"A","text":"bilateral"},{"label":"B","text":"multilateral"},{"label":"C","text":"project"},{"label":"D","text":"tied"}],"correct":""},{"id":26,"text":"Unemployment in an economy increases. What is a probable consequence?","options":[{"label":"A","text":"a switch from direct to indirect taxation"},{"label":"B","text":"an increase in demand-pull inflation"},{"label":"C","text":"an increase in the balance of trade deficit"},{"label":"D","text":"an increase in the government budget deficit"}],"correct":""}];

const paper_17: MCQQuestion[] = [{"id":1,"text":"The production possibility curve for a country is shown. What can be determined from the diagram?","options":[{"label":"A","text":"the consumers' preferred combination of output"},{"label":"B","text":"the level of economic growth"},{"label":"C","text":"the opportunity cost of manufactured goods in terms of agricultural products"},{"label":"D","text":"the preference for present consumption rather than future consumption"}],"correct":"","image":"/images/econ-as-mcq/173_636_232_525_405_0.jpg"},{"id":2,"text":"In a clothing business, after specialisation, real output per worker increased in the first six months but then output per worker began to fall. What might be the most likely reason for the reduction in productivity?","options":[{"label":"A","text":"An increase in output per worker in the long run depends on an increase in pay."},{"label":"B","text":"An increase in output per worker requires more capital."},{"label":"C","text":"Specialisation means workers lose skills."},{"label":"D","text":"Workers get bored if they are repeating the same work."}],"correct":""},{"id":3,"text":"A wine producer and bottler wanted to expand its production significantly. To finance the expansion it offered investors discounts on restaurant meals if they bought 2000 shares in the company. Which factors of production are most likely to be involved in this expansion?","options":[{"label":"A","text":"labour, land, capital and enterprise"},{"label":"B","text":"labour, land and capital only"},{"label":"C","text":"enterprise and land only"},{"label":"D","text":"enterprise only"}],"correct":""},{"id":4,"text":"The diagram shows the change in a country's production possibility curve from PQ to PR. private goods What increases as a result of the change from PQ to PR?","options":[{"label":"A","text":"the price of private goods"},{"label":"B","text":"the price of public goods"},{"label":"C","text":"the opportunity cost of private goods"},{"label":"D","text":"the opportunity cost of public goods"}],"correct":"","image":"/images/econ-as-mcq/174_591_584_611_465_0.jpg"},{"id":5,"text":"The graph shows the demand and supply curves for an industry. What would cause a shift in the supply curve from \\({S}_{1}\\) to \\({S}_{2}\\) ?","options":[{"label":"A","text":"an increase in the number of firms in the industry"},{"label":"B","text":"an increase in the number of workers employed"},{"label":"C","text":"an increase in the productivity of the workforce"},{"label":"D","text":"an increase in the wage rates paid to workers"}],"correct":"","image":"/images/econ-as-mcq/175_607_233_580_474_0.jpg"},{"id":6,"text":"What is most likely to cause the demand curve of an inferior good to shift to the right?","options":[{"label":"A","text":"a rise in consumers' incomes"},{"label":"B","text":"a rise in income tax"},{"label":"C","text":"a rise in sales tax"},{"label":"D","text":"a rise in the price of a complement"}],"correct":""},{"id":7,"text":"Good X has a substitute, good Y, and a complement, good Z. The price of good Y decreases and the price of good Z increases. Why might the equilibrium price of good X remain unchanged?","options":[{"label":"A","text":"Producers of good X adopt new technology."},{"label":"B","text":"Producers of good X receive a subsidy."},{"label":"C","text":"Some firms stop production of good X."},{"label":"D","text":"The tax on the production of good X is cut."}],"correct":""},{"id":8,"text":"Inequality in an economy can be categorised as either income inequality or wealth inequality. What is most likely to cause greater wealth inequality than income inequality?","options":[{"label":"A","text":"an increase in indirect taxation"},{"label":"B","text":"an increase in the value of property"},{"label":"C","text":"a reduction in the minimum wage"},{"label":"D","text":"a reduction in the rate of interest paid on savings"}],"correct":""},{"id":9,"text":"An economy experiences rising unemployment due to incomes falling as a result of a virus pandemic. How would this unemployment be classified?","options":[{"label":"A","text":"cyclical"},{"label":"B","text":"frictional"},{"label":"C","text":"seasonal"},{"label":"D","text":"structural"}],"correct":""},{"id":10,"text":"What is likely to move an economy's aggregate demand curve to the right?","options":[{"label":"A","text":"a fall in income equality"},{"label":"B","text":"a fall in incomes abroad"},{"label":"C","text":"a fall in the exchange rate"},{"label":"D","text":"a fall in the government budget deficit"}],"correct":""},{"id":11,"text":"Which items have to be added to and subtracted from Gross Domestic Product at market prices to calculate the value of Gross Domestic Product at basic prices?","options":[{"label":"A","text":"capital consumption and net property income from abroad"},{"label":"B","text":"expenditure taxes and capital consumption"},{"label":"C","text":"net property income from abroad and subsidies"},{"label":"D","text":"subsidies and expenditure taxes"}],"correct":""},{"id":12,"text":"In an economy with an interest rate of 4\\% per annum, the rate of inflation falls from 5\\% to 3\\% per annum. What will be a benefit of this fall?","options":[{"label":"A","text":"Menu costs will fall to zero."},{"label":"B","text":"People on fixed incomes will be better off in real terms."},{"label":"C","text":"Savers will gain in real terms."},{"label":"D","text":"The purchasing power of the currency will rise."}],"correct":""},{"id":13,"text":"What is an example of a macroeconomic policy?","options":[{"label":"A","text":"encourage the consumption of merit goods"},{"label":"B","text":"reduce pollution in the steel industry"},{"label":"C","text":"maintain general price stability"},{"label":"D","text":"reduce unemployment in the service sector"}],"correct":""},{"id":14,"text":"Which supply-side policy is likely to lower real output before raising it?","options":[{"label":"A","text":"increased spending on early years education"},{"label":"B","text":"increased spending on infrastructure"},{"label":"C","text":"reduced import barriers"},{"label":"D","text":"subsidies to exporters"}],"correct":""},{"id":15,"text":"The number of people employed in a country and the level of unemployment both decrease. What could explain this?","options":[{"label":"A","text":"net inward immigration"},{"label":"B","text":"an increase in the level of unemployment benefits"},{"label":"C","text":"an increase in the age at which state pensions are payable"},{"label":"D","text":"an increase in the number of university students"}],"correct":""},{"id":16,"text":"A country has a floating exchange rate. Its current account on the balance of payments moves from a surplus to a deficit. Which rate is likely to increase in the short run as a consequence of this worsening of its current account?","options":[{"label":"A","text":"economic growth rate"},{"label":"B","text":"exchange rate"},{"label":"C","text":"interest rate"},{"label":"D","text":"unemployment rate"}],"correct":""},{"id":17,"text":"Which policy is most likely to reduce a balance of payments deficit without causing inflation?","options":[{"label":"A","text":"decreased import quotas"},{"label":"B","text":"depreciation of currency"},{"label":"C","text":"higher interest rates"},{"label":"D","text":"decreased import tariffs"}],"correct":""},{"id":18,"text":"What is not an example of protectionism?","options":[{"label":"A","text":"the European Union (EU) requiring goods imported into member states to meet safety standards"},{"label":"B","text":"the Pakistan government increasing the rate of goods and services tax (GST) on some exported goods from 2\\% to 5\\%"},{"label":"C","text":"the Nigeria government banning the import of packaged sugar"},{"label":"D","text":"the US imposing a 35\\% tariff on tyres imported from China"}],"correct":""},{"id":19,"text":"Turkey imported \\$220 million worth of goods and services. Turkey exported \\$12 million worth of goods and services during the same period. Its net income was -\\$15 million. What is Turkey's current account balance?","options":[{"label":"A","text":"-\\$223 million"},{"label":"B","text":"-\\$217 million"},{"label":"C","text":"+\\$208 million"},{"label":"D","text":"+\\$247 million"}],"correct":""},{"id":20,"text":"An increase in which factor will cause a decrease in investment spending?","options":[{"label":"A","text":"business confidence"},{"label":"B","text":"company profits"},{"label":"C","text":"interest rates"},{"label":"D","text":"national income"}],"correct":""},{"id":21,"text":"The diagram shows the relationship between tax revenue and the tax rate. What is the curve on the diagram called?","options":[{"label":"A","text":"income elasticity curve"},{"label":"B","text":"J curve"},{"label":"C","text":"Lorenz curve"},{"label":"D","text":"Laffer curve"}],"correct":"","image":"/images/econ-mcq/96_601_583_598_432_0.jpg"},{"id":22,"text":"The table shows the rate of inflation (consumer prices index) and the monthly percentage rate of unemployment for the USA over a six month period in 2017. } What can be concluded from this table?","options":[{"label":"A","text":"Falling inflation leads to lower unemployment."},{"label":"B","text":"Increasing inflation leads to rising unemployment."},{"label":"C","text":"The rate of inflation correlates exactly with the rate of unemployment."},{"label":"D","text":"The rate of inflation has a marginal effect on the rate of unemployment."}],"correct":""},{"id":23,"text":"Which policy does a central bank undertake to pursue quantitative easing?","options":[{"label":"A","text":"purchase long-term government debt from the public"},{"label":"B","text":"purchase short-term government debt from the public"},{"label":"C","text":"sell long-term government debt to the public"},{"label":"D","text":"sell short-term government debt to the public"}],"correct":""},{"id":24,"text":"Which statement would both Keynesian and Monetarist schools of thought accept?","options":[{"label":"A","text":"High inflation and high unemployment are undesirable in a properly-functioning economy."},{"label":"B","text":"Increased government spending on investment projects will always crowd out private investment."},{"label":"C","text":"The best way for an economy to get out of a recession is for the government to increase its expenditure."},{"label":"D","text":"The most effective way to reduce inflation is for the government to exercise tight control over the money supply."}],"correct":""},{"id":25,"text":"In country X the marginal rate of income tax imposed on the highest earners was \\({83}\\%\\) which increased to 98\\% if income was received from interest or dividends. The highest marginal rate was then reduced to 40\\%. Despite this reduction, the tax revenue raised from the highest earners increased substantially. Which theoretical concept illustrates this relationship between tax rates and tax revenue?","options":[{"label":"A","text":"the J curve"},{"label":"B","text":"the Laffer curve"},{"label":"C","text":"the Marshall-Lerner condition"},{"label":"D","text":"the Phillips curve"}],"correct":""},{"id":26,"text":"A government is increasing the role of market forces in its economy. However, it imposed temporary maximum price controls. Why might a government, committed to reducing central planning, introduce price controls?","options":[{"label":"A","text":"to increase allocative efficiency"},{"label":"B","text":"to increase the incentive for producers to raise supply"},{"label":"C","text":"to reduce consumer demand"},{"label":"D","text":"to reduce expectations of inflation"}],"correct":""}];

const paper_18: MCQQuestion[] = [{"id":1,"text":"Which type of good does not consume scarce resources?","options":[{"label":"A","text":"economic good"},{"label":"B","text":"free good"},{"label":"C","text":"merit good"},{"label":"D","text":"public good"}],"correct":""},{"id":2,"text":"The factors of production earn different rewards. What identifies the correct economic term for these rewards?","options":[{"label":"A","text":"capital - surpluses"},{"label":"B","text":"enterprise - dividends"},{"label":"C","text":"labour - interest"},{"label":"D","text":") land - rents"}],"correct":""},{"id":3,"text":"What is most likely to be an advantage of the division of labour?","options":[{"label":"A","text":"an increase in labour force creativity"},{"label":"B","text":"an increase in labour productivity"},{"label":"C","text":"an increase in workforce flexibility"},{"label":"D","text":"an increase in worker satisfaction"}],"correct":""},{"id":4,"text":"Shoe manufacturers often use leather to make their most expensive shoes. Due to a world shortage of leather, the price of leather has risen. What will be the effect of this price change?","options":[{"label":"A","text":"The demand curve for leather shoes will shift to the left."},{"label":"B","text":"The demand curve for a substitute for leather shoes will shift to the right."},{"label":"C","text":"The supply curve for leather shoes will shift to the right."},{"label":"D","text":"The supply curve for a substitute for leather to make expensive shoes will shift to the right."}],"correct":""},{"id":5,"text":"Which policy is most likely to solve the free rider problem caused by public goods?","options":[{"label":"A","text":"an advertising campaign"},{"label":"B","text":"a direct provision by the government"},{"label":"C","text":"a minimum price"},{"label":"D","text":"a tax on a substitute good"}],"correct":""},{"id":6,"text":"Very low interest rates in an economy encourage economic growth and cause a large increase in house prices. Which group of people is most likely to experience a fall in income and an increase in wealth as a result of these changes?","options":[{"label":"A","text":"retired people living in rented houses"},{"label":"B","text":"retired people who own their houses"},{"label":"C","text":"young people buying their own houses"},{"label":"D","text":"young people living with their parents"}],"correct":""},{"id":7,"text":"A country experienced an annual deflation rate of 2\\% for four successive years. Which statement is correct for the four-year period?","options":[{"label":"A","text":"The price level fell by 8\\%."},{"label":"B","text":"The price level fell by less than 8\\%."},{"label":"C","text":"The real value of money fell by 8\\%."},{"label":"D","text":"The real value of money fell by less than 8\\%."}],"correct":""},{"id":8,"text":"In the circular flow of income model of an economy, Y, C, I, G, X, S, T and M represent total income, consumption, investment, government expenditure, exports, saving, taxation and imports respectively. Which statement is correct?","options":[{"label":"A","text":"At equilibrium, the levels of Y and C are always the same."},{"label":"B","text":"Governments always adjust G so that the economy is in equilibrium."},{"label":"C","text":"If I is not equal to S, it is still possible for the national income to be in equilibrium."},{"label":"D","text":"If the national income is in equilibrium, X must be equal to M."}],"correct":""},{"id":9,"text":"What leads to a rise in frictional unemployment?","options":[{"label":"A","text":"an economy moving into a period of recession"},{"label":"B","text":"replacement of workers with computers in the service sector"},{"label":"C","text":"a change from an agriculturally based economy to an industrial economy"},{"label":"D","text":"a rise in the number of workers leaving one job to look for another job"}],"correct":""},{"id":10,"text":"If interest rates are reduced, what is most likely to decrease?","options":[{"label":"A","text":"borrowing by firms"},{"label":"B","text":"consumer spending"},{"label":"C","text":"import prices"},{"label":"D","text":"export prices"}],"correct":""},{"id":11,"text":"Supply-side policy often has fiscal consequences. Which statement is not correct?","options":[{"label":"A","text":"Increased government spending supporting technical progress has beneficial long-term supply-side effects but may have short-term inflationary consequences."},{"label":"B","text":"Increased government expenditure on training increases a country's long-run aggregate supply (LRAS) and also has an expansionary effect on aggregate demand (AD)."},{"label":"C","text":"Reduced government infrastructure spending reduces an economy's LRAS and has a short-term expansionary effect on AD."},{"label":"D","text":"Reduced rates of tax on higher incomes increases an economy's LRAS and has an expansionary effect on AD."}],"correct":""},{"id":12,"text":"Changes in fiscal policy can affect the distribution of income and wealth. Which combination of fiscal policy would most likely be regressive?","options":[{"label":"A","text":"a fall in the lowest level of income when income tax has to be paid and a fall in the rate of inheritance tax"},{"label":"B","text":"a fall in the charge made for visits to a doctor and a rise in the level of unemployment benefit"},{"label":"C","text":"a rise in the rate of income tax charged at higher levels of income and a rise in the standard rate of corporation tax"},{"label":"D","text":"a rise in the standard rate of income tax and a fall in the standard rate of goods and services tax"}],"correct":""},{"id":13,"text":"What does it mean when a government has a budget surplus?","options":[{"label":"A","text":"Government revenue exceeds expenditure."},{"label":"B","text":"Imports exceed exports."},{"label":"C","text":"The government has an expansionary fiscal policy."},{"label":"D","text":"The national debt is increasing."}],"correct":""},{"id":14,"text":"What is not a valid explanation of why a government might allow a deficit on the balance of payments current account to continue?","options":[{"label":"A","text":"The balance of payments account must always balance."},{"label":"B","text":"Foreign direct investment might help to finance the deficit."},{"label":"C","text":"The country may have a larger surplus on the other parts of its balance of payments account."},{"label":"D","text":"The standard of living is increased if the level of cheap food imports is significant."}],"correct":""},{"id":15,"text":"A country currently producing at point \\(X\\) on its production possibility curve decides to specialise in the manufacture of cars and import trucks. It finds it can import one truck in exchange for four cars. What is the result in the domestic market if it exports all the extra cars?","options":[{"label":"A","text":"250 extra trucks"},{"label":"B","text":"1000 extra trucks"},{"label":"C","text":"1250 extra trucks"},{"label":"D","text":"2000 extra trucks"}],"correct":"","image":"/images/econ-as-mcq/190_502_686_790_326_0.jpg"},{"id":16,"text":"What is most likely to cause a current account deficit?","options":[{"label":"A","text":"a recession in the domestic economy"},{"label":"B","text":"a relatively high rate of inflation"},{"label":"C","text":"an undervalued exchange rate"},{"label":"D","text":"high labour productivity"}],"correct":""},{"id":17,"text":"When is there an improvement in a country's terms of trade?","options":[{"label":"A","text":"when the price of exports falls more than the price of imports"},{"label":"B","text":"when there is no change in the price of exports but a fall in the price of imports"},{"label":"C","text":"when the value of exports increases relative to the total value of imports"},{"label":"D","text":"when the volume of exports increases relative to the total volume of imports"}],"correct":""},{"id":18,"text":"What is likely to happen if there is a rise in the international value of a country's currency?","options":[{"label":"A","text":"a fall in the foreign currency price of its exports"},{"label":"B","text":"a fall in the volume of its exports"},{"label":"C","text":"a rise in the domestic currency price of its imports"},{"label":"D","text":"a rise in the domestic price level"}],"correct":""},{"id":19,"text":"Which supply-side policy is most likely to decrease a government's budget deficit?","options":[{"label":"A","text":"cutting tax rates on company profits"},{"label":"B","text":"cutting unemployment benefits"},{"label":"C","text":"raising spending on education and training"},{"label":"D","text":"raising tax-free income tax allowances"}],"correct":""},{"id":20,"text":"The table shows the trade in goods and services for an economy between 2019 and 2021. What would have most likely caused the change from 2019 to 2021?","options":[{"label":"A","text":"increasing domestic unemployment"},{"label":"B","text":"increasing domestic rate of income tax"},{"label":"C","text":"increasing domestic inflation"},{"label":"D","text":"increasing import tariffs"}],"correct":"","table":"<table><tr><td>year</td><td>trade in goods and services ($ millions)</td></tr><tr><td>2019</td><td>-1000</td></tr><tr><td>2020</td><td>-3000</td></tr><tr><td>2021</td><td>-4000</td></tr></table>"},{"id":21,"text":"A government subsidises training to improve the skills of workers in the industrial sector of an economy. What is the most likely effect on the current account of the balance of payments?","options":[{"label":"A","text":"exports fall"},{"label":"B","text":"exports rise"},{"label":"C","text":"imports fall"},{"label":"D","text":"imports rise"}],"correct":""},{"id":22,"text":"Using all their resources efficiently, country X can produce 6 million tonnes of wheat or 2 million tonnes of steel whilst country Y can produce 4 million tonnes of wheat or 1 million tonnes of steel. Based on this information, what does the theory of comparative advantage suggest?","options":[{"label":"A","text":"Country X should produce only steel."},{"label":"B","text":"Country X will not gain from international trade."},{"label":"C","text":"Country Y has no comparative advantage."},{"label":"D","text":"Country Y will not gain from international trade."}],"correct":""},{"id":23,"text":"Countries X and Y are trade partners. An increase in which economic indicator in country Y is most likely to cause a fall in the exchange rate of country X?","options":[{"label":"A","text":"economic growth"},{"label":"B","text":"inflation rate"},{"label":"C","text":"money supply"},{"label":"D","text":"trade barriers"}],"correct":""},{"id":24,"text":"Which transaction is not recorded in the current account?","options":[{"label":"A","text":"aid received from the government of another country"},{"label":"B","text":"exports of raw materials"},{"label":"C","text":"investments by a foreign company"},{"label":"D","text":"payments of dividends to an overseas investor"}],"correct":""},{"id":25,"text":"A government decides to place a tariff on imports of raw materials. Which statement about the impact of the tariff is correct?","options":[{"label":"A","text":"It will increase costs of production for domestic firms."},{"label":"B","text":"It will increase consumer surplus for domestic consumers."},{"label":"C","text":"It will reduce government revenue."},{"label":"D","text":"There will be a fall in the price of imports and a rise in the demand."}],"correct":""},{"id":26,"text":"In which situation will a country's terms of trade improve?","options":[{"label":"A","text":"Its imports rise in value less than its exports."},{"label":"B","text":"Its imports rise in volume less than its exports."},{"label":"C","text":"The price of its imports rises by less than the prices of its exports."},{"label":"D","text":"The value of its external payments rises by less than the value of its external receipts."}],"correct":""},{"id":27,"text":"An increase in which factor will cause a decrease in investment spending?","options":[{"label":"A","text":"business confidence"},{"label":"B","text":"company profits"},{"label":"C","text":"interest rates"},{"label":"D","text":"national income"}],"correct":""},{"id":28,"text":"The diagram shows the relationship between tax revenue and the tax rate. What is the curve on the diagram called?","options":[{"label":"A","text":"income elasticity curve"},{"label":"B","text":"J curve"},{"label":"C","text":"Lorenz curve"},{"label":"D","text":"Laffer curve"}],"correct":"","image":"/images/econ-mcq/98_601_583_598_432_0.jpg"},{"id":29,"text":"The table shows the rate of inflation (consumer prices index) and the monthly percentage rate of unemployment for the USA over a six month period in 2017. } What can be concluded from this table?","options":[{"label":"A","text":"Falling inflation leads to lower unemployment."},{"label":"B","text":"Increasing inflation leads to rising unemployment."},{"label":"C","text":"The rate of inflation correlates exactly with the rate of unemployment."},{"label":"D","text":"The rate of inflation has a marginal effect on the rate of unemployment."}],"correct":""}];

const paper_19: MCQQuestion[] = [{"id":1,"text":"Which statement about a market economy is not correct?","options":[{"label":"A","text":"Competition is promoted among firms which can increase productive efficiency."},{"label":"B","text":"Immobility of the factors of production can lead to allocative inefficiency."},{"label":"C","text":"Price always reflects all the costs and all the benefits associated with production."},{"label":"D","text":"The entrepreneur is encouraged to innovate and take risks, motivated by profit."}],"correct":""},{"id":2,"text":"The price of a good rises by 5\\% and the quantity of it demanded rises by 3\\%. At the same time, the incomes of consumers of the good rise by 4\\%. The law of demand appears not to be working in this case. What is the most likely explanation?","options":[{"label":"A","text":"Other things did not remain equal."},{"label":"B","text":"The demand for the good was price inelastic."},{"label":"C","text":"The real price of the good fell."},{"label":"D","text":"The time period was the very short run."}],"correct":""},{"id":3,"text":"When is division of labour likely to be most effective?","options":[{"label":"A","text":"in a large market with stable demand"},{"label":"B","text":"in a market where consumers prefer a handmade product over a product made using machines"},{"label":"C","text":"in a market where consumers require a variety of goods"},{"label":"D","text":"in a small market where consumers require a custom-made product"}],"correct":""},{"id":4,"text":"What will influence the value of the price elasticity of supply of a good?","options":[{"label":"A","text":"the level of producer surplus"},{"label":"B","text":"the time period under consideration"},{"label":"C","text":"the total income spent on the good"},{"label":"D","text":"whether the good is a necessity"}],"correct":""},{"id":5,"text":"The diagram represents the market for a good. Which statement is correct?","options":[{"label":"A","text":"OX represents the price above which no producer wishes to stay in the market."},{"label":"B","text":"OZ represents the minimum price consumers are prepared to pay."},{"label":"C","text":"PYZ represents the total consumer surplus."},{"label":"D","text":"XYZ represents the total producer surplus."}],"correct":"","image":"/images/econ-as-mcq/194_542_250_710_459_0.jpg"},{"id":6,"text":"What is likely to have a greater effect on an individual demand curve than on a market demand curve?","options":[{"label":"A","text":"changing weather patterns"},{"label":"B","text":"government policy to promote consumption"},{"label":"C","text":"growth in population"},{"label":"D","text":"more expensive substitutes"}],"correct":""},{"id":7,"text":"The quantity demanded of a product is given by \\({Q}_{D} = {400} - {10P}\\) , when \\(P\\) is the price in dollars. Supply of the product is fixed at 100 units. If the price is \\$20, what will be the position in the market?","options":[{"label":"A","text":"It will be in disequilibrium with excess demand of 100 units."},{"label":"B","text":"It will be in disequilibrium with excess supply of 100 units."},{"label":"C","text":"It will be in equilibrium with 100 units traded."},{"label":"D","text":"It will be in equilibrium with 200 units traded."}],"correct":""},{"id":8,"text":"A decrease in the quantity demanded of a product results in a proportionate decrease in sales revenues. What is true about its price elasticity of demand?","options":[{"label":"A","text":"It is between zero and one."},{"label":"B","text":"It is infinite."},{"label":"C","text":"It is unitary."},{"label":"D","text":"It is zero."}],"correct":""},{"id":9,"text":"A government may use a range of methods to intervene in a market to affect both demand and supply. What is a method which will shift the demand curve for a good?","options":[{"label":"A","text":"an indirect tax"},{"label":"B","text":"a subsidy"},{"label":"C","text":"direct provision"},{"label":"D","text":"provision of information"}],"correct":""},{"id":10,"text":"To help achieve price stability, the government in country F operates a buffer stock scheme, with a minimum price of \\({P}_{1}\\) and a maximum price of \\({P}_{2}\\) . The current demand and supply in the market is shown. What should the government do to ensure the scheme is effective?","options":[{"label":"A","text":"buy an amount equal to GH"},{"label":"B","text":"buy an amount equal to KJ"},{"label":"C","text":"buy an amount equal to LJ"},{"label":"D","text":"do nothing as the equilibrium price is below \\({\\mathrm{P}}_{1}\\)"}],"correct":"","image":"/images/econ-as-mcq/196_540_325_722_551_0.jpg"},{"id":11,"text":"The table shows the Gini coefficient for income in three countries. } What can be concluded from this data?","options":[{"label":"A","text":"All three countries have seen an overall improvement in income equality."},{"label":"B","text":"Costa Rica has the highest level of consumer income of all three countries."},{"label":"C","text":"New Zealand's income inequality worsened between 2018 and 2020."},{"label":"D","text":"Sweden's economy has the highest income equality of all three countries."}],"correct":"","table":"<table><tr><td>2018</td><td>2019</td><td>2020</td></tr><tr><td>Costa Rica</td><td>0.479</td><td>0.478</td><td>0.497</td></tr><tr><td>New Zealand</td><td>0.330</td><td>0.326</td><td>0.320</td></tr><tr><td>Sweden</td><td>0.275</td><td>0.280</td><td>0.278</td></tr></table>"},{"id":12,"text":"Governments may have price stability as a macroeconomic objective. What is meant by price stability?","options":[{"label":"A","text":"All equilibrium prices are maintained in the long run."},{"label":"B","text":"Demand-pull inflation cancels out any cost-push inflation."},{"label":"C","text":"Only disinflation is present in the economy in the long run."},{"label":"D","text":"Prolonged periods of inflation and deflation are avoided."}],"correct":""},{"id":13,"text":"The money income of a country rises by 10\\% whereas its population falls by 10\\% during a year. What is likely to happen to the national income per head?","options":[{"label":"A","text":"It will remain unchanged."},{"label":"B","text":"It will rise by exactly 20\\%."},{"label":"C","text":"It will rise by less than 20\\%."},{"label":"D","text":"It will rise by more than 20\\%."}],"correct":""},{"id":14,"text":"High economic growth is often accompanied by a worsening of the current account of the balance of payments. Which reason for this trend is not valid?","options":[{"label":"A","text":"Economic growth raises domestic consumption, leaving very little to sell to overseas consumers."},{"label":"B","text":"Economic growth raises domestic output, leading to lower prices and more price-competitive goods both at home and abroad."},{"label":"C","text":"Economic growth raises incomes and leads to rising demand for foreign goods."},{"label":"D","text":"Economic growth results in rising requirements of inputs from other countries."}],"correct":""},{"id":15,"text":"A government cuts income tax. Why might this be seen as an example of a supply-side policy?","options":[{"label":"A","text":"Real incomes are increased."},{"label":"B","text":"The costs of businesses are reduced."},{"label":"C","text":"The opportunity cost of unemployment has increased."},{"label":"D","text":"The standard of living has improved."}],"correct":""},{"id":16,"text":"A country's central bank decides to reduce the level of credit regulation. What is this an example of?","options":[{"label":"A","text":"contractionary fiscal policy"},{"label":"B","text":"contractionary monetary policy"},{"label":"C","text":"expansionary fiscal policy"},{"label":"D","text":"expansionary monetary policy"}],"correct":""},{"id":17,"text":"A government decides to use supply-side policy to increase long-run aggregate supply (LRAS). What is the most likely reason why this policy tool will not lead to a fall in the price level?","options":[{"label":"A","text":"Aggregate demand will also increase."},{"label":"B","text":"Labour productivity levels will increase."},{"label":"C","text":"Workers will save any extra wages they earn."},{"label":"D","text":"Workers will spend any extra wages on imports."}],"correct":""},{"id":18,"text":"What defines a progressive tax?","options":[{"label":"A","text":"All taxpayers pay the same proportion of income in taxes."},{"label":"B","text":"Low-income earners pay a lower proportion of income in taxes than high-income earners."},{"label":"C","text":"Low-income earners pay less in taxes than high-income earners."},{"label":"D","text":"Low-income earners pay more in taxes than high-income earners."}],"correct":""},{"id":19,"text":"Country X trades with country Y. What are the terms of trade for country X?","options":[{"label":"A","text":"average price of country X's exports divided by the average price of country Y's exports"},{"label":"B","text":"the ratio of an index of country X's export prices to an index of its import prices"},{"label":"C","text":"value of country X's exports divided by the value of country Y's exports"},{"label":"D","text":"value of country X's imports divided by the value of country Y's imports"}],"correct":""},{"id":20,"text":"When is a country's exchange rate most likely to fall?","options":[{"label":"A","text":"When its current account surplus exceeds that of its trading partners."},{"label":"B","text":"When its inflation rate exceeds that of its trading partners."},{"label":"C","text":"When its interest rate exceeds that of its trading partners."},{"label":"D","text":"When its unemployment rate exceeds that of its trading partners."}],"correct":""},{"id":21,"text":"The diagram shows the production possibilities for barley and wheat in countries Q and R. What can be concluded?","options":[{"label":"A","text":"Country Q has a comparative advantage in the production of barley."},{"label":"B","text":"Country Q has an absolute advantage in producing both goods."},{"label":"C","text":"Country R has an absolute advantage in the production of barley."},{"label":"D","text":"There is no comparative advantage."}],"correct":"","image":"/images/econ-as-mcq/201_586_1116_627_426_0.jpg"},{"id":22,"text":"The diagram shows the impact of a government introducing an export subsidy for its domestic producers of oil. What will be the effect of this export subsidy on the operation of the domestic market?","options":[{"label":"A","text":"domestic output of oil will increase by 15 million units"},{"label":"B","text":"imports of oil will decrease by 25 million units"},{"label":"C","text":"the domestic price of oil will decrease by \\$28"},{"label":"D","text":"the domestic price of oil will increase by \\$8"}],"correct":"","image":"/images/econ-as-mcq/202_416_287_965_524_0.jpg"},{"id":23,"text":"The diagram shows a Lorenz curve with two areas, X and Y, identified. How is the corresponding Gini coefficient calculated?","options":[{"label":"A","text":"X divided by (X plus Y)"},{"label":"B","text":"(X plus Y) divided by X"},{"label":"C","text":"(X plus Y) divided by Y"},{"label":"D","text":"Y divided by (X plus Y)"}],"correct":"","image":"/images/econ-mcq/100_562_1140_670_524_0.jpg"},{"id":24,"text":"What is most likely to be found in an economy with a positive output gap?","options":[{"label":"A","text":"a higher potential than actual GDP"},{"label":"B","text":"high unemployment"},{"label":"C","text":"inflation"},{"label":"D","text":"low labour costs"}],"correct":""},{"id":25,"text":"Which statement about the Keynesian liquidity preference demand for money model is correct?","options":[{"label":"A","text":"Both the transactions and precautionary motives for holding liquidity are interest rate elastic."},{"label":"B","text":"The demand for liquidity is completely interest rate inelastic at low rates of interest."},{"label":"C","text":"The demand to hold liquidity by households is stable."},{"label":"D","text":"The rate of interest on long-term government securities is inversely related to their price."}],"correct":""},{"id":26,"text":"An increase in which factor will cause a decrease in investment spending?","options":[{"label":"A","text":"business confidence"},{"label":"B","text":"company profits"},{"label":"C","text":"interest rates"},{"label":"D","text":"national income"}],"correct":""},{"id":27,"text":"The diagram shows the relationship between tax revenue and the tax rate. What is the curve on the diagram called?","options":[{"label":"A","text":"income elasticity curve"},{"label":"B","text":"J curve"},{"label":"C","text":"Lorenz curve"},{"label":"D","text":"Laffer curve"}],"correct":"","image":"/images/econ-mcq/96_601_583_598_432_0.jpg"},{"id":28,"text":"The table shows the rate of inflation (consumer prices index) and the monthly percentage rate of unemployment for the USA over a six month period in 2017. } What can be concluded from this table?","options":[{"label":"A","text":"Falling inflation leads to lower unemployment."},{"label":"B","text":"Increasing inflation leads to rising unemployment."},{"label":"C","text":"The rate of inflation correlates exactly with the rate of unemployment."},{"label":"D","text":"The rate of inflation has a marginal effect on the rate of unemployment."}],"correct":""}];

const paper_20: MCQQuestion[] = [{"id":1,"text":"Which statement about a free vaccination programme is normative?","options":[{"label":"A","text":"It will help raise life expectancy."},{"label":"B","text":"It is likely to improve the welfare of society."},{"label":"C","text":"It will result in lower spending on other medical services."},{"label":"D","text":"Tax revenues generated through improved economic activity will exceed the spending on vaccination."}],"correct":""},{"id":2,"text":"The diagram shows the production possibility curves of two countries, X and Y. What can be concluded from the diagram?","options":[{"label":"A","text":"Both countries have decreasing opportunity cost in the production of consumer goods."},{"label":"B","text":"Both countries should produce 40 units of capital goods and 20 units of consumer goods."},{"label":"C","text":"Country Y has constant opportunity cost in the production of consumer goods."},{"label":"D","text":"Country Y is producing more consumer goods than country X."}],"correct":"","image":"/images/econ-as-mcq/203_712_649_591_377_0.jpg"},{"id":3,"text":"Which goods are least likely to be allocated by market forces in a mixed economy?","options":[{"label":"A","text":"hospitals"},{"label":"B","text":"Brailways"},{"label":"C","text":"street lighting"},{"label":"D","text":"television programmes"}],"correct":""},{"id":4,"text":"How can a public good become a private good?","options":[{"label":"A","text":"Consumers are dissatisfied with the performance of state-run services."},{"label":"B","text":"New technological developments make the good excludable."},{"label":"C","text":"The government privatises the industry producing the good."},{"label":"D","text":"The price of the good increases so it becomes more profitable."}],"correct":""},{"id":5,"text":"What is not a function of the price mechanism?","options":[{"label":"A","text":"to act as a signal to firms when allocating resources"},{"label":"B","text":"to maximise consumer surplus"},{"label":"C","text":"to provide an incentive to firms to produce goods"},{"label":"D","text":"to ration scarce resources"}],"correct":""},{"id":6,"text":"What would best explain why the price elasticity of supply (PES) is likely to be lower for fresh vegetables grown within a country compared to the PES of goods manufactured in that country?","options":[{"label":"A","text":"Alternative supplies can be flown in from foreign producers."},{"label":"B","text":"A positive price change encourages a positive output change along the supply curve."},{"label":"C","text":"Fresh vegetables has a horizontal supply curve."},{"label":"D","text":"There is a seasonal time lag involved in planting and harvesting more fresh vegetables."}],"correct":""},{"id":7,"text":"The diagram shows the demand for and supply of a product. What could cause supply to shift from \\({\\mathrm{S}}_{1}\\) to \\({\\mathrm{S}}_{2}\\) ?","options":[{"label":"A","text":"a fall in the price of the product"},{"label":"B","text":"a fall in labour costs"},{"label":"C","text":"a rise in the price of the product"},{"label":"D","text":"a rise in labour costs"}],"correct":"","image":"/images/econ-as-mcq/206_708_253_593_559_0.jpg"},{"id":8,"text":"What is an example of wealth?","options":[{"label":"A","text":"interest received"},{"label":"B","text":"profits"},{"label":"C","text":"property"},{"label":"D","text":"incomes"}],"correct":""},{"id":9,"text":"Too much sugar causes an increase in a consumer's weight. A government has introduced a 'sugar tax' on the consumption of soft drinks that have a high sugar content. How might this policy help to reduce the number of overweight people?","options":[{"label":"A","text":"Consumers switch to cheaper brands of soft drink with a high sugar content."},{"label":"B","text":"Consumers switch to other high-sugar substitute goods, such as alcohol or sweets."},{"label":"C","text":"The price elasticity of demand for soft drinks is inelastic."},{"label":"D","text":"The tax revenue is spent on education about the dangers of soft drink consumption."}],"correct":""},{"id":10,"text":"The diagram shows the demand for and supply of eye tests provided by opticians. Which policy would enable the government to increase the number of eye tests from \\({\\mathrm{{OQ}}}_{1}\\) to \\({\\mathrm{{OQ}}}_{2}\\) ?","options":[{"label":"A","text":"a maximum price of \\({\\mathrm{{OP}}}_{3}\\) per test"},{"label":"B","text":"a minimum price of \\({\\mathrm{{OP}}}_{2}\\) per test"},{"label":"C","text":"a subsidy paid to opticians of \\({\\mathrm{P}}_{3} - {\\mathrm{P}}_{2}\\) per test"},{"label":"D","text":"a subsidy paid to opticians of \\({\\mathrm{P}}_{3} - {\\mathrm{P}}_{1}\\) per test"}],"correct":"","image":"/images/econ-as-mcq/208_662_252_686_484_0.jpg"},{"id":11,"text":"What is an example of a transfer payment?","options":[{"label":"A","text":"a household moving savings from one bank account to another"},{"label":"B","text":"a monthly repayment on a loan used to buy a new cooker"},{"label":"C","text":"the amount paid to transport goods from one city to another"},{"label":"D","text":"grants paid to students by the government"}],"correct":""},{"id":12,"text":"Which statement correctly describes an increase in real GDP?","options":[{"label":"A","text":"Nominal GDP rising faster than nominal income."},{"label":"B","text":"Nominal GDP rising faster than the rate of inflation."},{"label":"C","text":"The rate of inflation rising faster than aggregate demand."},{"label":"D","text":"The rate of inflation rising faster than nominal income."}],"correct":""},{"id":13,"text":"An economy's manufacturing share of real GDP fell from 30\\% in 1990 to 12\\% in 2023. Which type of unemployment would have resulted from this?","options":[{"label":"A","text":"cyclical"},{"label":"B","text":"frictional"},{"label":"C","text":"structural"},{"label":"D","text":"voluntary"}],"correct":""},{"id":14,"text":"Which statement is not correct?","options":[{"label":"A","text":"The long-run aggregate supply curve can be downward sloping."},{"label":"B","text":"The long-run aggregate supply curve can be horizontal."},{"label":"C","text":"The long-run aggregate supply curve can be upward sloping."},{"label":"D","text":"The long-run aggregate supply curve can be vertical."}],"correct":""},{"id":15,"text":"What is not an example of monetary policy?","options":[{"label":"A","text":"a rise in import tariffs on manufactured goods"},{"label":"B","text":"a rise in interest rates by the central bank"},{"label":"C","text":"a rise in credit regulations"},{"label":"D","text":"a rise in the money supply"}],"correct":""},{"id":16,"text":"A government decides to raise most of its revenues from indirect taxes. What would increase the effectiveness of this policy?","options":[{"label":"A","text":"an increasing trend towards bartering of goods"},{"label":"B","text":"increasing interest rates on household savings"},{"label":"C","text":"increasing occurrence of informal markets in the economy"},{"label":"D","text":"placing taxes on goods and services which have a price-inelastic demand"}],"correct":""},{"id":17,"text":"What is not an example of an expansionary supply-side policy?","options":[{"label":"A","text":"a reduction in government spending on training"},{"label":"B","text":"an increase in support for technological improvement"},{"label":"C","text":"a reduction in payments to the unemployed"},{"label":"D","text":"an increase in privatisation of industry"}],"correct":""},{"id":18,"text":"Why does the value of a country's terms of trade have no monetary units?","options":[{"label":"A","text":"It cannot be calculated accurately enough."},{"label":"B","text":"It includes more than one currency."},{"label":"C","text":"It is a ratio of two index numbers."},{"label":"D","text":"It measures change over time."}],"correct":""},{"id":19,"text":"Which statement correctly describes a tariff?","options":[{"label":"A","text":"It is a complete ban on imports."},{"label":"B","text":"It is a minimum price for domestic producers."},{"label":"C","text":"It is a payment to exporters."},{"label":"D","text":"It is a tax imposed on imports."}],"correct":""},{"id":20,"text":"A country has a persistent deficit on the current account of its balance of payments. What is most likely to improve the situation in the long run?","options":[{"label":"A","text":"a lowering of the level of import duties"},{"label":"B","text":"a reduction in the level of income tax"},{"label":"C","text":"the introduction of expansionary monetary policy"},{"label":"D","text":"the use of grants to encourage new investment by firms"}],"correct":""},{"id":21,"text":"The table shows the change in the value of UK sterling over a three-month period. } What is likely to be the short-term impact of the change in the value of UK sterling on the UK economy?","options":[{"label":"A","text":"increased disinflation"},{"label":"B","text":"increase in cost-push inflation"},{"label":"C","text":"more purchasing power of money"},{"label":"D","text":"reduced demand-pull inflation"}],"correct":"","table":"<table><tr><td>Sept</td></tr><tr><td>£1 = $1.38</td><td>£1 = $1.32</td></tr></table>"},{"id":22,"text":"The table shows the change in the value of UK sterling over a three-month period. What is likely to be the short-term impact of the change in the value of UK sterling on the UK economy?","options":[{"label":"A","text":"increased disinflation"},{"label":"B","text":"increase in cost-push inflation"},{"label":"C","text":"more purchasing power of money"},{"label":"D","text":"reduced demand-pull inflation"}],"correct":"","table":"<table><tr><td>June</td><td>Sept</td></tr><tr><td>£1 = $1.38</td><td>£1 = $1.32</td></tr></table>"},{"id":23,"text":"What is most likely to be found in an economy with a positive output gap?","options":[{"label":"A","text":"a higher potential than actual GDP"},{"label":"B","text":"high unemployment"},{"label":"C","text":"inflation"},{"label":"D","text":"low labour costs"}],"correct":""},{"id":24,"text":"Which statement about the Keynesian liquidity preference demand for money model is correct?","options":[{"label":"A","text":"Both the transactions and precautionary motives for holding liquidity are interest rate elastic."},{"label":"B","text":"The demand for liquidity is completely interest rate inelastic at low rates of interest."},{"label":"C","text":"The demand to hold liquidity by households is stable."},{"label":"D","text":"The rate of interest on long-term government securities is inversely related to their price."}],"correct":""},{"id":25,"text":"An increase in which factor will cause a decrease in investment spending?","options":[{"label":"A","text":"business confidence"},{"label":"B","text":"company profits"},{"label":"C","text":"interest rates"},{"label":"D","text":"national income"}],"correct":""},{"id":26,"text":"The diagram shows the relationship between tax revenue and the tax rate. What is the curve on the diagram called?","options":[{"label":"A","text":"income elasticity curve"},{"label":"B","text":"J curve"},{"label":"C","text":"Lorenz curve"},{"label":"D","text":"Laffer curve"}],"correct":"","image":"/images/econ-mcq/98_601_583_598_432_0.jpg"},{"id":27,"text":"The table shows the rate of inflation (consumer prices index) and the monthly percentage rate of unemployment for the USA over a six month period in 2017. } What can be concluded from this table?","options":[{"label":"A","text":"Falling inflation leads to lower unemployment."},{"label":"B","text":"Increasing inflation leads to rising unemployment."},{"label":"C","text":"The rate of inflation correlates exactly with the rate of unemployment."},{"label":"D","text":"The rate of inflation has a marginal effect on the rate of unemployment."}],"correct":""}];

const paper_21: MCQQuestion[] = [{"id":1,"text":"What is the best definition of a positive economic statement?","options":[{"label":"A","text":"A statement that is based on fact and can be tested."},{"label":"B","text":"A statement that attempts to influence economic decisions."},{"label":"C","text":"A statement that is subjective and cannot be confirmed."},{"label":"D","text":"An encouraging economic update in the opinion of the central bank."}],"correct":""},{"id":2,"text":"The diagram is from a chapter on 'The Fundamental Economic Problem' in an Economics textbook. It should contain the terms opportunity cost, scarcity and choice in the order that identifies the fundamental economic problem. What is the correct order for the terms to appear in the diagram?","options":[{"label":"A","text":"choice \\(\\rightarrow\\) opportunity cost \\(\\rightarrow\\) scarcity"},{"label":"B","text":"choice \\(\\rightarrow\\) scarcity \\(\\rightarrow\\) opportunity cost"},{"label":"C","text":"scarcity \\(\\rightarrow\\) choice \\(\\rightarrow\\) opportunity cost"},{"label":"D","text":"scarcity \\(\\rightarrow\\) opportunity cost \\(\\rightarrow\\) choice"}],"correct":"","image":"/images/econ-as-mcq/213_472_688_1072_97_0.jpg"},{"id":3,"text":"What is a statement of the non-rivalrous nature of public goods?","options":[{"label":"A","text":"It is not possible to stop a non-payer from using the product."},{"label":"B","text":"One person consuming the product does not reduce the amount of it available to others."},{"label":"C","text":"People consume too little of the product because they are unaware of its true benefits."},{"label":"D","text":"There is an unlimited supply of the product."}],"correct":""},{"id":4,"text":"The diagram shows an outward shift of the production possibility curve from \\({\\mathrm{{PPC}}}_{1}\\) to \\({\\mathrm{{PPC}}}_{2}\\) . What could have caused this shift?","options":[{"label":"A","text":"a decrease in mineral resources"},{"label":"B","text":"a decrease in prices of consumer goods"},{"label":"C","text":"an increase in employment"},{"label":"D","text":"an increase in technology"}],"correct":"","image":"/images/econ-as-mcq/214_612_1222_575_470_0.jpg"},{"id":5,"text":"When can a product be said to have a negative income elasticity of demand?","options":[{"label":"A","text":"When it is a luxury good."},{"label":"B","text":"When it is a necessity good."},{"label":"C","text":"When it is a normal good."},{"label":"D","text":"When it is an inferior good."}],"correct":""},{"id":6,"text":"An increase in which variable will always lead to an increase in the consumer surplus?","options":[{"label":"A","text":"cost of production"},{"label":"B","text":"maximum price"},{"label":"C","text":"minimum price"},{"label":"D","text":"subsidy"}],"correct":""},{"id":7,"text":"Farmers want to extract wild honey from beehives. They find the beehives by following birds known as honeyguide birds who want the beeswax that is also found in the beehives. What does this suggest?","options":[{"label":"A","text":"Farmers and honeyguide birds are rival consumers."},{"label":"B","text":"Wild honey and beeswax are free goods."},{"label":"C","text":"Wild honey and beeswax are in joint supply."},{"label":"D","text":"Wild honey is the opportunity cost of beeswax."}],"correct":""},{"id":8,"text":"An indirect tax is imposed on good X. Which situation is most likely to result in producers bearing a higher burden of the tax?","options":[{"label":"A","text":"price elasticity of demand is elastic"},{"label":"B","text":"price elasticity of demand is inelastic"},{"label":"C","text":"price elasticity of supply is elastic"},{"label":"D","text":"price elasticity of supply is inelastic"}],"correct":""},{"id":9,"text":"What would not be included in the calculation of an individual's wealth?","options":[{"label":"A","text":"the house owned by the individual"},{"label":"B","text":"the savings in the individual's bank account"},{"label":"C","text":"the stocks and shares owned by the individual"},{"label":"D","text":"the wages earned by the individual"}],"correct":""},{"id":10,"text":"Why might governments provide free education for children aged 4 to 16 years old?","options":[{"label":"A","text":"Consumers are not fully aware of the benefits of education."},{"label":"B","text":"Education in a free market system would be over consumed."},{"label":"C","text":"Education is a public good and there would be many free riders."},{"label":"D","text":"The private costs of education exceed the private benefits in a free market."}],"correct":""},{"id":11,"text":"The diagram shows the demand and supply for rice. The market for rice is initially in equilibrium at a price of \\({P}_{1}\\) . The government introduces a maximum price of \\({P}_{\\max }\\) . At the same time the supply of rice increases. What is the impact of these changes on the market for rice?","options":[{"label":"A","text":"A new market equilibrium will be established."},{"label":"B","text":"An illegal market for rice will develop."},{"label":"C","text":"There will be a shortage of rice."},{"label":"D","text":"There will be a surplus of rice."}],"correct":"","image":"/images/econ-as-mcq/217_578_362_659_548_0.jpg"},{"id":12,"text":"Price stability can be said to occur if the measured value of the consumer prices index (CPI) is unchanged during the year. Which statement is correct?","options":[{"label":"A","text":"For price stability to occur, there must be no changes in prices of any products."},{"label":"B","text":"For price stability to occur, the number of products whose prices rise must exactly match the number whose prices fall."},{"label":"C","text":"If some prices rise and others fall, there cannot be price stability."},{"label":"D","text":"Different weightings of items used in the calculation of CPI mean that price stability can occur in many ways."}],"correct":""},{"id":13,"text":"Based on the circular flow of income, which condition is necessary for an open economy to be in equilibrium?","options":[{"label":"A","text":"Government investment is equal to private investment."},{"label":"B","text":"Planned injections are equal to planned withdrawals."},{"label":"C","text":"Spending by households is equal to taxes collected by government."},{"label":"D","text":"Value of export earnings is equal to expenditure on imports."}],"correct":""},{"id":14,"text":"The aggregate demand curve is typically downward sloping. What is one possible explanation for this?","options":[{"label":"A","text":"A fall in the price level will lead to a rise in demand for imports."},{"label":"B","text":"As the price level falls, improved productivity will reduce unit costs."},{"label":"C","text":"If the price level is high, any interest rate changes will encourage consumption."},{"label":"D","text":"The real value of assets increases as the price level falls."}],"correct":""},{"id":15,"text":"What is most likely to cause an unemployed worker to be classified as frictionally unemployed?","options":[{"label":"A","text":"lack of relevant skills for vacant jobs"},{"label":"B","text":"lack of up-to-date job vacancy information"},{"label":"C","text":"greater use of technology in the production process"},{"label":"D","text":"an increase in regional pay inequality"}],"correct":""},{"id":16,"text":"What is likely to be an expansionary monetary policy?","options":[{"label":"A","text":"a decrease in the availability of credit"},{"label":"B","text":"a decrease in the exchange rate"},{"label":"C","text":"an increase in government spending"},{"label":"D","text":"an increase in subsidies for training"}],"correct":""},{"id":17,"text":"An income tax has a tax-free allowance of \\$10000 and a single rate of 25\\%. What type of tax is this?","options":[{"label":"A","text":"indirect"},{"label":"B","text":"progressive"},{"label":"C","text":"proportional"},{"label":"D","text":"regressive"}],"correct":""},{"id":18,"text":"Which supply-side policy will encourage new entrepreneurs?","options":[{"label":"A","text":"an increase in government subsidy to small firms"},{"label":"B","text":"an increase in the national minimum wage"},{"label":"C","text":"an increase in the power of trade unions"},{"label":"D","text":"an increase in the tax on business profits"}],"correct":""},{"id":19,"text":"Which statement is not a valid reason why a country may impose protectionist measures?","options":[{"label":"A","text":"to allow a newly developed domestic industry to grow to a viable size"},{"label":"B","text":"to enable a country to retain control of an industry it regards as being of strategic importance"},{"label":"C","text":"to give consumers a wider choice of goods and services"},{"label":"D","text":"to give time for workers in a declining domestic industry to find alternative employment"}],"correct":""},{"id":20,"text":"What is most likely to lead to a persistent surplus in a country's current account of its balance of payments?","options":[{"label":"A","text":"a low domestic savings rate"},{"label":"B","text":"an undervalued exchange rate"},{"label":"C","text":"highly protectionist policies by other countries"},{"label":"D","text":"low investment income from abroad"}],"correct":""},{"id":21,"text":"Which formula is used to calculate the terms of trade?","options":[{"label":"A","text":"the average price of exports divided by the average price of imports"},{"label":"B","text":"the average price of imports divided by the average price of exports"},{"label":"C","text":"the value of exports divided by the value of imports"},{"label":"D","text":"the value of imports divided by the value of exports"}],"correct":""},{"id":22,"text":"A country is experiencing a deficit on the current account of its balance of payments. Which policy decision could reduce the deficit?","options":[{"label":"A","text":"decrease in income tax rates"},{"label":"B","text":"increase in exchange rates"},{"label":"C","text":"increase in government spending"},{"label":"D","text":") increase in import tariffs"}],"correct":""},{"id":23,"text":"The Euro (€) is the main currency of the European Union. The diagram shows the exchange rate between the Euro and the US dollar. quantity What is likely to have caused this change in the value of the Euro?","options":[{"label":"A","text":"a decrease in European Union inflation"},{"label":"B","text":"a decrease in US interest rates"},{"label":"C","text":"an increase in European Union imports"},{"label":"D","text":"an increase in European Union unemployment"}],"correct":"","image":"/images/econ-as-mcq/222_563_723_667_529_0.jpg"},{"id":24,"text":"During a certain period, a country with a constant population expands its output per head. It also experiences a significant increase in river and atmospheric pollution. In the absence of any other changes, which measure would show a decrease in living standards?","options":[{"label":"A","text":"Gross Domestic Product per head"},{"label":"B","text":"Gross National Product per head"},{"label":"C","text":"Human Development Index"},{"label":"D","text":"Measure of Economic Welfare"}],"correct":""},{"id":25,"text":"What would reduce the effectiveness of a supply-side stimulus to the economy?","options":[{"label":"A","text":"an imposition of maximum hours in a working week"},{"label":"B","text":"an increase in public sector spending"},{"label":"C","text":"the provision of new training schemes"},{"label":"D","text":"the relaxation of import controls on raw materials"}],"correct":""},{"id":26,"text":"To indicate the changing income distribution, the Kuznets curve plots gross domestic product per capita against an economic variable X. What is variable X?","options":[{"label":"A","text":"the exchange rate"},{"label":"B","text":"the level of income inequality"},{"label":"C","text":"the price level"},{"label":"D","text":"the rate of interest"}],"correct":""},{"id":27,"text":"The table shows some United Nations population statistics for 2010 and estimates for 2050. } Which relationship can be confirmed from the table?","options":[{"label":"A","text":"The least developed regions have the largest urban populations, actual or predicted, in both years."},{"label":"B","text":"The more developed regions have the lowest growth rate of urbanisation between 2010 and 2050."},{"label":"C","text":"The type of region with the greatest total population in 2010 is predicted to have the greatest rate of population growth by 2050."},{"label":"D","text":"The type of region with the greatest urban population in 2010 is predicted to have the highest level of urbanisation by 2050."}],"correct":""},{"id":28,"text":"The diagram shows a Lorenz curve with two areas, X and Y, identified. How is the corresponding Gini coefficient calculated?","options":[{"label":"A","text":"X divided by (X plus Y)"},{"label":"B","text":"(X plus Y) divided by X"},{"label":"C","text":"(X plus Y) divided by Y"},{"label":"D","text":"Y divided by (X plus Y)"}],"correct":"","image":"/images/econ-mcq/100_562_1140_670_524_0.jpg"}];

const paper_22: MCQQuestion[] = [{"id":1,"text":"What is a common criticism of economics?","options":[{"label":"A","text":"It fails to establish theories of economic behaviour."},{"label":"B","text":"It is unable to construct models of how an economy might work."},{"label":"C","text":"It lacks the ability to use and apply mathematics."},{"label":"D","text":"It is very difficult to undertake laboratory experiments in economics."}],"correct":""},{"id":2,"text":"What is an essential requirement for a market economy to be able to allocate its resources?","options":[{"label":"A","text":"freedom of entry and exit"},{"label":"B","text":"private ownership of property"},{"label":"C","text":"many buyers and sellers"},{"label":"D","text":"perfect product knowledge"}],"correct":""},{"id":3,"text":"What does a production possibility curve show?","options":[{"label":"A","text":"the actual demand in an economy given its existing resources"},{"label":"B","text":"the maximum output an economy can achieve using existing resources"},{"label":"C","text":"the maximum output an economy can ever achieve"},{"label":"D","text":"the minimum combinations of output an economy can achieve"}],"correct":""},{"id":4,"text":"A city built a new stadium to host the World Athletics championships. The city authorities also ensured clean air by closing factories and making their workers unemployed during the championships. Which part of this is an example of non-rival consumption?","options":[{"label":"A","text":"The improved air quality also benefited those who did not have to pay for it."},{"label":"B","text":"The private costs and external costs were borne by the city authorities."},{"label":"C","text":"The stadium could be used after the championships."},{"label":"D","text":"The unemployed factory workers were entitled to free tickets to the stadium."}],"correct":""},{"id":5,"text":"Along which axis can the market demand curve be aggregated from individual demand curves?","options":[{"label":"A","text":"both the horizontal and the vertical axis"},{"label":"B","text":"the horizontal axis only"},{"label":"C","text":"the horizontal or the vertical axis but not both"},{"label":"D","text":"the vertical axis only"}],"correct":"","image":"/images/econ-as-mcq/225_611_1073_570_444_0.jpg"},{"id":6,"text":"What is the likely nature of the price elasticity of supply of a crop such as rice?","options":[{"label":"A","text":"highly elastic in both the short and the long run as rice is an essential product"},{"label":"B","text":"highly elastic in the short run and more inelastic in the long run as production methods improve"},{"label":"C","text":"highly inelastic in both the short and the long run as the land area of a country is fixed"},{"label":"D","text":"highly inelastic in the short run and more elastic in the long run as it takes time to plant rice"}],"correct":""},{"id":7,"text":"The price of laptop computers falls. The price of which product is likely to rise as a result?","options":[{"label":"A","text":"desktop computers"},{"label":"B","text":"carrying cases for laptop computers"},{"label":"C","text":"monitors for desktop computers"},{"label":"D","text":"workstation tables for desktop computers"}],"correct":""},{"id":8,"text":"Assuming normal demand and supply for a product, what will definitely increase consumer surplus?","options":[{"label":"A","text":"a shift in the demand curve to the left"},{"label":"B","text":"a shift in the demand curve to the right"},{"label":"C","text":"a shift in the supply curve to the left"},{"label":"D","text":"a shift in the supply curve to the right"}],"correct":""},{"id":9,"text":"A government in a market economy decides to subsidise the provision of the internet in remote parts of a country. What is the most likely reason for doing this?","options":[{"label":"A","text":"to decrease provision of a demerit good"},{"label":"B","text":"to increase provision of a merit good"},{"label":"C","text":"to provide a public good"},{"label":"D","text":"to reduce negative externalities"}],"correct":""},{"id":10,"text":"Who is intended to benefit from an agricultural buffer stock scheme during periods of plentiful harvests?","options":[{"label":"A","text":"consumers of food"},{"label":"B","text":"growers of food"},{"label":"C","text":"processors of food"},{"label":"D","text":"taxpayers"}],"correct":""},{"id":11,"text":"A government decides to increase indirect taxes, abolish the agricultural subsidy and lower the income level at which tax becomes payable. What would be the most likely consequence of these changes?","options":[{"label":"A","text":"a decrease in cost-push inflation"},{"label":"B","text":"an increase in income inequality"},{"label":"C","text":"an increase in the balance of payments deficit"},{"label":"D","text":"an increase in the budget deficit"}],"correct":""},{"id":12,"text":"What can be calculated using the formula price index in base year?","options":[{"label":"A","text":"gross national income"},{"label":"B","text":"real gross domestic product"},{"label":"C","text":"net domestic income"},{"label":"D","text":"net domestic product"}],"correct":""},{"id":13,"text":"What is always regarded as a cause, rather than a consequence, of a change in the circular flow of income?","options":[{"label":"A","text":"a decrease in government tax revenue"},{"label":"B","text":"an increase in consumption spending"},{"label":"C","text":"an increase in savings"},{"label":"D","text":") an increase in the value of exports"}],"correct":""},{"id":14,"text":"The diagram shows an economy's aggregate demand curve. What explains the downward movement from L to M along the AD curve?","options":[{"label":"A","text":"an increase in tariffs leading to decreased imports"},{"label":"B","text":"a decrease in taxes on firms, causing an increase in short-run aggregate supply"},{"label":"C","text":"an increase in consumer confidence, prompting higher spending on local goods as well as imports"},{"label":"D","text":"a slow-down in economic activity, resulting in decreased investment spending"}],"correct":"","image":"/images/econ-as-mcq/228_603_1264_589_395_0.jpg"},{"id":15,"text":"If a country is suffering from deflation, what would be the best policy to reflate the economy?","options":[{"label":"A","text":"increase corporation tax"},{"label":"B","text":"increase income tax"},{"label":"C","text":"reduce interest rates"},{"label":"D","text":") reduce spending on education"}],"correct":""},{"id":16,"text":"What would be a positive effect on the growth of an economy in the short run, if the government reduced a direct tax on individual earnings?","options":[{"label":"A","text":"Food prices would increase because of shortages."},{"label":"B","text":"Imports of luxury cars would increase to satisfy a change in demand."},{"label":"C","text":"Savings would increase because of additional disposable income."},{"label":"D","text":"The consumption of domestically produced goods would increase."}],"correct":""},{"id":17,"text":"What is not a monetary policy measure?","options":[{"label":"A","text":"credit regulations for banks"},{"label":"B","text":"interest rate changes"},{"label":"C","text":"increased government subsidies"},{"label":"D","text":"money supply changes"}],"correct":""},{"id":18,"text":"The government has a macroeconomic objective of low unemployment. It has recently decreased interest rates. What may limit the effectiveness of this tool in achieving the objective of low unemployment?","options":[{"label":"A","text":"a lack of productive capacity"},{"label":"B","text":"excess demand in the economy"},{"label":"C","text":"increased government spending on infrastructure"},{"label":"D","text":"low levels of welfare benefits"}],"correct":""},{"id":19,"text":"The table shows the ability of two countries, P and Q, to produce two goods, Y and Z. } Which statement is correct?","options":[{"label":"A","text":"P has an absolute advantage in Z and Q has a comparative advantage in Y."},{"label":"B","text":"P has an absolute advantage in Z and Q has an absolute advantage in Y."},{"label":"C","text":"P has a comparative advantage in Y and Q has an absolute advantage in Z."},{"label":"D","text":"P has a comparative advantage in Z and Q has an absolute advantage in Y."}],"correct":"","table":"<table><tr><td>production of good Y per person</td><td>production of good Z per person</td></tr><tr><td>country P</td><td>1000</td><td>1600</td></tr><tr><td>country Q</td><td>1500</td><td>2000</td></tr></table>"},{"id":20,"text":"A trading country can produce two goods, X and Y. It specialises completely in the production of good Y. What will be the opportunity cost to the country of consuming additional imports of good X?","options":[{"label":"A","text":"the additional imports of good X"},{"label":"B","text":"the increase in the resources required to produce good X"},{"label":"C","text":"the reduction in the domestic consumption of good \\(Y\\)"},{"label":"D","text":"the reduction in the resources available to produce good \\(Y\\)"}],"correct":""},{"id":21,"text":"A government believes its current account deficit will be beneficial in the long run. What is the most likely reason for this?","options":[{"label":"A","text":"Immigration has increased."},{"label":"B","text":"It imports capital goods."},{"label":"C","text":"It exports raw materials."},{"label":"D","text":"It reduces unemployment."}],"correct":""},{"id":22,"text":"A country has a freely floating exchange rate. In which circumstance is it most likely to appreciate?","options":[{"label":"A","text":"A competitor trading country experiences a fall in the value of its currency."},{"label":"B","text":"Increased administrative burdens are placed on companies within this country wishing to buy imports."},{"label":"C","text":"There is a fall in demand for its exports."},{"label":"D","text":"There is a fall in the level of its rate of interest."}],"correct":""},{"id":23,"text":"The table shows the ability of two countries, P and Q, to produce two goods, Y and Z. Which statement is correct?","options":[{"label":"A","text":"P has an absolute advantage in Z and Q has a comparative advantage in Y."},{"label":"B","text":"P has an absolute advantage in Z and Q has an absolute advantage in Y."},{"label":"C","text":"P has a comparative advantage in Y and Q has an absolute advantage in Z."},{"label":"D","text":"P has a comparative advantage in Z and Q has an absolute advantage in Y."}],"correct":"","table":"<table><tr><td></td><td>production of good Y per person</td><td>production of good Z per person</td></tr><tr><td>country P</td><td>1000</td><td>1600</td></tr><tr><td>country Q</td><td>1500</td><td>2000</td></tr></table>"},{"id":24,"text":"Both the US and the EU operate in floating exchange rate markets. The rate of exchange fluctuated greatly during the period shown. What would explain the changes in the US dollar-euro rate of exchange?","options":[{"label":"A","text":"changes in the supply and demand for dollars and euros in the foreign exchange market"},{"label":"B","text":"continuous appreciation of the US dollar throughout the period"},{"label":"C","text":"continuous depreciation of the US dollar throughout the period"},{"label":"D","text":"restraints placed by trade agreements on the rate of exchange"}],"correct":"","table":"<table><tr><td>year</td><td>US dollar-euro rate of exchange</td></tr><tr><td>2000</td><td>0.84 dollars per euro</td></tr><tr><td>2008</td><td>1.59 dollars per euro</td></tr><tr><td>2022</td><td>1.00 dollar per euro</td></tr></table>"},{"id":25,"text":"What is not an example of an expenditure-reducing policy?","options":[{"label":"A","text":"a decrease in government spending"},{"label":"B","text":"a depreciation of the exchange rate"},{"label":"C","text":"an increase in direct taxes"},{"label":"D","text":"an increase in interest rates"}],"correct":""},{"id":26,"text":"What does the J-curve effect show?","options":[{"label":"A","text":"A successful currency depreciation requires the sum of the import and export elasticities of demand to be greater than 1."},{"label":"B","text":"After a currency devaluation, the current account is likely to get worse before it gets better."},{"label":"C","text":"In the short run, the demand for imports and exports tends to be price elastic."},{"label":"D","text":"The value of the terms of trade will affect the success of a currency's devaluation."}],"correct":""},{"id":27,"text":"What is the most likely consequence of an increase in the number of multinational companies?","options":[{"label":"A","text":"a decrease in advancements in technology"},{"label":"B","text":"a decrease in foreign direct investment"},{"label":"C","text":"an increase in exports"},{"label":"D","text":"an increase in unemployment"}],"correct":""}];

const paper_23: MCQQuestion[] = [{"id":1,"text":"What is characterised as a free good?","options":[{"label":"A","text":"one that has zero opportunity cost"},{"label":"B","text":"one that is non-excludable and non-rivalrous"},{"label":"C","text":"one that is supplied by the government with no charge"},{"label":"D","text":"one that receives a 100\\% government subsidy"}],"correct":""},{"id":2,"text":"A government wants to move its economy away from central planning towards a market economy. Which policy would be consistent with this aim?","options":[{"label":"A","text":"introduce tariffs on imported goods"},{"label":"B","text":"privatise the ownership of electricity generation"},{"label":"C","text":"provide free education for primary school pupils"},{"label":"D","text":"reduce prices of foods such as wheat and rice"}],"correct":""},{"id":3,"text":"Which statement about factors of production is correct?","options":[{"label":"A","text":"In the short run all factors are fixed; in the long run all factors are varied."},{"label":"B","text":"In the short run at least one factor is fixed; in the long run all factors can be varied."},{"label":"C","text":"In the short run at least one factor is varied; in the long run all factors are fixed."},{"label":"D","text":"In the short run at least one factor is varied; in the long run at least one factor is fixed."}],"correct":""},{"id":4,"text":"Which factor affects the price elasticity of supply of a product?","options":[{"label":"A","text":"availability of stocks"},{"label":"B","text":"percentage of income spent on the product"},{"label":"C","text":"price of substitutes"},{"label":"D","text":"wage rate"}],"correct":""},{"id":5,"text":"What is a major function of the price mechanism?","options":[{"label":"A","text":"providing incentives for government intervention to reduce income inequality"},{"label":"B","text":"removing shortages by creating incentives for market prices to fall"},{"label":"C","text":"removing surpluses by creating incentives for market prices to rise"},{"label":"D","text":") signalling changes in market conditions to producers and consumers"}],"correct":""},{"id":6,"text":"What is a characteristic of a public good?","options":[{"label":"A","text":"Households cannot accurately value the benefits of a good."},{"label":"B","text":"Households cannot be excluded from consuming the good."},{"label":"C","text":"The amount of the good available diminishes as households consume it."},{"label":"D","text":"Households are rivals in the consumption of the good."}],"correct":""},{"id":7,"text":"A government imposes a specific indirect tax on a product that has an inelastic demand curve. What is the incidence of tax in this case?","options":[{"label":"A","text":"The tax falls entirely on the consumer."},{"label":"B","text":"The tax falls entirely on the producer."},{"label":"C","text":"The tax falls to a greater extent on the consumer than on the producer."},{"label":"D","text":"The tax falls to a smaller extent on the consumer than on the producer."}],"correct":""},{"id":8,"text":"What is an example of direct public provision of goods and services?","options":[{"label":"A","text":"a charity hospital funded by public donations that offers free treatment to the rural poor"},{"label":"B","text":"a mobile government library that travels to rural villages offering access to books"},{"label":"C","text":"a private-sector pharmacy that provides treatment directly to the public"},{"label":"D","text":"a private school that offers free places to children of low income families"}],"correct":""},{"id":9,"text":"When is a minimum wage most likely to help reduce the problem of income inequality?","options":[{"label":"A","text":"Higher paid workers maintain pay differentials."},{"label":"B","text":"Labour mobility is low."},{"label":"C","text":"The informal economy is small."},{"label":"D","text":"The minimum wage leads to increased unemployment."}],"correct":""},{"id":10,"text":"What is not true about subsidies?","options":[{"label":"A","text":"They are paid to firms."},{"label":"B","text":"They have to be paid back."},{"label":"C","text":"They reduce the cost of production."},{"label":"D","text":"They shift the supply curve to the right."}],"correct":""},{"id":11,"text":"What is required to prevent a rising price level due to an increase in aggregate demand?","options":[{"label":"A","text":"Additional productive capacity must be created."},{"label":"B","text":"Government investment must remain at a constant level to stabilise supply."},{"label":"C","text":"Greater reliance must be placed on imported goods to overcome any domestic shortfalls."},{"label":"D","text":"Wage rates must change more frequently to maintain levels of employment and output."}],"correct":""},{"id":12,"text":"Which increase makes cost-push inflation less likely to happen?","options":[{"label":"A","text":"indirect tax rates"},{"label":"B","text":"Braw material shortages"},{"label":"C","text":"the foreign exchange rate"},{"label":"D","text":"trade union power"}],"correct":""},{"id":13,"text":"When calculating national income by the income method, what would not be included?","options":[{"label":"A","text":"income from abroad"},{"label":"B","text":"profits of private sector businesses"},{"label":"C","text":"rent from the ownership of land"},{"label":"D","text":"transfer payments"}],"correct":""},{"id":14,"text":"What is an example of expansionary fiscal policy?","options":[{"label":"A","text":"an increase in income tax"},{"label":"B","text":"an increase in private sector investment"},{"label":"C","text":"an increase in spending on public goods"},{"label":"D","text":"an increase in the money supply"}],"correct":""},{"id":15,"text":"What is an example of a supply-side policy?","options":[{"label":"A","text":"an import quota to restrict the supply of goods"},{"label":"B","text":"a rise in interest rates to encourage the supply of savings"},{"label":"C","text":"a specific tax on the supply of goods to raise revenue"},{"label":"D","text":"a subsidy to businesses to promote the supply of training courses"}],"correct":""},{"id":16,"text":"A worker earns \\$10000 and pays \\$1000 in income tax. Another worker earns \\$30 000 and pays \\$4500 in income tax.","options":[{"label":"A","text":"third worker earns \\$150000 and pays \\$50000 in income tax."},{"label":"B","text":"Which type of tax is this?"},{"label":"C","text":"proportional"},{"label":"D","text":"regressive"}],"correct":""},{"id":17,"text":"An increase in interest rates is an example of which type of policy?","options":[{"label":"A","text":"contractionary fiscal policy"},{"label":"B","text":"contractionary monetary policy"},{"label":"C","text":"expansionary monetary policy"},{"label":"D","text":"restrictive supply-side policy"}],"correct":""},{"id":18,"text":"The table shows the terms of trade for an economy expressed as an index number for the period 2019 to 2021. } What can be concluded from the table?","options":[{"label":"A","text":"The quantity of imports rose relative to the quantity of exports."},{"label":"B","text":"The price of exports rose relative to the price of imports."},{"label":"C","text":"The price of imports rose relative to the price of exports."},{"label":"D","text":"The value of exports rose relative to the value of imports."}],"correct":"","table":"<table><tr><td>terms of trade index (2018 = 100)</td></tr><tr><td>2019</td><td>101</td></tr><tr><td>2020</td><td>104</td></tr><tr><td>2021</td><td>109</td></tr></table>"},{"id":19,"text":"Which explanation for a country choosing to engage in international trade is not valid?","options":[{"label":"A","text":"Engaging in international trade enables the country to achieve a higher average standard of living."},{"label":"B","text":"Other countries are more efficient at producing some goods."},{"label":"C","text":"There are some products that the country cannot produce."},{"label":"D","text":"The country has a comparative advantage in the production of all of its goods compared to other countries."}],"correct":""},{"id":20,"text":"In which economic context is the term 'protectionism' usually applied?","options":[{"label":"A","text":"the protection of consumers against excessive prices"},{"label":"B","text":"the protection of employees against exploitation by multinational companies"},{"label":"C","text":"the protection of local producers against international competitors"},{"label":"D","text":"the protection of the foreign exchange rate against currency speculators"}],"correct":""},{"id":21,"text":"Both the US and the EU operate in floating exchange rate markets. The rate of exchange fluctuated greatly during the period shown. } What would explain the changes in the US dollar-euro rate of exchange?","options":[{"label":"A","text":"changes in the supply and demand for dollars and euros in the foreign exchange market"},{"label":"B","text":"continuous appreciation of the US dollar throughout the period"},{"label":"C","text":"continuous depreciation of the US dollar throughout the period"},{"label":"D","text":"restraints placed by trade agreements on the rate of exchange"}],"correct":"","table":"<table><tr><td>US dollar-euro rate of exchange</td></tr><tr><td>2000</td><td>0.84 dollars per euro</td></tr><tr><td>2008</td><td>1.59 dollars per euro</td></tr><tr><td>2022</td><td>1.00 dollar per euro</td></tr></table>"},{"id":22,"text":"The table shows the terms of trade for an economy expressed as an index number for the period 2019 to 2021. What can be concluded from the table?","options":[{"label":"A","text":"The quantity of imports rose relative to the quantity of exports."},{"label":"B","text":"The price of exports rose relative to the price of imports."},{"label":"C","text":"The price of imports rose relative to the price of exports."},{"label":"D","text":"The value of exports rose relative to the value of imports."}],"correct":"","table":"<table><tr><td>year</td><td>terms of trade index (2018 = 100)</td></tr><tr><td>2019</td><td>101</td></tr><tr><td>2020</td><td>104</td></tr><tr><td>2021</td><td>109</td></tr></table>"},{"id":23,"text":"Both the US and the EU operate in floating exchange rate markets. The rate of exchange fluctuated greatly during the period shown. What would explain the changes in the US dollar-euro rate of exchange?","options":[{"label":"A","text":"changes in the supply and demand for dollars and euros in the foreign exchange market"},{"label":"B","text":"continuous appreciation of the US dollar throughout the period"},{"label":"C","text":"continuous depreciation of the US dollar throughout the period"},{"label":"D","text":"restraints placed by trade agreements on the rate of exchange"}],"correct":"","table":"<table><tr><td>year</td><td>US dollar-euro rate of exchange</td></tr><tr><td>2000</td><td>0.84 dollars per euro</td></tr><tr><td>2008</td><td>1.59 dollars per euro</td></tr><tr><td>2022</td><td>1.00 dollar per euro</td></tr></table>"},{"id":24,"text":"The following are four conditions sometimes attached to IMF loans to low-income countries. Which condition would conflict with the 'infant industry' argument?","options":[{"label":"A","text":"the need to allow free trade"},{"label":"B","text":"the need to control inflation"},{"label":"C","text":"the need to have a contractionary fiscal policy"},{"label":"D","text":"the need to privatise government enterprises"}],"correct":""},{"id":25,"text":"The table shows indicators for the macroeconomies of two South American countries over one year. During this year, both governments attempted to reduce unemployment by expanding aggregate demand. } Based on the information given, what is the most likely reason why Argentina achieved a higher \\% change in the unemployment rate than Chile?","options":[{"label":"A","text":"Argentina had a greater \\% change in GDP growth."},{"label":"B","text":"Chile's performance on the current account balance was worse."},{"label":"C","text":"Each country had a weak exchange rate against the US dollar."},{"label":"D","text":"Wage increases in each country were linked to their respective rates of inflation."}],"correct":""},{"id":26,"text":"A measure encourages consumers to change spending on imports to spending on domestically produced goods. What does this describe?","options":[{"label":"A","text":"an expenditure-reducing policy"},{"label":"B","text":"an expenditure-switching policy"},{"label":"C","text":"the law of comparative advantage"},{"label":"D","text":"the Marshall-Lerner condition"}],"correct":""},{"id":27,"text":"The table gives information about the population of three countries in a given year. } Which conclusion can be drawn about the countries in the table in that year?","options":[{"label":"A","text":"China had the highest percentage of children who died in infancy."},{"label":"B","text":"People in Hong Kong lived the longest."},{"label":"C","text":"Singapore had the largest number of people aged over 16."},{"label":"D","text":"The population of Singapore was expected to fall in the next five years."}],"correct":""},{"id":28,"text":"During a certain period, a country with a constant population expands its output per head. It also experiences a significant increase in river and atmospheric pollution. In the absence of any other changes, which measure would show a decrease in living standards?","options":[{"label":"A","text":"Gross Domestic Product per head"},{"label":"B","text":"Gross National Product per head"},{"label":"C","text":"Human Development Index"},{"label":"D","text":"Measure of Economic Welfare"}],"correct":""}];

